import React, { useEffect, useState } from 'react';
import { SpinnerIcon } from './Icons';

interface SplashScreenProps {
  onFinish: () => void;
}

const SplashScreen: React.FC<SplashScreenProps> = ({ onFinish }) => {
  const [isFading, setIsFading] = useState(false);

  useEffect(() => {
    // Start fade out slightly before 3s to ensure smooth transition ending around 3s
    const timer = setTimeout(() => {
      setIsFading(true);
      // Wait for animation to finish before unmounting
      setTimeout(onFinish, 500); 
    }, 2500);

    return () => clearTimeout(timer);
  }, [onFinish]);

  return (
    <div className={`absolute inset-0 z-50 flex flex-col items-center justify-center bg-gradient-to-br from-bg to-pale ${isFading ? 'animate-fade-out' : ''}`}>
      <div className="flex flex-col items-center gap-8">
        <img 
          src="https://raiyansoft.com/wp-content/uploads/2026/01/logo-road80-s.png" 
          alt="Starzat Logo" 
          className="w-40 h-auto animate-fade-in"
        />
        <SpinnerIcon className="w-8 h-8 text-navy animate-spin" />
      </div>
    </div>
  );
};

export default SplashScreen;

import React from 'react';
import { Tab, NavItem } from '../types';
import { HomeIcon, BuildingIcon, PlusIcon, HeartIcon, UserIcon } from './Icons';

interface BottomNavigationProps {
  activeTab: Tab;
  onTabChange: (tab: Tab) => void;
}

const NAV_ITEMS: NavItem[] = [
  { id: Tab.HOME, label: 'الرئيسية', icon: HomeIcon },
  { id: Tab.OFFICES, label: 'المكاتب', icon: BuildingIcon },
  { id: Tab.ADD, icon: PlusIcon, isSpecial: true },
  { id: Tab.FAVORITES, label: 'مفضلتي', icon: HeartIcon },
  { id: Tab.PROFILE, label: 'حسابي', icon: UserIcon },
];

const BottomNavigation: React.FC<BottomNavigationProps> = ({ activeTab, onTabChange }) => {
  return (
    <div className="relative bg-white border-t border-pale pb-[env(safe-area-inset-bottom)] shadow-[0_-5px_15px_rgba(0,0,0,0.02)]">
      <div className="flex justify-between items-center h-[70px] px-2">
        {NAV_ITEMS.map((item) => {
          const isActive = activeTab === item.id;

          if (item.isSpecial) {
            return (
              <button
                key={item.id}
                onClick={() => onTabChange(item.id)}
                className="relative -top-6 bg-navy text-white rounded-full w-14 h-14 flex items-center justify-center shadow-lg transform transition-transform active:scale-95 border-4 border-bg"
                aria-label="إضافة"
              >
                <item.icon className="w-8 h-8" />
              </button>
            );
          }

          return (
            <button
              key={item.id}
              onClick={() => onTabChange(item.id)}
              className={`flex flex-1 flex-col items-center justify-center gap-1 h-full transition-colors duration-200 ${
                isActive ? 'text-navy' : 'text-gray-400'
              }`}
              aria-label={item.label}
              aria-selected={isActive}
            >
              <item.icon className={`w-6 h-6 ${isActive ? 'fill-current' : ''}`} />
              <span className={`text-[10px] font-medium ${isActive ? 'font-bold' : ''}`}>
                {item.label}
              </span>
              {isActive && (
                <span className="absolute bottom-[calc(env(safe-area-inset-bottom)+4px)] w-1 h-1 bg-navy rounded-full" />
              )}
            </button>
          );
        })}
      </div>
    </div>
  );
};

export default BottomNavigation;

