import React, { useState } from 'react';
import SplashScreen from './components/SplashScreen';
import BottomNavigation from './components/BottomNavigation';
import PlaceholderPage from './components/PlaceholderPage';
import { Tab } from './types';

const App: React.FC = () => {
  const [showSplash, setShowSplash] = useState(true);
  const [activeTab, setActiveTab] = useState<Tab>(Tab.HOME);

  // Shell styles to ensure mobile look on desktop
  const shellClasses = `
    w-full h-[100dvh] 
    sm:h-[90vh] sm:max-h-[850px] sm:max-w-[420px] 
    bg-bg 
    sm:rounded-[40px] sm:shadow-2xl sm:overflow-hidden 
    relative flex flex-col
    mx-auto
  `;

  return (
    <div className={shellClasses}>
      {/* Status bar spacer for mobile safe area (top) */}
      <div className="h-[env(safe-area-inset-top)] w-full bg-transparent shrink-0" />

      {/* Main Content Area */}
      <main className="flex-grow flex flex-col relative overflow-hidden">
        {showSplash ? (
          <SplashScreen onFinish={() => setShowSplash(false)} />
        ) : (
          <div className="flex flex-col h-full animate-fade-in">
             {/* 
                Header is minimal/invisible as per requirements for now, 
                but we can reserve space or just let content center itself.
             */}

            <div className="flex-grow flex flex-col overflow-y-auto no-scrollbar">
              {/* All tabs render same placeholder for now */}
              <PlaceholderPage />
            </div>

            {/* Bottom Navigation */}
            <BottomNavigation 
              activeTab={activeTab} 
              onTabChange={setActiveTab} 
            />
          </div>
        )}
      </main>
    </div>
  );
};

export default App;

