  const [savedListings, setSavedListings] = useState<ListingProps[]>([]);

  useEffect(() => {
    const loadListings = async () => {
        try {
            const dbListings = await getListings();
            // Map DB format to UI format
            const mapped = dbListings.map((l: any) => ({
                id: l.id,
                price: l.price || '0 د.ك',
                area: l.area || 'غير محدد',
                title: `${l.listingType} ${l.propertyType}`,
                imageUrl: l.imageUrl || FALLBACK_IMAGE // Should be blob URL or string
            }));
            setSavedListings(mapped);
        } catch (e) {
            console.error("Failed to load listings", e);
        }
    };
