import React, { useState } from 'react';
import SplashScreen from './components/SplashScreen';
import BottomNavigation from './components/BottomNavigation';
import PlaceholderPage from './components/PlaceholderPage';
import ProfilePage from './components/ProfilePage';
import AddWizard from './components/AddWizard';
import Header from './components/Header';
import { Tab } from './types';

const App: React.FC = () => {
  const [showSplash, setShowSplash] = useState(true);
  const [activeTab, setActiveTab] = useState<Tab>(Tab.HOME);
  const [lastUpdate, setLastUpdate] = useState(Date.now());

  // Shell styles to ensure mobile look on desktop
  const shellClasses = `
    w-full h-[100dvh] 
    sm:h-[90vh] sm:max-h-[850px] sm:max-w-[420px] 
    bg-bg 
    sm:rounded-[40px] sm:shadow-2xl sm:overflow-hidden 
    relative flex flex-col
    mx-auto
  `;

  const getPageTitle = (tab: Tab): string => {
    switch (tab) {
      case Tab.HOME: return 'الرئيسية';
      case Tab.OFFICES: return 'المكاتب';
      case Tab.ADD: return 'انشر اعلانك';
      case Tab.EXPLORE: return 'اكسبلور';
      case Tab.PROFILE: return 'حسابي';
      default: return '80road';
    }
  };

  const handleWizardComplete = () => {
    setActiveTab(Tab.PROFILE);
    setLastUpdate(Date.now()); // Trigger ProfilePage refresh
  };

  return (
    <div className={shellClasses}>
      {/* Status bar spacer for mobile safe area (top) */}
      <div className="h-[env(safe-area-inset-top)] w-full bg-transparent shrink-0" />

      {/* Main Content Area */}
      <main className="flex-grow flex flex-col relative overflow-hidden">
        {showSplash ? (
          <SplashScreen onFinish={() => setShowSplash(false)} />
        ) : (
          <div className="flex flex-col h-full animate-fade-in">
            {/* Header */}
            <Header title={getPageTitle(activeTab)} />

            {/* Content Page Container */}
            <div className="flex-grow relative overflow-hidden bg-bg">
              {/* We use display:none to persist the Wizard state when navigating away */}

              <div className={`${activeTab === Tab.HOME ? 'block' : 'hidden'} h-full overflow-y-auto no-scrollbar`}>
                <PlaceholderPage />
              </div>

              <div className={`${activeTab === Tab.OFFICES ? 'block' : 'hidden'} h-full overflow-y-auto no-scrollbar`}>
                <PlaceholderPage />
              </div>

              <div className={`${activeTab === Tab.ADD ? 'block' : 'hidden'} h-full overflow-y-auto no-scrollbar`}>
                 <AddWizard onComplete={handleWizardComplete} />
              </div>

              <div className={`${activeTab === Tab.EXPLORE ? 'block' : 'hidden'} h-full overflow-y-auto no-scrollbar`}>
                <PlaceholderPage />
              </div>

              <div className={`${activeTab === Tab.PROFILE ? 'block' : 'hidden'} h-full overflow-y-auto no-scrollbar`}>
                <ProfilePage key={lastUpdate} />
              </div>
            </div>

            {/* Bottom Navigation */}
            <BottomNavigation 
              activeTab={activeTab} 
              onTabChange={setActiveTab} 
            />
          </div>
        )}
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { ChevronRightIcon, CheckIcon, AppleIcon, UploadIcon, PlayIcon, BuildingIcon } from './Icons';
import { GOVERNORATES, AREAS } from '../data/locations';
import { saveListing } from '../utils/db';

interface AddWizardProps {
  onComplete: () => void;
}

const TOTAL_STEPS = 16;
const FALLBACK_IMAGE = 'https://raiyansoft.com/wp-content/uploads/2026/01/1.png';

const AddWizard: React.FC<AddWizardProps> = ({ onComplete }) => {
  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState<any>({
    listingType: '',
    propertyType: '',
    governorate: '',
    area: '',
    rooms: '',
    bathrooms: '',
    size: 400,
    balcony: '',
    parking: '',
    parkingSystems: [],
    electricity: '',
    water: '',
    ac: '',
    video: null,
    images: []
  });
  const [isProcessing, setIsProcessing] = useState(false);
  const [isPaid, setIsPaid] = useState(false);

  // Helper to scroll to top on step change
  useEffect(() => {
    const content = document.getElementById('wizard-content');
    if (content) content.scrollTop = 0;
  }, [step]);

  const updateData = (key: string, value: any) => {
    setFormData((prev: any) => ({ ...prev, [key]: value }));
  };

  const nextStep = () => {
    if (step < TOTAL_STEPS) setStep(step + 1);
  };

  const prevStep = () => {
    if (step > 1) setStep(step - 1);
  };

  const selectAndNext = (key: string, value: any) => {
    updateData(key, value);
    nextStep();
  };

  const handleMediaUpload = (e: React.ChangeEvent<HTMLInputElement>, type: 'video' | 'images') => {
    if (e.target.files && e.target.files.length > 0) {
      if (type === 'video') {
        updateData('video', e.target.files[0]);
      } else {
        const newImages = Array.from(e.target.files);
        setFormData((prev: any) => ({ ...prev, images: [...prev.images, ...newImages] }));
      }
    }
  };

  const handlePublish = async () => {
    setIsProcessing(true);
    // Simulate Apple Pay
    setTimeout(async () => {
      setIsProcessing(false);
      setIsPaid(true);

      const newListing = {
        id: Date.now(),
        createdAt: new Date(),
        price: '5 د.ك', // Default dummy rental price or use logic
        ...formData,
        imageUrl: formData.images.length > 0 
          ? URL.createObjectURL(formData.images[0]) 
          : FALLBACK_IMAGE
      };

      await saveListing(newListing);

      setTimeout(() => {
        onComplete();
        // Reset wizard
        setStep(1);
        setIsPaid(false);
        setFormData({ size: 400, parkingSystems: [], images: [] });
      }, 1500);
    }, 2000);
  };

  // Render Helpers
  const renderOption = (label: string, isSelected: boolean, onClick: () => void) => (
    <button
      onClick={onClick}
      className={`w-full p-4 mb-3 rounded-2xl border flex items-center justify-between transition-all duration-200 active:scale-98 ${
        isSelected 
          ? 'border-navy bg-navy text-white shadow-lg shadow-navy/20' 
          : 'border-pale bg-white text-navy hover:border-mid'
      }`}
    >
      <span className="font-bold text-sm">{label}</span>
      {isSelected && <CheckIcon className="w-5 h-5 text-white" />}
    </button>
  );

  const renderTitle = (title: string) => (
    <h2 className="text-xl font-bold text-navy mb-6 text-center">{title}</h2>
  );

  // Determine if we need to show the floating footer
  const showFooter = [7, 10, 14, 15].includes(step) || (step === 16 && !isPaid);

  const renderFooterAction = () => {
    if ([7, 10, 14, 15].includes(step)) {
      return (
        <button 
          onClick={nextStep} 
          className="w-full py-4 bg-navy text-white rounded-xl font-bold shadow-lg shadow-navy/20 active:scale-95 transition-all"
        >
          التالي
        </button>
      );
    }

    if (step === 16 && !isPaid) {
      return (
        <button 
          onClick={handlePublish}
          disabled={isProcessing}
          className="w-full py-4 bg-black text-white rounded-xl font-bold flex items-center justify-center gap-2 active:scale-95 transition-all shadow-xl"
        >
          {isProcessing ? (
             <span className="animate-pulse">جاري المعالجة...</span>
          ) : (
            <>
             <AppleIcon className="w-5 h-5 mb-0.5" />
             <span>الدفع والنشر (Apple Pay)</span>
            </>
          )}
        </button>
      );
    }

    return null;
  };

  const renderContent = () => {
    switch (step) {
      case 1:
        return (
          <>
            {renderTitle('نوع الاعلان')}
            {['للبيع', 'للإيجار'].map(opt => (
              renderOption(opt, formData.listingType === opt, () => selectAndNext('listingType', opt))
            ))}
          </>
        );
      case 2:
        return (
          <>
            {renderTitle('نوع العقار')}
            {['بيت', 'شقة', 'دور', 'عمارة', 'دوبلكس'].map(opt => (
              renderOption(opt, formData.propertyType === opt, () => selectAndNext('propertyType', opt))
            ))}
          </>
        );
      case 3:
        return (
          <>
            {renderTitle('المحافظة')}
            {GOVERNORATES.map(opt => (
              renderOption(opt, formData.governorate === opt, () => selectAndNext('governorate', opt))
            ))}
          </>
        );
      case 4:
        const areas = AREAS[formData.governorate] || [];
        return (
          <>
            {renderTitle('المنطقة')}
            <div className="grid grid-cols-1 gap-1">
              {areas.map(opt => (
                renderOption(opt, formData.area === opt, () => selectAndNext('area', opt))
              ))}
            </div>
          </>
        );
      case 5:
        return (
          <>
            {renderTitle('عدد الغرف')}
            <div className="grid grid-cols-3 gap-3">
              {Array.from({ length: 12 }, (_, i) => i + 1).map(num => (
                <button
                  key={num}
                  onClick={() => selectAndNext('rooms', num)}
                  className={`aspect-square rounded-2xl border flex items-center justify-center text-lg font-bold transition-all ${
                    formData.rooms === num ? 'bg-navy text-white' : 'bg-white text-navy border-pale'
                  }`}
                >
                  {num}
                </button>
              ))}
            </div>
          </>
        );
      case 6:
        return (
          <>
            {renderTitle('عدد الحمامات')}
            <div className="grid grid-cols-3 gap-3">
              {[...Array.from({ length: 10 }, (_, i) => i + 1), '10+'].map(num => (
                <button
                  key={num}
                  onClick={() => selectAndNext('bathrooms', num)}
                  className={`aspect-square rounded-2xl border flex items-center justify-center text-lg font-bold transition-all ${
                    formData.bathrooms === num ? 'bg-navy text-white' : 'bg-white text-navy border-pale'
                  }`}
                >
                  {num}
                </button>
              ))}
            </div>
          </>
        );
      case 7:
        return (
          <>
            {renderTitle('المساحة')}
            <div className="flex flex-col items-center justify-center gap-8 py-10 bg-white rounded-3xl border border-pale shadow-sm">
              <span className="text-4xl font-bold text-blue">{formData.size} <span className="text-sm text-gray-400">م²</span></span>
              <input 
                type="range" 
                min="50" 
                max="2000" 
                step="5" 
                value={formData.size} 
                onChange={(e) => updateData('size', parseInt(e.target.value))}
                className="w-4/5 accent-navy h-2 bg-pale rounded-lg appearance-none cursor-pointer"
              />
            </div>
          </>
        );
      case 8:
        return (
          <>
            {renderTitle('بلكونة')}
            {['نعم', 'لا'].map(opt => (
              renderOption(opt, formData.balcony === opt, () => selectAndNext('balcony', opt))
            ))}
          </>
        );
      case 9:
        return (
          <>
            {renderTitle('عدد المواقف')}
            {['1', '2', '3', '3+'].map(opt => (
              renderOption(opt, formData.parking === opt, () => selectAndNext('parking', opt))
            ))}
          </>
        );
      case 10:
        const toggleSystem = (val: string) => {
          const current = formData.parkingSystems || [];
          if (current.includes(val)) {
            updateData('parkingSystems', current.filter((i: string) => i !== val));
          } else {
            updateData('parkingSystems', [...current, val]);
          }
        };
        return (
          <>
            {renderTitle('نظام المواقف')}
            {['مظلات', 'سرداب', 'اخرى'].map(opt => (
              renderOption(opt, formData.parkingSystems.includes(opt), () => toggleSystem(opt))
            ))}
          </>
        );
      case 11:
        return (
          <>
            {renderTitle('الكهرباء')}
            {['على المالك', 'على المستأجر'].map(opt => (
              renderOption(opt, formData.electricity === opt, () => selectAndNext('electricity', opt))
            ))}
          </>
        );
      case 12:
        return (
          <>
            {renderTitle('الماء')}
            {['على المالك', 'على المستأجر'].map(opt => (
              renderOption(opt, formData.water === opt, () => selectAndNext('water', opt))
            ))}
          </>
        );
      case 13:
        return (
          <>
            {renderTitle('التكييف')}
            {['على المالك', 'على المستأجر'].map(opt => (
              renderOption(opt, formData.ac === opt, () => selectAndNext('ac', opt))
            ))}
          </>
        );
      case 14:
        return (
          <>
            {renderTitle('ارفع فيديو')}
            <div className="relative aspect-video bg-gray-100 rounded-xl overflow-hidden border-2 border-dashed border-mid mb-4 flex items-center justify-center group">
              {formData.video ? (
                <video src={URL.createObjectURL(formData.video)} className="w-full h-full object-cover" controls />
              ) : (
                <div className="flex flex-col items-center gap-2">
                  <div className="w-16 h-16 bg-navy/10 rounded-full flex items-center justify-center">
                    <PlayIcon className="w-8 h-8 text-navy" />
                  </div>
                  <span className="text-sm text-gray-500">فيديو ديمو</span>
                </div>
              )}
              <input 
                type="file" 
                accept="video/*" 
                onChange={(e) => handleMediaUpload(e, 'video')}
                className="absolute inset-0 opacity-0 cursor-pointer"
              />
            </div>
          </>
        );
      case 15:
        const demoImages = [
           'https://images.unsplash.com/photo-1522708323590-d24dbb6b0267?q=80&w=300&auto=format&fit=crop',
           'https://images.unsplash.com/photo-1502672260266-1c1ef2d93688?q=80&w=300&auto=format&fit=crop',
           'https://images.unsplash.com/photo-1600607687939-ce8a6c25118c?q=80&w=300&auto=format&fit=crop',
           'https://images.unsplash.com/photo-1600596542815-40b5104d57ea?q=80&w=300&auto=format&fit=crop',
        ];
        return (
          <>
            {renderTitle('ارفع صور العقار')}
            <div className="grid grid-cols-2 gap-3 mb-4">
              {/* Upload Button */}
              <div className="aspect-square bg-pale/30 rounded-xl border-2 border-dashed border-mid flex flex-col items-center justify-center relative active:bg-pale/50 transition-colors">
                <UploadIcon className="w-8 h-8 text-navy mb-2" />
                <span className="text-xs font-bold text-navy">رفع المزيد</span>
                <input 
                  type="file" 
                  multiple 
                  accept="image/*" 
                  onChange={(e) => handleMediaUpload(e, 'images')}
                  className="absolute inset-0 opacity-0 cursor-pointer"
                />
              </div>

              {/* User Uploaded */}
              {formData.images.map((file: File, i: number) => (
                <div key={`new-${i}`} className="aspect-square rounded-xl overflow-hidden bg-gray-100 relative">
                   <img src={URL.createObjectURL(file)} className="w-full h-full object-cover" onError={(e) => (e.currentTarget.src = FALLBACK_IMAGE)} />
                </div>
              ))}

              {/* Demo Images */}
              {demoImages.map((src, i) => (
                <div key={`demo-${i}`} className="aspect-square rounded-xl overflow-hidden bg-gray-100 relative">
                   <img src={src} className="w-full h-full object-cover" onError={(e) => (e.currentTarget.src = FALLBACK_IMAGE)} />
                   <span className="absolute top-1 right-1 bg-black/50 text-white text-[9px] px-1.5 rounded">ديمو</span>
                </div>
              ))}
            </div>
          </>
        );
      case 16:
        return (
          <>
            {renderTitle('ملخص الاعلان')}
            <div className="bg-white rounded-2xl p-4 shadow-sm border border-pale mb-6 text-sm flex flex-col gap-2">
               <div className="flex justify-between"><span className="text-gray-500">نوع الاعلان</span><span className="font-bold">{formData.listingType}</span></div>
               <div className="flex justify-between"><span className="text-gray-500">المنطقة</span><span className="font-bold">{formData.area}</span></div>
               <div className="flex justify-between"><span className="text-gray-500">السعر</span><span className="font-bold text-blue">5 د.ك</span></div>
               <div className="flex justify-between"><span className="text-gray-500">مدة النشر</span><span className="font-bold">30 يوم</span></div>
            </div>

            {isPaid && (
               <div className="flex flex-col items-center justify-center py-10 animate-fade-in">
                  <div className="w-16 h-16 bg-green-100 rounded-full flex items-center justify-center mb-4 text-green-600">
                    <CheckIcon className="w-8 h-8" />
                  </div>
                  <h3 className="text-xl font-bold text-navy mb-2">تم نشر الإعلان بنجاح</h3>
                  <p className="text-gray-500 text-sm">سيظهر إعلانك في حسابك فوراً</p>
               </div>
            )}
          </>
        );
      default:
        return null;
    }
  };

  return (
    <div className="flex flex-col h-full bg-bg relative">
      {/* Progress */}
      <div className="px-6 py-4 flex items-center justify-between shrink-0 z-20 bg-bg">
        <span className="text-xs font-bold text-navy">{step} من {TOTAL_STEPS}</span>
        <div className="flex-1 h-1.5 bg-pale mx-4 rounded-full overflow-hidden">
           <div 
             className="h-full bg-navy transition-all duration-300 rounded-full"
             style={{ width: `${(step / TOTAL_STEPS) * 100}%` }}
           ></div>
        </div>
        {step > 1 && !isPaid && (
          <button onClick={prevStep} className="text-xs font-bold text-gray-400 hover:text-navy">
             رجوع
          </button>
        )}
      </div>

      {/* Content */}
      <div id="wizard-content" className="flex-1 overflow-y-auto px-6 pb-32">
        <div className="max-w-md mx-auto py-2">
           {renderContent()}
        </div>
      </div>

      {/* Sticky Floating Footer */}
      {showFooter && (
        <div className="absolute bottom-0 left-0 right-0 p-6 pt-12 bg-gradient-to-t from-bg via-bg/95 to-transparent z-10 animate-fade-in">
           {renderFooterAction()}
        </div>
      )}
    </div>
  );
};

export default AddWizard;

import React, { useState, useEffect } from 'react';
import { ChevronRightIcon, CheckIcon, AppleIcon, UploadIcon, PlayIcon, BuildingIcon } from './Icons';
import { GOVERNORATES, AREAS } from '../data/locations';
import { saveListing } from '../utils/db';

interface AddWizardProps {
  onComplete: () => void;
}

const TOTAL_STEPS = 16;
const FALLBACK_IMAGE = 'https://raiyansoft.com/wp-content/uploads/2026/01/1.png';

const AddWizard: React.FC<AddWizardProps> = ({ onComplete }) => {
  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState<any>({
    listingType: '',
    propertyType: '',
    governorate: '',
    area: '',
    rooms: '',
    bathrooms: '',
    size: 400,
    balcony: '',
    parking: '',
    parkingSystems: [],
    electricity: '',
    water: '',
    ac: '',
    video: null,
    images: []
  });
  const [isProcessing, setIsProcessing] = useState(false);
  const [isPaid, setIsPaid] = useState(false);

  // Helper to scroll to top on step change
  useEffect(() => {
    const content = document.getElementById('wizard-content');
    if (content) content.scrollTop = 0;
  }, [step]);

  const updateData = (key: string, value: any) => {
    setFormData((prev: any) => ({ ...prev, [key]: value }));
  };

  const nextStep = () => {
    if (step < TOTAL_STEPS) setStep(step + 1);
  };

  const prevStep = () => {
    if (step > 1) setStep(step - 1);
  };

  const selectAndNext = (key: string, value: any) => {
    updateData(key, value);
    nextStep();
  };

  const handleMediaUpload = (e: React.ChangeEvent<HTMLInputElement>, type: 'video' | 'images') => {
    if (e.target.files && e.target.files.length > 0) {
      if (type === 'video') {
        updateData('video', e.target.files[0]);
      } else {
        const newImages = Array.from(e.target.files);
        setFormData((prev: any) => ({ ...prev, images: [...prev.images, ...newImages] }));
      }
    }
  };

  const handlePublish = async () => {
    setIsProcessing(true);
    // Simulate Apple Pay
    setTimeout(async () => {
      setIsProcessing(false);
      setIsPaid(true);

      const newListing = {
        id: Date.now(),
        createdAt: new Date(),
        price: '5 د.ك', // Default dummy rental price or use logic
        ...formData,
        imageUrl: formData.images.length > 0 
          ? URL.createObjectURL(formData.images[0]) 
          : FALLBACK_IMAGE
      };

      await saveListing(newListing);

      setTimeout(() => {
        onComplete();
        // Reset wizard
        setStep(1);
        setIsPaid(false);
        setFormData({ size: 400, parkingSystems: [], images: [] });
      }, 1500);
    }, 2000);
  };

  // Render Helpers
  const renderOption = (label: string, isSelected: boolean, onClick: () => void) => (
    <button
      onClick={onClick}
      className={`w-full p-4 mb-3 rounded-2xl border flex items-center justify-between transition-all duration-200 active:scale-98 ${
        isSelected 
          ? 'border-navy bg-navy text-white shadow-lg shadow-navy/20' 
          : 'border-pale bg-white text-navy hover:border-mid'
      }`}
    >
      <span className="font-bold text-sm">{label}</span>
      {isSelected && <CheckIcon className="w-5 h-5 text-white" />}
    </button>
  );

  const renderTitle = (title: string) => (
    <h2 className="text-xl font-bold text-navy mb-6 text-center">{title}</h2>
  );

  // Determine if we need to show the floating footer
  const showFooter = [7, 14, 15].includes(step) || (step === 16 && !isPaid);

  const renderFooterAction = () => {
    if ([7, 14, 15].includes(step)) {
      return (
        <button 
          onClick={nextStep} 
          className="w-full py-4 bg-navy text-white rounded-xl font-bold shadow-lg shadow-navy/20 active:scale-95 transition-all"
        >
          التالي
        </button>
      );
    }

    if (step === 16 && !isPaid) {
      return (
        <button 
          onClick={handlePublish}
          disabled={isProcessing}
          className="w-full py-4 bg-black text-white rounded-xl font-bold flex items-center justify-center gap-2 active:scale-95 transition-all shadow-xl"
        >
          {isProcessing ? (
             <span className="animate-pulse">جاري المعالجة...</span>
          ) : (
            <>
             <AppleIcon className="w-5 h-5 mb-0.5" />
             <span>الدفع والنشر (Apple Pay)</span>
            </>
          )}
        </button>
      );
    }

    return null;
  };

  const renderContent = () => {
    switch (step) {
      case 1:
        return (
          <>
            {renderTitle('نوع الاعلان')}
            {['للبيع', 'للإيجار'].map(opt => (
              renderOption(opt, formData.listingType === opt, () => selectAndNext('listingType', opt))
            ))}
          </>
        );
      case 2:
        return (
          <>
            {renderTitle('نوع العقار')}
            {['بيت', 'شقة', 'دور', 'عمارة', 'دوبلكس'].map(opt => (
              renderOption(opt, formData.propertyType === opt, () => selectAndNext('propertyType', opt))
            ))}
          </>
        );
      case 3:
        return (
          <>
            {renderTitle('المحافظة')}
            {GOVERNORATES.map(opt => (
              renderOption(opt, formData.governorate === opt, () => selectAndNext('governorate', opt))
            ))}
          </>
        );
      case 4:
        const areas = AREAS[formData.governorate] || [];
        return (
          <>
            {renderTitle('المنطقة')}
            <div className="grid grid-cols-1 gap-1">
              {areas.map(opt => (
                renderOption(opt, formData.area === opt, () => selectAndNext('area', opt))
              ))}
            </div>
          </>
        );
      case 5:
        return (
          <>
            {renderTitle('عدد الغرف')}
            <div className="grid grid-cols-3 gap-3">
              {Array.from({ length: 12 }, (_, i) => i + 1).map(num => (
                <button
                  key={num}
                  onClick={() => selectAndNext('rooms', num)}
                  className={`aspect-square rounded-2xl border flex items-center justify-center text-lg font-bold transition-all ${
                    formData.rooms === num ? 'bg-navy text-white' : 'bg-white text-navy border-pale'
                  }`}
                >
                  {num}
                </button>
              ))}
            </div>
          </>
        );
      case 6:
        return (
          <>
            {renderTitle('عدد الحمامات')}
            <div className="grid grid-cols-3 gap-3">
              {[...Array.from({ length: 10 }, (_, i) => i + 1), '10+'].map(num => (
                <button
                  key={num}
                  onClick={() => selectAndNext('bathrooms', num)}
                  className={`aspect-square rounded-2xl border flex items-center justify-center text-lg font-bold transition-all ${
                    formData.bathrooms === num ? 'bg-navy text-white' : 'bg-white text-navy border-pale'
                  }`}
                >
                  {num}
                </button>
              ))}
            </div>
          </>
        );
      case 7:
        return (
          <>
            {renderTitle('المساحة')}
            <div className="flex flex-col items-center justify-center gap-8 py-10 bg-white rounded-3xl border border-pale shadow-sm">
              <span className="text-4xl font-bold text-blue">{formData.size} <span className="text-sm text-gray-400">م²</span></span>
              <input 
                type="range" 
                min="50" 
                max="2000" 
                step="5" 
                value={formData.size} 
                onChange={(e) => updateData('size', parseInt(e.target.value))}
                className="w-4/5 accent-navy h-2 bg-pale rounded-lg appearance-none cursor-pointer"
              />
            </div>
          </>
        );
      case 8:
        return (
          <>
            {renderTitle('بلكونة')}
            {['نعم', 'لا'].map(opt => (
              renderOption(opt, formData.balcony === opt, () => selectAndNext('balcony', opt))
            ))}
          </>
        );
      case 9:
        return (
          <>
            {renderTitle('عدد المواقف')}
            {['1', '2', '3', '3+'].map(opt => (
              renderOption(opt, formData.parking === opt, () => selectAndNext('parking', opt))
            ))}
          </>
        );
      case 10:
        return (
          <>
            {renderTitle('نظام المواقف')}
            {['مظلات', 'سرداب', 'اخرى'].map(opt => (
              renderOption(opt, formData.parkingSystems.includes(opt), () => selectAndNext('parkingSystems', [opt]))
            ))}
          </>
        );
      case 11:
        return (
          <>
            {renderTitle('الكهرباء')}
            {['على المالك', 'على المستأجر'].map(opt => (
              renderOption(opt, formData.electricity === opt, () => selectAndNext('electricity', opt))
            ))}
          </>
        );
      case 12:
        return (
          <>
            {renderTitle('الماء')}
            {['على المالك', 'على المستأجر'].map(opt => (
              renderOption(opt, formData.water === opt, () => selectAndNext('water', opt))
            ))}
          </>
        );
      case 13:
        return (
          <>
            {renderTitle('التكييف')}
            {['على المالك', 'على المستأجر'].map(opt => (
              renderOption(opt, formData.ac === opt, () => selectAndNext('ac', opt))
            ))}
          </>
        );
      case 14:
        return (
          <>
            {renderTitle('ارفع فيديو')}
            <div className="relative aspect-video bg-gray-100 rounded-xl overflow-hidden border-2 border-dashed border-mid mb-4 flex items-center justify-center group">
              {formData.video ? (
                <video src={URL.createObjectURL(formData.video)} className="w-full h-full object-cover" controls />
              ) : (
                <div className="flex flex-col items-center gap-2">
                  <div className="w-16 h-16 bg-navy/10 rounded-full flex items-center justify-center">
                    <PlayIcon className="w-8 h-8 text-navy" />
                  </div>
                  <span className="text-sm text-gray-500">فيديو ديمو</span>
                </div>
              )}
              <input 
                type="file" 
                accept="video/*" 
                onChange={(e) => handleMediaUpload(e, 'video')}
                className="absolute inset-0 opacity-0 cursor-pointer"
              />
            </div>
          </>
        );
      case 15:
        const demoImages = [
           'https://images.unsplash.com/photo-1522708323590-d24dbb6b0267?q=80&w=300&auto=format&fit=crop',
           'https://images.unsplash.com/photo-1502672260266-1c1ef2d93688?q=80&w=300&auto=format&fit=crop',
           'https://images.unsplash.com/photo-1600607687939-ce8a6c25118c?q=80&w=300&auto=format&fit=crop',
           'https://images.unsplash.com/photo-1600596542815-40b5104d57ea?q=80&w=300&auto=format&fit=crop',
        ];
        return (
          <>
            {renderTitle('ارفع صور العقار')}
            <div className="grid grid-cols-2 gap-3 mb-4">
              {/* Upload Button */}
              <div className="aspect-square bg-pale/30 rounded-xl border-2 border-dashed border-mid flex flex-col items-center justify-center relative active:bg-pale/50 transition-colors">
                <UploadIcon className="w-8 h-8 text-navy mb-2" />
                <span className="text-xs font-bold text-navy">رفع المزيد</span>
                <input 
                  type="file" 
                  multiple 
                  accept="image/*" 
                  onChange={(e) => handleMediaUpload(e, 'images')}
                  className="absolute inset-0 opacity-0 cursor-pointer"
                />
              </div>

              {/* User Uploaded */}
              {formData.images.map((file: File, i: number) => (
                <div key={`new-${i}`} className="aspect-square rounded-xl overflow-hidden bg-gray-100 relative">
                   <img src={URL.createObjectURL(file)} className="w-full h-full object-cover" onError={(e) => (e.currentTarget.src = FALLBACK_IMAGE)} />
                </div>
              ))}

              {/* Demo Images */}
              {demoImages.map((src, i) => (
                <div key={`demo-${i}`} className="aspect-square rounded-xl overflow-hidden bg-gray-100 relative">
                   <img src={src} className="w-full h-full object-cover" onError={(e) => (e.currentTarget.src = FALLBACK_IMAGE)} />
                   <span className="absolute top-1 right-1 bg-black/50 text-white text-[9px] px-1.5 rounded">ديمو</span>
                </div>
              ))}
            </div>
          </>
        );
      case 16:
        return (
          <>
            {renderTitle('ملخص الاعلان')}
            <div className="bg-white rounded-2xl p-4 shadow-sm border border-pale mb-6 text-sm flex flex-col gap-2">
               <div className="flex justify-between"><span className="text-gray-500">نوع الاعلان</span><span className="font-bold">{formData.listingType}</span></div>
               <div className="flex justify-between"><span className="text-gray-500">المنطقة</span><span className="font-bold">{formData.area}</span></div>
               <div className="flex justify-between"><span className="text-gray-500">السعر</span><span className="font-bold text-blue">5 د.ك</span></div>
               <div className="flex justify-between"><span className="text-gray-500">مدة النشر</span><span className="font-bold">30 يوم</span></div>
            </div>

            {isPaid && (
               <div className="flex flex-col items-center justify-center py-10 animate-fade-in">
                  <div className="w-16 h-16 bg-green-100 rounded-full flex items-center justify-center mb-4 text-green-600">
                    <CheckIcon className="w-8 h-8" />
                  </div>
                  <h3 className="text-xl font-bold text-navy mb-2">تم نشر الإعلان بنجاح</h3>
                  <p className="text-gray-500 text-sm">سيظهر إعلانك في حسابك فوراً</p>
               </div>
            )}
          </>
        );
      default:
        return null;
    }
  };

  return (
    <div className="flex flex-col h-full bg-bg relative">
      {/* Progress */}
      <div className="px-6 py-4 flex items-center justify-between shrink-0 z-20 bg-bg">
        <span className="text-xs font-bold text-navy">{step} من {TOTAL_STEPS}</span>
        <div className="flex-1 h-1.5 bg-pale mx-4 rounded-full overflow-hidden">
           <div 
             className="h-full bg-navy transition-all duration-300 rounded-full"
             style={{ width: `${(step / TOTAL_STEPS) * 100}%` }}
           ></div>
        </div>
        {step > 1 && !isPaid && (
          <button onClick={prevStep} className="text-xs font-bold text-gray-400 hover:text-navy">
             رجوع
          </button>
        )}
      </div>

      {/* Content */}
      <div id="wizard-content" className="flex-1 overflow-y-auto px-6 pb-32">
        <div className="max-w-md mx-auto py-2">
           {renderContent()}
        </div>
      </div>

      {/* Sticky Floating Footer */}
      {showFooter && (
        <div className="absolute bottom-0 left-0 right-0 p-6 pt-12 bg-gradient-to-t from-bg via-bg/95 to-transparent z-10 animate-fade-in">
           {renderFooterAction()}
        </div>
      )}
    </div>
  );
};

export default AddWizard;

import React from 'react';
import { Tab, NavItem } from '../types';
import { HomeIcon, BuildingIcon, PlusIcon, PlayIcon, UserIcon } from './Icons';

interface BottomNavigationProps {
  activeTab: Tab;
  onTabChange: (tab: Tab) => void;
}

const NAV_ITEMS: NavItem[] = [
  { id: Tab.HOME, label: 'الرئيسية', icon: HomeIcon },
  { id: Tab.OFFICES, label: 'المكاتب', icon: BuildingIcon },
  { id: Tab.ADD, icon: PlusIcon, isSpecial: true },
  { id: Tab.EXPLORE, label: 'اكسبلور', icon: PlayIcon },
  { id: Tab.PROFILE, label: 'حسابي', icon: UserIcon },
];

const BottomNavigation: React.FC<BottomNavigationProps> = ({ activeTab, onTabChange }) => {
  return (
    <div className="relative bg-white border-t border-pale pb-[env(safe-area-inset-bottom)] shadow-[0_-5px_15px_rgba(0,0,0,0.02)] z-30">
      <div className="flex justify-between items-center h-[70px] px-2">
        {NAV_ITEMS.map((item) => {
          const isActive = activeTab === item.id;

          if (item.isSpecial) {
            return (
              <button
                key={item.id}
                onClick={() => onTabChange(item.id)}
                className={`relative -top-6 bg-navy text-white rounded-full w-14 h-14 flex items-center justify-center transform transition-all duration-300 active:scale-95 border-4 border-bg z-50 ${
                  isActive ? 'shadow-[0_0_20px_4px_rgba(5,47,117,0.4)]' : 'shadow-lg'
                }`}
                aria-label="إضافة"
              >
                <item.icon className="w-8 h-8" />
              </button>
            );
          }

          return (
            <button
              key={item.id}
              onClick={() => onTabChange(item.id)}
              className={`flex flex-1 flex-col items-center justify-center gap-1 h-full transition-colors duration-200 ${
                isActive ? 'text-navy' : 'text-gray-400'
              }`}
              aria-label={item.label}
              aria-selected={isActive}
            >
              <item.icon className={`w-6 h-6 ${isActive ? 'fill-current' : ''}`} />
              <span className={`text-[10px] font-medium ${isActive ? 'font-bold' : ''}`}>
                {item.label}
              </span>
              {isActive && (
                <span className="absolute bottom-[calc(env(safe-area-inset-bottom)+4px)] w-1 h-1 bg-navy rounded-full" />
              )}
            </button>
          );
        })}
      </div>
    </div>
  );
};

export default BottomNavigation;

