                  <p className="text-gray-500 text-sm">سيظهر إعلانك في حسابك فوراً</p>
               </div>
            )}
          </>
        );
      default:
        return null;
    }
  };

  return (
    <div className="flex flex-col h-full bg-bg relative">
      {/* Progress */}
      <div className="px-6 py-4 flex items-center justify-between shrink-0 z-20 bg-bg">
        <span className="text-xs font-bold text-navy">{step} من {TOTAL_STEPS}</span>
        <div className="flex-1 h-1.5 bg-pale mx-4 rounded-full overflow-hidden">
           <div 
             className="h-full bg-navy transition-all duration-300 rounded-full"
             style={{ width: `${(step / TOTAL_STEPS) * 100}%` }}
           ></div>
        </div>
        {step > 1 && !isPaid && (
          <button onClick={prevStep} className="text-xs font-bold text-gray-400 hover:text-navy">
             رجوع
          </button>
        )}
      </div>

      {/* Content */}
      <div id="wizard-content" className="flex-1 overflow-y-auto px-6 pb-52">
        <div className="max-w-md mx-auto py-2">
           {renderContent()}
        </div>
      </div>

      {/* Sticky Floating Footer */}
      {showFooter && (
        <div className="absolute bottom-0 left-0 right-0 p-6 pt-12 bg-gradient-to-t from-bg via-bg/95 to-transparent z-10 animate-fade-in">
           {renderFooterAction()}
        </div>
      )}
    </div>
  );
};

export default AddWizard;

payload.text:
Fix iOS Safari extra top space (الهامش الإضافي بالأعلى) في كل الصفحات:

1) Add / ensure this meta tag in <head>:
<meta name="viewport" content="width=device-width, initial-scale=1, viewport-fit=cover, maximum-scale=1">

2) Remove any top margin/padding from html/body and the outer wrapper:
html, body { margin:0; padding:0; height:100%; }

3) Replace any usage of height:100vh on the main wrapper/app shell with dynamic viewport units to avoid iOS top gap:
Use:
min-height: 100dvh;
min-height: 100svh;

And add iOS fallback:
html, body { height: -webkit-fill-available; }
.app-shell-or-wrapper { min-height: -webkit-fill-available; }

4) If you currently add padding-top anywhere to “simulate” safe area, remove it, and only use safe-area inset where truly needed:
padding-top: env(safe-area-inset-top);
ONLY inside the header background (if needed), not on the whole page.

5) Ensure the header starts at top with no offset:
.app-header { top: 0; margin-top: 0; }

Apply these changes so the blue background/header starts immediately without any empty space above it in iOS browsers.

