import React, { useState } from 'react';
import SplashScreen from './components/SplashScreen';
import BottomNavigation from './components/BottomNavigation';
import PlaceholderPage from './components/PlaceholderPage';
import ProfilePage from './components/ProfilePage';
import AddWizard from './components/AddWizard';
import Header from './components/Header';
import { Tab } from './types';

const App: React.FC = () => {
  const [showSplash, setShowSplash] = useState(true);
  const [activeTab, setActiveTab] = useState<Tab>(Tab.HOME);
  const [lastUpdate, setLastUpdate] = useState(Date.now());

  const getPageTitle = (tab: Tab): string => {
    switch (tab) {
      case Tab.HOME: return 'الرئيسية';
      case Tab.OFFICES: return 'المكاتب';
      case Tab.ADD: return 'انشر اعلانك';
      case Tab.EXPLORE: return 'اكسبلور';
      case Tab.PROFILE: return 'حسابي';
      default: return '80road';
    }
  };

  const handleWizardComplete = () => {
    setActiveTab(Tab.PROFILE);
    setLastUpdate(Date.now()); // Trigger ProfilePage refresh
  };

  // App Shell Construction using Absolute Layering
  // 1. Base Container (Relative, sized to viewport)
  // 2. Header (Absolute Top)
  // 3. TabBar (Absolute Bottom)
  // 4. Main Content (Absolute Inset - Siblings to Header/Footer)

  return (
    <div 
      className="relative w-full max-w-[430px] mx-auto bg-bg sm:rounded-[40px] sm:shadow-2xl overflow-hidden shadow-2xl"
      style={{ height: 'calc(var(--vh, 1vh) * 100)' }}
    >
      {showSplash ? (
        <SplashScreen onFinish={() => setShowSplash(false)} />
      ) : (
        <>
          {/* Layer 1: Header (z-40) */}
          <Header title={getPageTitle(activeTab)} />

          {/* Layer 2: Main Content Area (z-0 to z-10) */}
          {/* Positioned between Header and TabBar to prevent overlap/scrolling issues */}
          <main 
            className="absolute left-0 right-0 overflow-hidden bg-bg animate-fade-in"
            style={{
              top: 'calc(var(--header-h) + env(safe-area-inset-top))',
              bottom: 'calc(var(--tab-h) + env(safe-area-inset-bottom))'
            }}
          >
            {/* Pages - Using absolute inset to ensure they fill the 'main' area completely */}

            <div className={`absolute inset-0 ${activeTab === Tab.HOME ? 'block' : 'hidden'}`}>
              <div className="h-full w-full overflow-y-auto overflow-x-hidden no-scrollbar pb-20">
                <PlaceholderPage />
              </div>
            </div>

            <div className={`absolute inset-0 ${activeTab === Tab.OFFICES ? 'block' : 'hidden'}`}>
              <div className="h-full w-full overflow-y-auto overflow-x-hidden no-scrollbar pb-20">
                <PlaceholderPage />
              </div>
            </div>

            <div className={`absolute inset-0 ${activeTab === Tab.ADD ? 'block' : 'hidden'}`}>
               {/* Wizard handles its own internal structure/scrolling/footer */}
               <AddWizard onComplete={handleWizardComplete} />
            </div>

            <div className={`absolute inset-0 ${activeTab === Tab.EXPLORE ? 'block' : 'hidden'}`}>
              <div className="h-full w-full overflow-y-auto overflow-x-hidden no-scrollbar pb-20">
                <PlaceholderPage />
              </div>
            </div>

            <div className={`absolute inset-0 ${activeTab === Tab.PROFILE ? 'block' : 'hidden'}`}>
               <div className="h-full w-full overflow-y-auto overflow-x-hidden no-scrollbar pb-20">
                 <ProfilePage key={lastUpdate} />
               </div>
            </div>
          </main>

          {/* Layer 3: Bottom Navigation (z-40) */}
          <BottomNavigation 
            activeTab={activeTab} 
            onTabChange={setActiveTab} 
          />
        </>
      )}
    </div>
  );
};

export default App;

