const FALLBACK_IMAGE = 'https://raiyansoft.com/wp-content/uploads/2026/01/1.png';

const ListingCard: React.FC<ListingProps> = ({ price, area, title, imageUrl }) => {
  const [imgSrc, setImgSrc] = useState(imageUrl);

  // Handle Blob URLs or String URLs
  const displaySrc = imgSrc instanceof Blob ? URL.createObjectURL(imgSrc) : imgSrc;

