                    ) : (
                        <div className="w-full h-full bg-navy/5 flex flex-col items-center justify-center gap-3">
                             <div className="w-12 h-12 rounded-full bg-white flex items-center justify-center shadow-sm">
                                <PlayIcon className="w-5 h-5 text-gray-300 ml-1" />
                             </div>
                             <span className="text-xs text-gray-400 font-medium">لا يتوفر فيديو للمعانية</span>
                        </div>
                    )}
                 </div>
            </div>

            {/* Description */}
            <div>
                 <h3 className="text-lg font-bold text-navy mb-3">الوصف</h3>
                 <p className="text-sm text-gray-600 leading-relaxed whitespace-pre-line">
                    {listing.description || 'لا يوجد وصف متاح لهذا العقار. يرجى التواصل مع المالك لمزيد من التفاصيل حول العقار ومميزاته.'}
                 </p>
            </div>

            {/* Details Grid */}
            <div>
                 <h3 className="text-lg font-bold text-navy mb-3">تفاصيل العقار</h3>
                 <div className="grid grid-cols-2 gap-3">
                    <AttrBadge label="نوع الإعلان" value={listing.listingType} />
                    <AttrBadge label="نوع العقار" value={listing.propertyType} />
                    <AttrBadge label="المساحة" value={listing.size ? `${listing.size} م²` : undefined} />
                    <AttrBadge label="الغرف" value={listing.rooms} />
                    <AttrBadge label="الحمامات" value={listing.bathrooms} />
                    <AttrBadge label="بلكونة" value={listing.balcony} />
                    <AttrBadge label="المواقف" value={listing.parking} />
                    <AttrBadge label="نظام المواقف" value={listing.parkingSystems?.join(', ')} />
                    <AttrBadge label="التكييف" value={listing.ac} />
                    <AttrBadge label="الكهرباء" value={listing.electricity} />
                    <AttrBadge label="الماء" value={listing.water} />
                 </div>
            </div>
        </div>
      </div>

      {/* Sticky Bottom Actions */}
      <div className="absolute bottom-0 left-0 right-0 p-4 pt-4 bg-white border-t border-pale z-20" style={{ paddingBottom: 'calc(env(safe-area-inset-bottom) + 16px)' }}>
