import React, { useState } from 'react';
import SplashScreen from './components/SplashScreen';
import BottomNavigation from './components/BottomNavigation';
import PlaceholderPage from './components/PlaceholderPage';
import ProfilePage from './components/ProfilePage';
import AddWizard from './components/AddWizard';
import ListingDetailsPage from './components/ListingDetailsPage';
import Header from './components/Header';
import { Tab, Listing } from './types';

const App: React.FC = () => {
  const [showSplash, setShowSplash] = useState(true);
  const [activeTab, setActiveTab] = useState<Tab>(Tab.HOME);
  const [lastUpdate, setLastUpdate] = useState(Date.now());
  const [selectedListing, setSelectedListing] = useState<Listing | null>(null);

  const getPageTitle = (tab: Tab): string => {
    switch (tab) {
      case Tab.HOME: return 'الرئيسية';
      case Tab.OFFICES: return 'المكاتب';
      case Tab.ADD: return 'انشر اعلانك';
      case Tab.EXPLORE: return 'اكسبلور';
      case Tab.PROFILE: return 'حسابي';
      default: return '80road';
    }
  };

  const handleWizardComplete = () => {
    setActiveTab(Tab.PROFILE);
    setLastUpdate(Date.now()); // Trigger ProfilePage refresh
  };

  const handleListingClick = (listing: Listing) => {
    setSelectedListing(listing);
  };

  const handleBackFromDetails = () => {
    setSelectedListing(null);
  };

  // App Shell Construction using Absolute Layering
  // 1. Base Container (Relative, sized to viewport)
  // 2. Header (Absolute Top)
  // 3. TabBar (Absolute Bottom)
  // 4. Main Content (Absolute Inset - Siblings to Header/Footer)

  return (
    <div 
      className="relative w-full max-w-[430px] mx-auto bg-bg sm:rounded-[40px] sm:shadow-2xl overflow-hidden shadow-2xl"
      style={{ height: 'calc(var(--vh, 1vh) * 100)' }}
    >
      {showSplash ? (
        <SplashScreen onFinish={() => setShowSplash(false)} />
      ) : (
        <>
          {/* Layer 1: Header (z-40) */}
          {/* Hide main header when details page is open to allow details header to take over */}
          {!selectedListing && <Header title={getPageTitle(activeTab)} />}

          {/* Layer 2: Main Content Area (z-0 to z-10) */}
          {/* Positioned between Header and TabBar to prevent overlap/scrolling issues */}
          <main 
            className="absolute left-0 right-0 overflow-hidden bg-bg animate-fade-in"
            style={{
              top: selectedListing ? '0' : 'calc(var(--header-h) + env(safe-area-inset-top))',
              bottom: selectedListing ? '0' : 'calc(var(--tab-h) + env(safe-area-inset-bottom))',
              zIndex: selectedListing ? 50 : 10
            }}
          >
             {selectedListing ? (
                <ListingDetailsPage 
                  listing={selectedListing} 
                  onBack={handleBackFromDetails} 
                />
             ) : (
               <>
                {/* Pages - Using absolute inset to ensure they fill the 'main' area completely */}

                <div className={`absolute inset-0 ${activeTab === Tab.HOME ? 'block' : 'hidden'}`}>
                  <div className="h-full w-full overflow-y-auto overflow-x-hidden no-scrollbar pb-20">
                    <PlaceholderPage />
                  </div>
                </div>

                <div className={`absolute inset-0 ${activeTab === Tab.OFFICES ? 'block' : 'hidden'}`}>
                  <div className="h-full w-full overflow-y-auto overflow-x-hidden no-scrollbar pb-20">
                    <PlaceholderPage />
                  </div>
                </div>

                <div className={`absolute inset-0 ${activeTab === Tab.ADD ? 'block' : 'hidden'}`}>
                   {/* Wizard handles its own internal structure/scrolling/footer */}
                   <AddWizard onComplete={handleWizardComplete} />
                </div>

                <div className={`absolute inset-0 ${activeTab === Tab.EXPLORE ? 'block' : 'hidden'}`}>
                  <div className="h-full w-full overflow-y-auto overflow-x-hidden no-scrollbar pb-20">
                    <PlaceholderPage />
                  </div>
                </div>

                <div className={`absolute inset-0 ${activeTab === Tab.PROFILE ? 'block' : 'hidden'}`}>
                   <div className="h-full w-full overflow-y-auto overflow-x-hidden no-scrollbar pb-20">
                     <ProfilePage 
                        key={lastUpdate} 
                        onListingClick={handleListingClick}
                     />
                   </div>
                </div>
               </>
             )}
          </main>

          {/* Layer 3: Bottom Navigation (z-40) */}
          {/* Hide bottom nav when details page is active */}
          {!selectedListing && (
            <BottomNavigation 
                activeTab={activeTab} 
                onTabChange={setActiveTab} 
            />
          )}
        </>
      )}
    </div>
  );
};

export default App;

import React, { useState, useRef } from 'react';
import { ChevronRightIcon, PlayIcon, CheckIcon, UserIcon, PhoneIcon, WhatsappIcon, BuildingIcon } from './Icons';
import { Listing } from '../types';

interface ListingDetailsPageProps {
  listing: Listing;
  onBack: () => void;
}

const FALLBACK_IMAGE = 'https://raiyansoft.com/wp-content/uploads/2026/01/1.png';

interface MediaItem {
  type: 'image' | 'video';
  src: string | File | Blob;
  id: string;
}

const ListingDetailsPage: React.FC<ListingDetailsPageProps> = ({ listing, onBack }) => {
  const [activeImageIndex, setActiveImageIndex] = useState(0);
  const scrollRef = useRef<HTMLDivElement>(null);
  const thumbsRef = useRef<HTMLDivElement>(null);

  // Prepare Media Items
  const mediaItems: MediaItem[] = [];

  // Images
  const rawImages = listing.images && listing.images.length > 0 
    ? listing.images 
    : [listing.imageUrl || FALLBACK_IMAGE];

  rawImages.forEach((img, idx) => {
      mediaItems.push({ type: 'image', src: img, id: `img-${idx}` });
  });

  // Video (appended to end)
  if (listing.video) {
      mediaItems.push({ type: 'video', src: listing.video, id: 'vid-main' });
  }

  const getSrc = (src: string | File | Blob) => {
    if (src instanceof File || src instanceof Blob) {
      return URL.createObjectURL(src);
    }
    return src;
  };

  const handleScroll = (e: React.UIEvent<HTMLDivElement>) => {
    const width = e.currentTarget.offsetWidth;
    const scrollLeft = Math.abs(e.currentTarget.scrollLeft);
    const index = Math.round(scrollLeft / width);
    setActiveImageIndex(index);

    // Auto scroll thumbnails to keep active one in view
    if (thumbsRef.current) {
        const thumb = thumbsRef.current.children[index] as HTMLElement;
        if (thumb) {
            thumb.scrollIntoView({ behavior: 'smooth', block: 'nearest', inline: 'center' });
        }
    }
  };

  const scrollToMedia = (index: number) => {
      setActiveImageIndex(index);
      if (scrollRef.current) {
          const child = scrollRef.current.children[index] as HTMLElement;
          if (child) {
              child.scrollIntoView({ behavior: 'smooth', block: 'nearest', inline: 'center' });
          }
      }
  };

  const AttrBadge: React.FC<{ label: string; value: string | number | undefined }> = ({ label, value }) => {
    if (!value) return null;
    return (
      <div className="bg-white border border-pale rounded-xl p-3 flex flex-col gap-1 items-start shadow-sm">
        <span className="text-[10px] text-gray-400 font-medium">{label}</span>
        <span className="text-sm font-bold text-navy">{value}</span>
      </div>
    );
  };

  return (
    <div className="absolute inset-0 bg-bg z-50 flex flex-col h-full overflow-hidden animate-fade-in">
      {/* Header */}
      <div 
        className="absolute top-0 left-0 right-0 z-20 flex items-center justify-between px-4"
        style={{ 
            height: 'calc(var(--header-h) + env(safe-area-inset-top))', 
            paddingTop: 'env(safe-area-inset-top)',
            background: 'linear-gradient(to bottom, rgba(0,0,0,0.4) 0%, transparent 100%)'
        }}
      >
        <button 
          onClick={onBack}
          className="w-10 h-10 bg-white/20 backdrop-blur-md rounded-full flex items-center justify-center text-white active:scale-95 transition-all"
        >
          <ChevronRightIcon className="w-6 h-6 rotate-180" />
        </button>

        {/* Actions */}
        <div className="flex gap-3">
          <button className="w-10 h-10 bg-white/20 backdrop-blur-md rounded-full flex items-center justify-center text-white active:scale-95 transition-all">
             <CheckIcon className="w-5 h-5" />
          </button>
        </div>
      </div>

      {/* Content Scroll */}
      <div className="flex-1 overflow-y-auto overflow-x-hidden pb-24 no-scrollbar bg-bg">

        {/* Unified Media Section */}
        <div className="relative bg-white shadow-sm">
             {/* Main Carousel */}
             <div className="w-full aspect-[4/3] relative bg-gray-200">
                 <div 
                    ref={scrollRef}
                    className="w-full h-full flex overflow-x-auto snap-x snap-mandatory no-scrollbar"
                    onScroll={handleScroll}
                 >
                    {mediaItems.map((item, idx) => (
                        <div key={item.id} className="w-full h-full shrink-0 snap-center relative bg-black flex items-center justify-center">
                            {item.type === 'video' ? (
                                <video 
                                    src={getSrc(item.src)} 
                                    controls 
                                    className="w-full h-full object-contain"
                                    poster={FALLBACK_IMAGE}
                                />
                            ) : (
                                <img 
                                    src={getSrc(item.src)} 
                                    className="w-full h-full object-cover" 
                                    onError={(e) => (e.currentTarget.src = FALLBACK_IMAGE)}
                                    alt={`Slide ${idx}`}
                                />
                            )}
                        </div>
                    ))}
                 </div>

                 {/* Counter Badge */}
                 <div className="absolute bottom-4 right-4 bg-black/60 backdrop-blur-md text-white text-[10px] font-bold px-2.5 py-1 rounded-full border border-white/10">
                    {activeImageIndex + 1} / {mediaItems.length}
                 </div>
             </div>

             {/* Thumbnails Row */}
             {mediaItems.length > 1 && (
                 <div 
                    ref={thumbsRef}
                    className="flex gap-2 p-3 overflow-x-auto no-scrollbar border-b border-pale/50 bg-white"
                 >
                    {mediaItems.map((item, idx) => (
                        <button 
                            key={`thumb-${item.id}`}
                            onClick={() => scrollToMedia(idx)}
                            className={`relative flex-shrink-0 w-16 h-16 rounded-lg overflow-hidden border-2 transition-all ${
                                activeImageIndex === idx ? 'border-navy ring-1 ring-navy shadow-md opacity-100' : 'border-transparent opacity-60 hover:opacity-100'
                            }`}
                        >
                             {item.type === 'video' ? (
                                 <div className="w-full h-full bg-gray-800 flex items-center justify-center relative">
                                     <PlayIcon className="w-6 h-6 text-white z-10" />
                                     {/* Overlay to look consistent */}
                                     <div className="absolute inset-0 bg-black/20"></div>
                                 </div>
                             ) : (
                                 <img 
                                     src={getSrc(item.src)} 
                                     className="w-full h-full object-cover" 
                                     onError={(e) => (e.currentTarget.src = FALLBACK_IMAGE)}
                                     alt={`Thumb ${idx}`}
                                 />
                             )}
                        </button>
                    ))}
                 </div>
             )}
        </div>

        <div className="flex flex-col gap-6 px-5 py-6">
            {/* Main Info Card */}
            <div className="bg-white rounded-3xl p-5 shadow-lg shadow-navy/5 border border-pale">
                <div className="flex justify-between items-start mb-2">
                    <h1 className="text-xl font-bold text-navy leading-snug max-w-[70%]">{listing.title}</h1>
                    <span className="text-blue font-bold text-lg">{listing.price}</span>
                </div>
                <div className="flex items-center gap-2 text-gray-500 text-sm mb-4">
                    <BuildingIcon className="w-4 h-4" />
                    <span>{listing.area}، {listing.governorate}</span>
                </div>

                <div className="flex items-center justify-between pt-4 border-t border-gray-100">
                    <div className="flex items-center gap-2">
                         <div className="w-8 h-8 rounded-full bg-gray-100 flex items-center justify-center text-gray-400">
                            <UserIcon className="w-4 h-4" />
                         </div>
                         <span className="text-xs font-bold text-navy">المالك</span>
                    </div>
                    <span className="text-[10px] text-gray-400">
                        {listing.views ? `${listing.views} مشاهدة` : 'جديد'}
                    </span>
                </div>
            </div>

            {/* Description */}
            <div>
                 <h3 className="text-lg font-bold text-navy mb-3">الوصف</h3>
                 <p className="text-sm text-gray-600 leading-relaxed whitespace-pre-line">
                    {listing.description || 'لا يوجد وصف متاح لهذا العقار. يرجى التواصل مع المالك لمزيد من التفاصيل حول العقار ومميزاته.'}
                 </p>
            </div>

            {/* Details Grid */}
            <div>
                 <h3 className="text-lg font-bold text-navy mb-3">تفاصيل العقار</h3>
                 <div className="grid grid-cols-2 gap-3">
                    <AttrBadge label="نوع الإعلان" value={listing.listingType} />
                    <AttrBadge label="نوع العقار" value={listing.propertyType} />
                    <AttrBadge label="المساحة" value={listing.size ? `${listing.size} م²` : undefined} />
                    <AttrBadge label="الغرف" value={listing.rooms} />
                    <AttrBadge label="الحمامات" value={listing.bathrooms} />
                    <AttrBadge label="بلكونة" value={listing.balcony} />
                    <AttrBadge label="المواقف" value={listing.parking} />
                    <AttrBadge label="نظام المواقف" value={listing.parkingSystems?.join(', ')} />
                    <AttrBadge label="التكييف" value={listing.ac} />
                    <AttrBadge label="الكهرباء" value={listing.electricity} />
                    <AttrBadge label="الماء" value={listing.water} />
                 </div>
            </div>
        </div>
      </div>

      {/* Sticky Bottom Actions */}
      <div className="absolute bottom-0 left-0 right-0 p-4 pt-4 bg-white border-t border-pale z-20" style={{ paddingBottom: 'calc(env(safe-area-inset-bottom) + 16px)' }}>
          <div className="flex gap-3">
            <a 
            href="https://wa.me/96598812020" 
            className="flex-1 flex items-center justify-center gap-2 py-3 rounded-xl border border-navy/20 bg-green-50 text-green-700 font-bold text-sm active:scale-95 transition-transform"
            >
            <WhatsappIcon className="w-5 h-5" />
            <span>واتساب</span>
            </a>
            <a 
            href="tel:+96598812020" 
            className="flex-1 flex items-center justify-center gap-2 py-3 rounded-xl bg-navy text-white font-bold text-sm shadow-lg shadow-navy/20 active:scale-95 transition-transform"
            >
            <PhoneIcon className="w-5 h-5" />
            <span>اتصال</span>
            </a>
          </div>
      </div>
    </div>
  );
};

