export const initDB = (): Promise<IDBDatabase> => {
  return new Promise((resolve, reject) => {
    const request = indexedDB.open(DB_NAME, DB_VERSION);

    request.onupgradeneeded = (event: IDBVersionChangeEvent) => {
      const db = (event.target as IDBOpenDBRequest).result;
      if (!db.objectStoreNames.contains(STORE_LISTINGS)) {
        db.createObjectStore(STORE_LISTINGS, { keyPath: 'id' });
      }
    };

    request.onsuccess = () => resolve(request.result);
    request.onerror = () => reject(request.error);
  });
};

export const saveListing = async (listing: any) => {
  const db = await initDB();
  return new Promise((resolve, reject) => {
    const tx = db.transaction(STORE_LISTINGS, 'readwrite');
    const store = tx.objectStore(STORE_LISTINGS);
    store.put(listing);
    tx.oncomplete = () => resolve(true);
    tx.onerror = () => reject(tx.error);
  });
};

export const getListings = async () => {
  const db = await initDB();
  return new Promise<any[]>((resolve, reject) => {
    const tx = db.transaction(STORE_LISTINGS, 'readonly');
    const store = tx.objectStore(STORE_LISTINGS);
    const request = store.getAll();
    request.onsuccess = () => {
        // Sort by ID descending (newest first)
        const results = request.result;
        results.sort((a, b) => b.id - a.id);
        resolve(results);
    };
    request.onerror = () => reject(request.error);
  });
};

export const getListingById = async (id: number): Promise<Listing | null> => {
  // Check demo ads first
  const demo = DEMO_ADS.find(l => l.id === id);
  if (demo) return demo;

  // Check DB
  const db = await initDB();
  return new Promise((resolve, reject) => {
    const tx = db.transaction(STORE_LISTINGS, 'readonly');
    const store = tx.objectStore(STORE_LISTINGS);
    const request = store.get(id);
    request.onsuccess = () => {
        if (request.result) resolve(request.result);
        else resolve(null);
    };
    request.onerror = () => resolve(null);
  });
};

import React, { useState, useEffect } from 'react';
import { ChevronRightIcon, CheckIcon, AppleIcon, UploadIcon, PlayIcon, BuildingIcon } from './Icons';
import { GOVERNORATES, AREAS } from '../data/locations';
import { saveListing } from '../utils/db';

interface AddWizardProps {
  onComplete: () => void;
}

const TOTAL_STEPS = 16;
const FALLBACK_IMAGE = 'https://raiyansoft.com/wp-content/uploads/2026/01/1.png';

const AddWizard: React.FC<AddWizardProps> = ({ onComplete }) => {
  // Initialize step from URL
  const getStepFromUrl = () => {
    const params = new URLSearchParams(window.location.hash.split('?')[1]);
    const s = parseInt(params.get('step') || '1');
    return isNaN(s) || s < 1 ? 1 : (s > TOTAL_STEPS ? TOTAL_STEPS : s);
  };

  const [step, setStep] = useState(getStepFromUrl());
  const [formData, setFormData] = useState<any>({
    listingType: '',
    propertyType: '',
    governorate: '',
    area: '',
    rooms: '',
    bathrooms: '',
    size: 400,
    balcony: '',
    parking: '',
    parkingSystems: [],
    electricity: '',
    water: '',
    ac: '',
    video: null,
    images: []
  });
  const [isProcessing, setIsProcessing] = useState(false);
  const [isPaid, setIsPaid] = useState(false);

  // Sync state with URL changes (back/forward)
  useEffect(() => {
    const handleHashChange = () => {
      const newStep = getStepFromUrl();
      setStep(newStep);
    };
    window.addEventListener('hashchange', handleHashChange);
    return () => window.removeEventListener('hashchange', handleHashChange);
  }, []);

  // Update URL when step changes internally
  const updateStepUrl = (newStep: number) => {
     const currentHash = window.location.hash.split('?')[0];
     window.location.hash = `${currentHash}?step=${newStep}`;
  };

  // Helper to scroll to top on step change
  useEffect(() => {
    const content = document.getElementById('wizard-content');
    if (content) content.scrollTop = 0;
  }, [step]);

  const updateData = (key: string, value: any) => {
    setFormData((prev: any) => ({ ...prev, [key]: value }));
  };

  const nextStep = () => {
    if (step < TOTAL_STEPS) updateStepUrl(step + 1);
  };

  const prevStep = () => {
    if (step > 1) updateStepUrl(step - 1);
  };

  const selectAndNext = (key: string, value: any) => {
    updateData(key, value);
    nextStep();
  };

  const handleMediaUpload = (e: React.ChangeEvent<HTMLInputElement>, type: 'video' | 'images') => {
    if (e.target.files && e.target.files.length > 0) {
      if (type === 'video') {
        updateData('video', e.target.files[0]);
      } else {
        const newImages = Array.from(e.target.files);
        setFormData((prev: any) => ({ ...prev, images: [...prev.images, ...newImages] }));
      }
    }
  };

  const handlePublish = async () => {
    setIsProcessing(true);
    // Simulate Apple Pay
    setTimeout(async () => {
      setIsProcessing(false);
      setIsPaid(true);

      const newListing = {
        id: Date.now(),
        createdAt: new Date(),
        price: '5 د.ك', // Default dummy rental price or use logic
        publisherId: 'current_user',
        publisherName: 'فهد الحمدان',
        ...formData,
        imageUrl: formData.images.length > 0 
          ? URL.createObjectURL(formData.images[0]) 
          : FALLBACK_IMAGE
      };

      await saveListing(newListing);

      setTimeout(() => {
        onComplete();
        // Reset wizard
        setFormData({ size: 400, parkingSystems: [], images: [] });
      }, 1500);
    }, 2000);
  };

  // Render Helpers
  const renderOption = (label: string, isSelected: boolean, onClick: () => void) => (
    <button
      onClick={onClick}
      className={`w-full p-4 mb-3 rounded-2xl border flex items-center justify-between transition-all duration-200 active:scale-98 ${
        isSelected 
          ? 'border-navy bg-navy text-white shadow-lg shadow-navy/20' 
          : 'border-pale bg-white text-navy hover:border-mid'
      }`}
    >
      <span className="font-bold text-sm">{label}</span>
      {isSelected && <CheckIcon className="w-5 h-5 text-white" />}
    </button>
  );

  const renderTitle = (title: string) => (
    <h2 className="text-xl font-bold text-navy mb-6 text-center">{title}</h2>
  );

  // Show footer on all steps unless payment is successfully processed
  const showFooter = !isPaid;

  const renderFooterAction = () => {
    const isFirstStep = step === 1;

    // Shared Back Button (Secondary Style)
    const backButton = (
      <button 
        onClick={prevStep} 
        disabled={isFirstStep}
        className={`w-full py-3 bg-white border border-pale text-navy rounded-xl font-bold transition-all shadow-sm ${
          isFirstStep ? 'opacity-50 cursor-not-allowed' : 'active:scale-95 hover:bg-pale/30'
        }`}
      >
        رجوع
      </button>
    );

    // Primary Next Button
    const nextButton = (
      <button 
        onClick={nextStep} 
        className="w-full py-4 bg-navy text-white rounded-xl font-bold shadow-lg shadow-navy/20 active:scale-95 transition-all"
      >
        التالي
      </button>
    );

    // Steps that require a manual "Next" button (stacked layout)
    if ([7, 14, 15].includes(step)) {
      return (
        <div className="flex flex-col gap-3">
          {backButton}
          {nextButton}
        </div>
      );
    }

    // Step 16: Publish (Apple Pay)
    if (step === 16) {
      return (
        <div className="flex flex-col gap-3">
          {backButton}
          <button 
            onClick={handlePublish}
            disabled={isProcessing}
            className="w-full py-4 bg-black text-white rounded-xl font-bold flex items-center justify-center gap-2 active:scale-95 transition-all shadow-xl"
          >
            {isProcessing ? (
               <span className="animate-pulse">جاري المعالجة...</span>
            ) : (
              <>
               <AppleIcon className="w-5 h-5 mb-0.5" />
               <span>الدفع والنشر (Apple Pay)</span>
              </>
            )}
          </button>
        </div>
      );
    }

    // Default for all other steps (Single Choice / Auto-advance)
    // Always render at least the back button as per requirement
    return (
      <div className="w-full">
        {backButton}
      </div>
    );
  };

  const renderContent = () => {
    switch (step) {
      case 1:
        return (
          <>
            {renderTitle('نوع الاعلان')}
            {['للبيع', 'للإيجار'].map(opt => (
              renderOption(opt, formData.listingType === opt, () => selectAndNext('listingType', opt))
            ))}
          </>
        );
      case 2:
        return (
          <>
            {renderTitle('نوع العقار')}
            {['بيت', 'شقة', 'دور', 'عمارة', 'دوبلكس'].map(opt => (
              renderOption(opt, formData.propertyType === opt, () => selectAndNext('propertyType', opt))
