import React, { useState, useEffect } from 'react';
import { UserIcon, PhoneIcon, WhatsappIcon, BuildingIcon } from './Icons';
import { getListings, DEMO_ADS } from '../utils/db';
import { Listing } from '../types';

interface ProfilePageProps {
  onListingClick?: (listing: Listing) => void;
}

const FALLBACK_IMAGE = 'https://raiyansoft.com/wp-content/uploads/2026/01/1.png';

const ListingCard: React.FC<{ listing: Listing, onClick?: () => void }> = ({ listing, onClick }) => {
  const [imgSrc, setImgSrc] = useState<string>('');

  useEffect(() => {
    if (listing.imageUrl instanceof Blob || listing.imageUrl instanceof File) {
        setImgSrc(URL.createObjectURL(listing.imageUrl));
    } else if (typeof listing.imageUrl === 'string') {
        setImgSrc(listing.imageUrl);
    } else if (listing.images && listing.images.length > 0) {
         const first = listing.images[0];
         if (first instanceof Blob || first instanceof File) {
             setImgSrc(URL.createObjectURL(first));
         } else {
             setImgSrc(first as string);
         }
    } else {
        setImgSrc(FALLBACK_IMAGE);
    }
  }, [listing]);

  return (
    <div 
      onClick={onClick}
      className="flex flex-col bg-white rounded-xl shadow-[0_2px_8px_rgba(0,0,0,0.04)] border border-pale/50 overflow-hidden active:scale-98 transition-transform cursor-pointer"
    >
      {/* Image Container */}
      <div className="aspect-square bg-slate-100 flex items-center justify-center relative">
        <img 
          src={imgSrc} 
          alt={listing.title}
          className="w-full h-full object-cover"
          onError={() => setImgSrc(FALLBACK_IMAGE)}
        />
        <span className="absolute top-2 left-2 bg-navy/80 text-white text-[10px] px-2 py-0.5 rounded-full z-10">
          جديد
        </span>
      </div>

      {/* Content */}
      <div className="p-3 flex flex-col gap-1">
        <span className="text-blue font-bold text-sm text-right font-sans">{listing.price}</span>
        <h4 className="text-navy font-bold text-xs truncate text-right font-sans">{listing.title}</h4>
        <div className="flex items-center justify-end gap-1 opacity-60">
          <span className="text-[10px] text-navy font-sans">{listing.area}</span>
          <div className="w-1 h-1 rounded-full bg-navy"></div>
        </div>
      </div>
    </div>
  );
};

const StatItem: React.FC<{ label: string; value: string }> = ({ label, value }) => (
  <div className="flex flex-col items-center gap-1">
    <span className="text-lg font-bold text-navy font-sans">{value}</span>
    <span className="text-xs text-gray-400 font-medium font-sans">{label}</span>
