  if (isMe) {
      const myAds = [...savedListings, ...DEMO_ADS]; // Show all for me
      const myFavs = [DEMO_ADS[3]]; 
      displayList = activeSubTab === 'ads' ? myAds : myFavs;
  } else {
      // Mock external profile data
      if (viewedUserId === 'user_101') {
          profileName = 'مكتب الريان العقاري';
          profileBio = 'نقدم أفضل الفرص الاستثمارية في الكويت.';
      } else if (viewedUserId === 'user_102') {
          profileName = 'أبو فهد العقارية';
          profileBio = 'بيع وشراء وإدارة أملاك الغير.';
      } else if (viewedUserId === 'user_103') {
          profileName = 'مؤسسة الدار';
          profileBio = 'شقق وفلل فاخرة للإيجار.';
      } else {
          profileName = 'ناشر الإعلان';
          profileBio = 'عضو في 80road';
      }

      // Filter ads for this user
      // For demo purposes, filter DEMO_ADS by publisherId
      // And also check savedListings (though usually savedListings are "my" listings created by wizard)
      // Since wizard creates listings as 'current_user', they won't match 'user_101' etc.

      const externalAds = [...savedListings, ...DEMO_ADS].filter(l => l.publisherId === viewedUserId);
      displayList = externalAds;
  }

  const adsCount = displayList.length;

  return (
    <div className="flex flex-col p-4 gap-6 pb-24 animate-fade-in">
      {/* Profile Header Row */}
      <div className="flex items-center gap-4">
        {/* Avatar */}
        <div className="w-20 h-20 rounded-full bg-gradient-to-br from-pale to-white flex items-center justify-center text-navy shrink-0 border-2 border-white shadow-md overflow-hidden relative">
          <UserIcon className="w-10 h-10 opacity-80" />
        </div>

        {/* Name & Bio */}
        <div className="flex flex-col gap-1 flex-1">
          <h2 className="text-xl font-bold text-navy font-sans">{profileName}</h2>
          <p className="text-xs text-gray-500 leading-snug font-sans font-medium whitespace-pre-line">
            {profileBio}
          </p>
        </div>
      </div>

      {/* Stats Row */}
      <div className="flex justify-between items-center px-4 py-4 bg-white rounded-2xl shadow-sm border border-pale/60">
        <StatItem label="الإعلانات" value={adsCount.toString()} />
        <div className="w-px h-8 bg-gray-100"></div>
        <StatItem label="اللايكات" value={isMe ? "27" : "12"} />
        <div className="w-px h-8 bg-gray-100"></div>
        <StatItem label="المشاهدات" value={isMe ? "1,240" : "540"} />
      </div>

      {/* Action Buttons */}
      <div className="flex gap-3">
        <a 
          href="https://wa.me/96598812020" 
          target="_blank" 
          rel="noopener noreferrer" 
          className="flex-1 flex items-center justify-center gap-2 py-2.5 rounded-xl border border-navy/20 bg-white text-navy font-bold text-sm hover:bg-pale/30 transition-colors active:scale-98"
        >
          <WhatsappIcon className="w-6 h-6" />
          <span>ارسال واتساب</span>
        </a>
        <a 
          href="tel:+96598812020" 
          className="flex-1 flex items-center justify-center gap-2 py-2.5 rounded-xl bg-navy text-white font-bold text-sm shadow-lg shadow-navy/20 hover:bg-blue transition-colors active:scale-98"
        >
          <PhoneIcon className="w-5 h-5" />
          <span>اتصال</span>
        </a>
      </div>

      {/* Listings Section */}
      <div className="flex flex-col gap-4 mt-2">
        <h3 className="text-lg font-bold text-navy font-sans px-1">
            {isMe ? 'اعلاناتي' : `إعلانات ${profileName}`}
        </h3>

        {/* Sub Tabs (Only for Me) */}
        {isMe && (
            <div className="flex p-1 bg-gray-100/80 rounded-xl relative">
            <button 
                onClick={() => handleTabChange('ads')}
                className={`flex-1 py-2 text-xs font-bold rounded-lg transition-all duration-300 font-sans ${
                activeSubTab === 'ads' 
                    ? 'bg-white shadow-[0_2px_8px_rgba(0,0,0,0.05)] text-navy' 
                    : 'text-gray-400 hover:text-gray-600'
                }`}
            >
                اعلاناتي
