            </div>
        )}

        {/* Grid */}
        <div className="grid grid-cols-2 gap-3 min-h-[200px]">
          {displayList.map(item => (
            <ListingCard 
                key={item.id} 
                listing={item} 
                onClick={() => onListingClick && onListingClick(item)}
            />
