import React, { useEffect, useState } from 'react';
import { getExploreListings } from '../utils/db';
import { Listing } from '../types';
import { PlayIcon, SpinnerIcon } from './Icons';

const FALLBACK_IMAGE = 'https://raiyansoft.com/wp-content/uploads/2026/01/1.png';

const ExplorePage: React.FC = () => {
  const [listings, setListings] = useState<Listing[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchExplore = async () => {
      setLoading(true);
      const data = await getExploreListings();
      setListings(data);
      setLoading(false);
    };
    fetchExplore();
  }, []);

  const handleClick = (id: number) => {
    window.location.hash = `#/ad/${id}`;
  };

  const getPoster = (l: Listing) => {
    // Use first image as poster
    if (l.images && l.images.length > 0) {
       const first = l.images[0];
       if (first instanceof File || first instanceof Blob) {
           return URL.createObjectURL(first);
       }
       return first as string;
    }
    if (l.imageUrl) {
        if (l.imageUrl instanceof File || l.imageUrl instanceof Blob) {
           return URL.createObjectURL(l.imageUrl);
        }
        return l.imageUrl as string;
    }
    return FALLBACK_IMAGE;
  };

  if (loading) {
    return (
      <div className="flex justify-center items-center h-full">
         <SpinnerIcon className="w-8 h-8 text-navy animate-spin" />
      </div>
    );
  }

  return (
    <div className="w-full h-full bg-bg overflow-y-auto no-scrollbar pb-24 animate-fade-in">
      {/* Grid */}
      <div className="grid grid-cols-2 gap-0.5">
         {listings.map(item => (
           <div 
             key={item.id}
             onClick={() => handleClick(item.id)}
             className="relative aspect-square bg-gray-200 cursor-pointer overflow-hidden group"
           >
             {/* Thumbnail */}
             <img 
               src={getPoster(item)} 
               alt={item.title}
               className="w-full h-full object-cover transition-transform duration-500 group-hover:scale-105"
               onError={(e) => e.currentTarget.src = FALLBACK_IMAGE}
             />

             {/* Dark Gradient Overlay */}
             <div className="absolute inset-0 bg-gradient-to-t from-black/60 via-transparent to-transparent opacity-80" />

             {/* Play Icon Center */}
             <div className="absolute inset-0 flex items-center justify-center">
                <div className="w-10 h-10 rounded-full bg-white/20 backdrop-blur-md flex items-center justify-center border border-white/30">
                    <PlayIcon className="w-5 h-5 text-white ml-0.5" />
                </div>
             </div>

             {/* Meta Info (Bottom) */}
             <div className="absolute bottom-0 left-0 right-0 p-3 flex flex-col justify-end text-white">
                <span className="font-bold text-sm drop-shadow-md truncate">{item.price}</span>
                <div className="flex items-center justify-between mt-0.5">
                   <span className="text-[10px] opacity-90 truncate max-w-[70%]">{item.area}</span>
                   <span className="text-[10px] opacity-75">{item.propertyType}</span>
                </div>
             </div>
           </div>
         ))}
      </div>

      {listings.length === 0 && (
          <div className="flex flex-col items-center justify-center h-64 text-gray-400">
             <PlayIcon className="w-12 h-12 mb-2 opacity-20" />
             <p className="text-sm">لا توجد فيديوهات حالياً</p>
          </div>
      )}
    </div>
  );
};

