  // Routing Hook
  useEffect(() => {
    const onHashChange = () => setCurrentHash(window.location.hash);
    window.addEventListener('hashchange', onHashChange);

    // Initial Route Set if empty
    if (!window.location.hash) {
      window.location.hash = '#/home';
    }

    return () => window.removeEventListener('hashchange', onHashChange);
  }, []);

  // Parse Route
  const routePath = currentHash.replace('#', '').split('?')[0] || '/home';

  // Determine Logic
  let activeTab = Tab.HOME;
  let listingId: number | null = null;

  if (routePath.startsWith('/home')) activeTab = Tab.HOME;
  else if (routePath.startsWith('/offices')) activeTab = Tab.OFFICES;
  else if (routePath.startsWith('/post-ad')) activeTab = Tab.ADD;
  else if (routePath.startsWith('/explore')) activeTab = Tab.EXPLORE;
  else if (routePath.startsWith('/profile')) activeTab = Tab.PROFILE;
  else if (routePath.startsWith('/ad/')) {
    activeTab = Tab.PROFILE; // Or keep previous? Profile is safe default for Back logic
    // Actually, keeping the active tab highlighted based on where we came from is hard without history state.
    // For now, let's just assume we might want to highlight Explore if we came from explore, or Home.
    // But simplistic logic: if ID is present, we are in details mode, Nav is hidden.
    const parts = routePath.split('/');
    if (parts.length >= 3) {
      listingId = parseInt(parts[2]);
    }
  }

  const getPageTitle = (tab: Tab): string => {
    switch (tab) {
      case Tab.HOME: return 'الرئيسية';
      case Tab.OFFICES: return 'المكاتب';
      case Tab.ADD: return 'انشر اعلانك';
      case Tab.EXPLORE: return 'اكسبلور';
      case Tab.PROFILE: return 'حسابي';
      default: return '80road';
    }
  };

  const handleWizardComplete = () => {
    window.location.hash = '#/profile';
    setLastUpdate(Date.now());
  };

  const handleListingClick = (listing: Listing) => {
    window.location.hash = `#/ad/${listing.id}`;
  };

  const handleBackFromDetails = () => {
    // Go back in history which will naturally trigger route change to previous
    window.history.back();
  };

  // Custom setter for tab change from nav (pushes route)
  // Not strictly needed since Nav uses hrefs now, but if passed as prop:
  const handleTabChange = () => {}; // Navigation component handles generic tabs via href

  return (
    <div 
      className="relative w-full max-w-[430px] mx-auto bg-bg sm:rounded-[40px] sm:shadow-2xl overflow-hidden shadow-2xl"
      style={{ height: 'calc(var(--vh, 1vh) * 100)' }}
    >
      {showSplash ? (
        <SplashScreen onFinish={() => setShowSplash(false)} />
      ) : (
        <>
          {/* Layer 1: Header (z-40) */}
          {!listingId && <Header title={getPageTitle(activeTab)} />}

          {/* Layer 2: Main Content Area (z-0 to z-10) */}
          <main 
            className="absolute left-0 right-0 overflow-hidden bg-bg animate-fade-in"
            style={{
              top: listingId ? '0' : 'calc(var(--header-h) + env(safe-area-inset-top))',
              bottom: listingId ? '0' : 'calc(var(--tab-h) + env(safe-area-inset-bottom))',
              zIndex: listingId ? 50 : 10
            }}
          >
             {listingId ? (
                <ListingDetailsPage 
                  listingId={listingId}
                  onBack={handleBackFromDetails} 
                />
             ) : (
               <>
                <div className={`absolute inset-0 ${activeTab === Tab.HOME ? 'block' : 'hidden'}`}>
                  <div className="h-full w-full overflow-y-auto overflow-x-hidden no-scrollbar pb-20">
                    <PlaceholderPage />
                  </div>
                </div>

                <div className={`absolute inset-0 ${activeTab === Tab.OFFICES ? 'block' : 'hidden'}`}>
                  <div className="h-full w-full overflow-y-auto overflow-x-hidden no-scrollbar pb-20">
                    <OfficesPage />
                  </div>
                </div>

                <div className={`absolute inset-0 ${activeTab === Tab.ADD ? 'block' : 'hidden'}`}>
                   <AddWizard onComplete={handleWizardComplete} />
                </div>

                <div className={`absolute inset-0 ${activeTab === Tab.EXPLORE ? 'block' : 'hidden'}`}>
                  <div className="h-full w-full overflow-y-auto overflow-x-hidden no-scrollbar pb-20">
                    {/* Replaced Placeholder with ExplorePage */}
                    <ExplorePage />
                  </div>
                </div>

                <div className={`absolute inset-0 ${activeTab === Tab.PROFILE ? 'block' : 'hidden'}`}>
                   <div className="h-full w-full overflow-y-auto overflow-x-hidden no-scrollbar pb-20">
                     <ProfilePage 
                        key={lastUpdate} 
                        onListingClick={handleListingClick}
                     />
                   </div>
                </div>
               </>
             )}
          </main>

          {/* Layer 3: Bottom Navigation (z-40) */}
          {!listingId && (
            <BottomNavigation 
                activeTab={activeTab} 
                onTabChange={handleTabChange} 
            />
          )}
        </>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { SpinnerIcon, ChevronRightIcon, PhoneIcon } from './Icons';

interface AuthPageProps {
  onLoginSuccess: () => void;
}

const AuthPage: React.FC<AuthPageProps> = ({ onLoginSuccess }) => {
  const [step, setStep] = useState<'PHONE' | 'OTP'>('PHONE');
  const [phone, setPhone] = useState('98812020'); // Demo default
  const [otp, setOtp] = useState(['', '', '', '']);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [timer, setTimer] = useState(30);
  const inputs = useRef<(HTMLInputElement | null)[]>([]);

  // Sync route with internal step on mount/hash change
  useEffect(() => {
    const handleHash = () => {
      const hash = window.location.hash;
      if (hash.includes('/verify')) {
         const storedPhone = sessionStorage.getItem('temp_auth_phone');
         if (!storedPhone) {
            window.location.hash = '#/auth';
            setStep('PHONE');
         } else {
            setStep('OTP');
            setPhone(storedPhone);
         }
      } else {
         setStep('PHONE');
      }
    };

    handleHash();
    window.addEventListener('hashchange', handleHash);
    return () => window.removeEventListener('hashchange', handleHash);
  }, []);

  // Timer logic for OTP
  useEffect(() => {
    let interval: any;
    if (step === 'OTP' && timer > 0) {
      interval = setInterval(() => setTimer((t) => t - 1), 1000);
    }
    return () => clearInterval(interval);
  }, [step, timer]);

  const handlePhoneSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');

    // Basic Validation
    if (!phone || phone.length < 8 || isNaN(Number(phone))) {
       setError('يرجى إدخال رقم هاتف صحيح');
       return;
    }

    setLoading(true);
    // Simulate API call
    setTimeout(() => {
       setLoading(false);
       sessionStorage.setItem('temp_auth_phone', phone);
       window.location.hash = '#/verify';
    }, 800);
  };

  const handleOtpChange = (index: number, value: string) => {
    if (value.length > 1) value = value[0];
    if (!/^\d*$/.test(value)) return;

    const newOtp = [...otp];
    newOtp[index] = value;
    setOtp(newOtp);

    // Auto focus next
    if (value && index < 3) {
      inputs.current[index + 1]?.focus();
    }

    // Clear error on change
    if (error) setError('');
  };

  const handleKeyDown = (index: number, e: React.KeyboardEvent) => {
    if (e.key === 'Backspace' && !otp[index] && index > 0) {
      inputs.current[index - 1]?.focus();
    }
  };

  const handleVerify = async () => {
    const code = otp.join('');
    if (code.length !== 4) return;

    setLoading(true);
    setError('');

    setTimeout(() => {
       if (code === '1234') {
          // Success
          const session = {
             phone,
             token: 'demo_token_' + Date.now(),
             loggedInAt: Date.now()
          };
          localStorage.setItem('road80_user', JSON.stringify(session));
          onLoginSuccess();
       } else {
          setError('رمز التفعيل غير صحيح');
          setLoading(false);
          setOtp(['', '', '', '']);
          inputs.current[0]?.focus();
       }
    }, 1000);
  };

  const handleResend = () => {
     if (timer > 0) return;
     setTimer(30);
     // Simulate resend
     alert('تم إعادة إرسال الرمز (1234)');
  };

  return (
    <div className="min-h-full w-full bg-white flex flex-col relative overflow-hidden animate-fade-in">
      {/* Decorative Background */}
      <div className="absolute top-0 left-0 right-0 h-64 bg-navy rounded-b-[40%] scale-x-150 -translate-y-20 z-0" />

      {/* Content Container */}
      <div className="flex-1 flex flex-col z-10 px-6 pt-20">

        {/* Logo Area */}
        <div className="flex flex-col items-center mb-12">
            <div className="w-20 h-20 bg-white rounded-2xl shadow-xl flex items-center justify-center mb-4">
               <img src="https://raiyansoft.com/wp-content/uploads/2026/01/logo-road80-favicon-1.png" className="w-12 h-12" alt="Logo" />
            </div>
            <h1 className="text-2xl font-bold text-white mb-1">
               {step === 'PHONE' ? 'أهلاً بك' : 'التحقق'}
            </h1>
            <p className="text-white/80 text-sm">
               {step === 'PHONE' ? 'سجل دخولك للمتابعة في 80road' : `تم إرسال الرمز إلى ${phone}`}
            </p>
        </div>

        {/* Card */}
        <div className="bg-white rounded-3xl shadow-[0_10px_40px_rgba(0,0,0,0.08)] p-8 flex flex-col gap-6 border border-gray-100">

           {step === 'PHONE' ? (
             <form onSubmit={handlePhoneSubmit} className="flex flex-col gap-6">
                <div>
                   <label className="block text-xs font-bold text-gray-500 mb-2 mr-1">رقم الهاتف</label>
                   <div className="relative">
                      <input 
                        type="tel"
                        dir="ltr"
                        value={phone}
                        onChange={(e) => setPhone(e.target.value)}
                        className="w-full h-14 bg-bg rounded-xl px-4 text-left font-sans font-bold text-lg text-navy focus:outline-none focus:ring-2 focus:ring-navy/20 transition-all placeholder:text-gray-300"
                        placeholder="12345678"
                        maxLength={8}
                      />
                      <div className="absolute top-0 right-0 h-full flex items-center px-4 pointer-events-none">
                         <span className="text-gray-400 font-bold text-sm tracking-wider">🇰🇼 +965</span>
                      </div>
                   </div>
                </div>

                <button 
                  type="submit"
                  disabled={loading}
                  className="w-full h-14 bg-navy text-white rounded-xl font-bold text-lg shadow-lg shadow-navy/20 active:scale-95 transition-all flex items-center justify-center gap-2"
                >
                  {loading ? <SpinnerIcon className="w-6 h-6 animate-spin text-white" /> : 'إرسال رمز التفعيل'}
                </button>
             </form>
           ) : (
             <div className="flex flex-col gap-8">
                <div className="flex flex-col gap-2">
                   <label className="block text-xs font-bold text-gray-500 mr-1 text-center">أدخل الرمز المكون من 4 أرقام</label>
                   <div className="flex justify-between items-center px-2" dir="ltr">
                      {otp.map((digit, idx) => (
                         <input
                           key={idx}
                           ref={el => inputs.current[idx] = el}
                           type="text"
                           inputMode="numeric"
                           maxLength={1}
                           value={digit}
                           onChange={(e) => handleOtpChange(idx, e.target.value)}
                           onKeyDown={(e) => handleKeyDown(idx, e)}
                           className={`w-14 h-16 rounded-2xl border-2 text-center text-2xl font-bold transition-all focus:outline-none ${
                              digit ? 'border-navy bg-white text-navy' : 'border-gray-100 bg-gray-50'
                           } ${error ? 'border-red-500 bg-red-50' : ''}`}
                         />
                      ))}
                   </div>
                </div>

                <button 
                  onClick={handleVerify}
                  disabled={loading || otp.join('').length !== 4}
                  className={`w-full h-14 rounded-xl font-bold text-lg shadow-lg transition-all flex items-center justify-center gap-2 ${
                     otp.join('').length === 4 
                     ? 'bg-navy text-white shadow-navy/20 active:scale-95' 
                     : 'bg-gray-200 text-gray-400 cursor-not-allowed'
                  }`}
                >
                  {loading ? <SpinnerIcon className="w-6 h-6 animate-spin" /> : 'تأكيد'}
                </button>

                <div className="flex flex-col items-center gap-4">
                   <button 
                     onClick={handleResend}
                     disabled={timer > 0}
                     className={`text-sm font-bold ${timer > 0 ? 'text-gray-300' : 'text-blue'}`}
                   >
                     {timer > 0 ? `إعادة الإرسال بعد ${timer} ثانية` : 'إعادة إرسال الرمز'}
                   </button>

                   <button 
                     onClick={() => window.location.hash = '#/auth'}
                     className="text-xs text-gray-400 hover:text-navy transition-colors"
                   >
                     تغيير رقم الهاتف
                   </button>
                </div>
             </div>
           )}

           {error && (
              <div className="p-3 bg-red-50 text-red-500 text-xs font-bold text-center rounded-lg animate-fade-in">
                 {error}
              </div>
           )}

        </div>

        {/* Footer */}
        <div className="mt-auto pb-8 text-center">
           <p className="text-xs text-gray-400">
              بتسجيل الدخول فإنك توافق على <br/>
              <span className="underline">الشروط والأحكام</span> و <span className="underline">سياسة الخصوصية</span>
           </p>
        </div>

      </div>
    </div>
  );
};

export default AuthPage;

import React, { useState, useEffect } from 'react';
import SplashScreen from './components/SplashScreen';
import BottomNavigation from './components/BottomNavigation';
import PlaceholderPage from './components/PlaceholderPage';
import ProfilePage from './components/ProfilePage';
import AddWizard from './components/AddWizard';
import ListingDetailsPage from './components/ListingDetailsPage';
import OfficesPage from './components/OfficesPage';
import ExplorePage from './components/ExplorePage';
import AuthPage from './components/AuthPage';
import Header from './components/Header';
import { Tab, Listing } from './types';

const App: React.FC = () => {
  const [showSplash, setShowSplash] = useState(true);
  const [currentHash, setCurrentHash] = useState(window.location.hash);
  const [lastUpdate, setLastUpdate] = useState(Date.now());
  const [isAuthenticated, setIsAuthenticated] = useState(false);

  // Check auth on mount
  useEffect(() => {
    const user = localStorage.getItem('road80_user');
    if (user) {
      setIsAuthenticated(true);
    }
  }, []);

  // Routing Hook
  useEffect(() => {
    const onHashChange = () => setCurrentHash(window.location.hash);
    window.addEventListener('hashchange', onHashChange);

    // Initial Route Set if empty
    if (!window.location.hash) {
      window.location.hash = '#/home';
    }

    return () => window.removeEventListener('hashchange', onHashChange);
  }, []);

  // Parse Route
  const routePath = currentHash.replace('#', '').split('?')[0] || '/home';
  const isAuthRoute = ['/auth', '/verify'].includes(routePath);

  // Route Guards
  useEffect(() => {
    if (!showSplash) {
      if (!isAuthenticated && !isAuthRoute) {
        // Not logged in -> Redirect to Auth
        window.location.hash = '#/auth';
      } else if (isAuthenticated && isAuthRoute) {
        // Logged in but on Auth page -> Redirect to Home
        window.location.hash = '#/home';
      }
    }
  }, [showSplash, isAuthenticated, isAuthRoute, routePath]);

  // Determine Logic
  let activeTab = Tab.HOME;
  let listingId: number | null = null;

  if (routePath.startsWith('/home')) activeTab = Tab.HOME;
  else if (routePath.startsWith('/offices')) activeTab = Tab.OFFICES;
  else if (routePath.startsWith('/post-ad')) activeTab = Tab.ADD;
  else if (routePath.startsWith('/explore')) activeTab = Tab.EXPLORE;
  else if (routePath.startsWith('/profile')) activeTab = Tab.PROFILE;
  else if (routePath.startsWith('/ad/')) {
    activeTab = Tab.PROFILE; 
    const parts = routePath.split('/');
    if (parts.length >= 3) {
      listingId = parseInt(parts[2]);
    }
  }

  const getPageTitle = (tab: Tab): string => {
    switch (tab) {
      case Tab.HOME: return 'الرئيسية';
      case Tab.OFFICES: return 'المكاتب';
      case Tab.ADD: return 'انشر اعلانك';
      case Tab.EXPLORE: return 'اكسبلور';
      case Tab.PROFILE: return 'حسابي';
      default: return '80road';
    }
  };

  const handleWizardComplete = () => {
    window.location.hash = '#/profile';
    setLastUpdate(Date.now());
  };

  const handleListingClick = (listing: Listing) => {
    window.location.hash = `#/ad/${listing.id}`;
  };

  const handleBackFromDetails = () => {
    window.history.back();
  };

  const handleTabChange = () => {}; 

  const handleLoginSuccess = () => {
    setIsAuthenticated(true);
    window.location.hash = '#/home';
  };

  return (
    <div 
      className="relative w-full max-w-[430px] mx-auto bg-bg sm:rounded-[40px] sm:shadow-2xl overflow-hidden shadow-2xl"
      style={{ height: 'calc(var(--vh, 1vh) * 100)' }}
    >
      {showSplash ? (
        <SplashScreen onFinish={() => setShowSplash(false)} />
      ) : (
        <>
          {/* Auth Flow */}
          {(!isAuthenticated || isAuthRoute) ? (
             <AuthPage onLoginSuccess={handleLoginSuccess} />
          ) : (
            /* Protected App Shell */
            <>
              {/* Layer 1: Header (z-40) */}
              {!listingId && <Header title={getPageTitle(activeTab)} />}

              {/* Layer 2: Main Content Area (z-0 to z-10) */}
              <main 
                className="absolute left-0 right-0 overflow-hidden bg-bg animate-fade-in"
                style={{
                  top: listingId ? '0' : 'calc(var(--header-h) + env(safe-area-inset-top))',
                  bottom: listingId ? '0' : 'calc(var(--tab-h) + env(safe-area-inset-bottom))',
                  zIndex: listingId ? 50 : 10
                }}
              >
                 {listingId ? (
                    <ListingDetailsPage 
                      listingId={listingId}
                      onBack={handleBackFromDetails} 
                    />
                 ) : (
                   <>
                    <div className={`absolute inset-0 ${activeTab === Tab.HOME ? 'block' : 'hidden'}`}>
                      <div className="h-full w-full overflow-y-auto overflow-x-hidden no-scrollbar pb-20">
                        <PlaceholderPage />
                      </div>
                    </div>

                    <div className={`absolute inset-0 ${activeTab === Tab.OFFICES ? 'block' : 'hidden'}`}>
                      <div className="h-full w-full overflow-y-auto overflow-x-hidden no-scrollbar pb-20">
                        <OfficesPage />
                      </div>
                    </div>

                    <div className={`absolute inset-0 ${activeTab === Tab.ADD ? 'block' : 'hidden'}`}>
                       <AddWizard onComplete={handleWizardComplete} />
                    </div>

                    <div className={`absolute inset-0 ${activeTab === Tab.EXPLORE ? 'block' : 'hidden'}`}>
                      <div className="h-full w-full overflow-y-auto overflow-x-hidden no-scrollbar pb-20">
                        <ExplorePage />
                      </div>
                    </div>

                    <div className={`absolute inset-0 ${activeTab === Tab.PROFILE ? 'block' : 'hidden'}`}>
                       <div className="h-full w-full overflow-y-auto overflow-x-hidden no-scrollbar pb-20">
                         <ProfilePage 
                            key={lastUpdate} 
                            onListingClick={handleListingClick}
                         />
                       </div>
                    </div>
                   </>
                 )}
              </main>

              {/* Layer 3: Bottom Navigation (z-40) */}
              {!listingId && (
                <BottomNavigation 
                    activeTab={activeTab} 
                    onTabChange={handleTabChange} 
                />
              )}
            </>
          )}
        </>
      )}
    </div>
  );
};

export default App;

import React, { useEffect, useState } from 'react';
import { SpinnerIcon } from './Icons';

interface SplashScreenProps {
  onFinish: () => void;
}

const SplashScreen: React.FC<SplashScreenProps> = ({ onFinish }) => {
  const [isFading, setIsFading] = useState(false);

  useEffect(() => {
    // Start fade out slightly before 3s to ensure smooth transition ending around 3s
    const timer = setTimeout(() => {
      setIsFading(true);
      // Wait for animation to finish before unmounting
      setTimeout(onFinish, 500); 
    }, 2500);

    return () => clearTimeout(timer);
  }, [onFinish]);

  return (
    <div className={`absolute inset-0 z-50 flex flex-col items-center justify-center bg-gradient-to-br from-bg to-pale ${isFading ? 'animate-fade-out' : ''}`}>
      <div className="flex flex-col items-center gap-8">
        <img 
          src="https://raiyansoft.com/wp-content/uploads/2026/02/sg54.png" 
          alt="80road Logo" 
          className="w-40 h-auto animate-fade-in"
        />
        <SpinnerIcon className="w-8 h-8 text-navy animate-spin" />
      </div>
    </div>
  );
};

