import React, { useState, useEffect, useRef } from 'react';
import { SpinnerIcon, ChevronRightIcon, PhoneIcon } from './Icons';

interface AuthPageProps {
  onLoginSuccess: () => void;
}

const AuthPage: React.FC<AuthPageProps> = ({ onLoginSuccess }) => {
  const [step, setStep] = useState<'PHONE' | 'OTP'>('PHONE');
  const [phone, setPhone] = useState('98812020'); // Demo default
  const [otp, setOtp] = useState(['', '', '', '']);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [timer, setTimer] = useState(30);
  const inputs = useRef<(HTMLInputElement | null)[]>([]);

  // Sync route with internal step on mount/hash change
  useEffect(() => {
    const handleHash = () => {
      const hash = window.location.hash;
      if (hash.includes('/verify')) {
         const storedPhone = sessionStorage.getItem('temp_auth_phone');
         if (!storedPhone) {
            window.location.hash = '#/auth';
            setStep('PHONE');
         } else {
            setStep('OTP');
            setPhone(storedPhone);
         }
      } else {
         setStep('PHONE');
      }
    };

    handleHash();
    window.addEventListener('hashchange', handleHash);
    return () => window.removeEventListener('hashchange', handleHash);
  }, []);

  // Timer logic for OTP
  useEffect(() => {
    let interval: any;
    if (step === 'OTP' && timer > 0) {
      interval = setInterval(() => setTimer((t) => t - 1), 1000);
    }
    return () => clearInterval(interval);
  }, [step, timer]);

  const handlePhoneSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');

    // Basic Validation
    if (!phone || phone.length < 8 || isNaN(Number(phone))) {
       setError('يرجى إدخال رقم هاتف صحيح');
       return;
    }

    setLoading(true);
    // Simulate API call
    setTimeout(() => {
       setLoading(false);
       sessionStorage.setItem('temp_auth_phone', phone);
       window.location.hash = '#/verify';
    }, 800);
  };

  const handleOtpChange = (index: number, value: string) => {
    if (value.length > 1) value = value[0];
    if (!/^\d*$/.test(value)) return;

    const newOtp = [...otp];
    newOtp[index] = value;
    setOtp(newOtp);

    // Auto focus next
    if (value && index < 3) {
      inputs.current[index + 1]?.focus();
    }

    // Clear error on change
    if (error) setError('');
  };

  const handleKeyDown = (index: number, e: React.KeyboardEvent) => {
    if (e.key === 'Backspace' && !otp[index] && index > 0) {
      inputs.current[index - 1]?.focus();
    }
  };

  const handleVerify = async () => {
    const code = otp.join('');
    if (code.length !== 4) return;

    setLoading(true);
    setError('');

    setTimeout(() => {
       if (code === '1234') {
          // Success
          const session = {
             phone,
             token: 'demo_token_' + Date.now(),
             loggedInAt: Date.now()
          };
          localStorage.setItem('road80_user', JSON.stringify(session));
          onLoginSuccess();
       } else {
          setError('رمز التفعيل غير صحيح');
          setLoading(false);
          setOtp(['', '', '', '']);
          inputs.current[0]?.focus();
       }
    }, 1000);
  };

  const handleResend = () => {
     if (timer > 0) return;
     setTimer(30);
     // Simulate resend
     alert('تم إعادة إرسال الرمز (1234)');
  };

  return (
    <div className="min-h-full w-full bg-slate-50 flex flex-col items-center justify-center relative overflow-hidden animate-fade-in p-6">

      {/* Soft Background Blobs */}
      <div className="absolute top-[-10%] left-[-10%] w-[60%] h-[40%] bg-blue/5 rounded-full blur-3xl pointer-events-none" />
      <div className="absolute bottom-[-10%] right-[-10%] w-[60%] h-[40%] bg-navy/5 rounded-full blur-3xl pointer-events-none" />

      {/* Main Content Container */}
      <div className="w-full max-w-[340px] flex flex-col items-center z-10">

        {/* Logo */}
        <div className="mb-8">
           <img 
              src="https://raiyansoft.com/wp-content/uploads/2026/02/sg54.png" 
              className="w-32 h-auto drop-shadow-sm" 
              alt="Logo" 
           />
        </div>

        {/* Floating Sheet Card */}
        <div className="w-full bg-white rounded-[32px] shadow-[0_8px_30px_rgba(0,0,0,0.04)] p-8 border border-white/60">

           {/* Header Text */}
           <div className="text-center mb-8">
              <h1 className="text-2xl font-bold text-navy mb-2">
                 {step === 'PHONE' ? 'تسجيل الدخول' : 'التحقق'}
              </h1>
              <p className="text-gray-400 text-xs font-medium">
                 {step === 'PHONE' 
                    ? 'أهلاً بك في منصة 80road العقارية' 
                    : `تم إرسال رمز التفعيل إلى ${phone}`
                 }
              </p>
           </div>

           {step === 'PHONE' ? (
             <form onSubmit={handlePhoneSubmit} className="flex flex-col gap-6">

                {/* Phone Input Group */}
                <div className="flex flex-col gap-2">
                   <label className="text-xs font-bold text-gray-500 mr-2">رقم الهاتف</label>

                   {/* Container enforced to LTR to keep [Code] [Divider] [Input] order correct visually */}
                   <div 
                     dir="ltr"
                     className="relative h-16 bg-slate-50 rounded-2xl flex items-center px-4 border border-transparent focus-within:border-navy/20 focus-within:bg-white focus-within:ring-4 focus-within:ring-navy/5 transition-all"
                   >
                      {/* Country Code (Left) */}
                      <div className="flex items-center gap-2 shrink-0 text-navy select-none">
                         <span className="text-2xl pt-1">🇰🇼</span>
                         <span className="text-sm font-bold tracking-wider">+965</span>
                      </div>

                      {/* Divider */}
                      <div className="w-px h-6 bg-gray-200 shrink-0 mx-3"></div>

                      {/* Input (Right) */}
                      <input 
                        type="tel"
                        value={phone}
                        onChange={(e) => setPhone(e.target.value)}
                        className="flex-1 bg-transparent h-full text-left font-sans font-bold text-xl text-navy placeholder:text-gray-300 focus:outline-none tracking-wider"
                        placeholder="00000000"
                        maxLength={8}
                      />
                   </div>
                </div>

                <button 
                  type="submit"
                  disabled={loading}
                  className="w-full h-14 bg-navy text-white rounded-2xl font-bold text-lg shadow-lg shadow-navy/20 hover:bg-blue active:scale-95 transition-all flex items-center justify-center gap-2 mt-2"
                >
                  {loading ? <SpinnerIcon className="w-6 h-6 animate-spin text-white" /> : 'إرسال رمز التفعيل'}
                </button>
             </form>
           ) : (
             <div className="flex flex-col gap-8">

                {/* OTP Inputs */}
                <div className="flex justify-between items-center px-1" dir="ltr">
                   {otp.map((digit, idx) => (
                      <input
                        key={idx}
                        ref={el => inputs.current[idx] = el}
                        type="text"
                        inputMode="numeric"
                        maxLength={1}
                        value={digit}
                        onChange={(e) => handleOtpChange(idx, e.target.value)}
                        onKeyDown={(e) => handleKeyDown(idx, e)}
                        className={`w-14 h-16 rounded-2xl border-2 text-center text-2xl font-bold transition-all focus:outline-none focus:ring-4 focus:ring-navy/10 ${
                           digit ? 'border-navy bg-white text-navy' : 'border-gray-100 bg-slate-50 text-gray-800'
                        } ${error ? 'border-red-500 bg-red-50' : ''}`}
                      />
                   ))}
                </div>

                <button 
                  onClick={handleVerify}
                  disabled={loading || otp.join('').length !== 4}
                  className={`w-full h-14 rounded-2xl font-bold text-lg shadow-lg transition-all flex items-center justify-center gap-2 ${
                     otp.join('').length === 4 
                     ? 'bg-navy text-white shadow-navy/20 active:scale-95 hover:bg-blue' 
                     : 'bg-gray-100 text-gray-400 cursor-not-allowed'
                  }`}
                >
                  {loading ? <SpinnerIcon className="w-6 h-6 animate-spin" /> : 'تأكيد'}
                </button>

                {/* Resend & Back */}
                <div className="flex flex-col items-center gap-4 -mt-2">
                   <button 
                     onClick={handleResend}
                     disabled={timer > 0}
                     className={`text-xs font-bold transition-colors ${timer > 0 ? 'text-gray-400' : 'text-blue hover:text-navy'}`}
                   >
                     {timer > 0 ? `إعادة الإرسال بعد ${timer} ثانية` : 'إعادة إرسال الرمز'}
                   </button>

                   <button 
                     onClick={() => window.location.hash = '#/auth'}
                     className="text-xs text-gray-400 hover:text-navy transition-colors py-2 px-4 hover:bg-slate-50 rounded-lg"
                   >
                     تغيير رقم الهاتف
                   </button>
                </div>
             </div>
           )}

           {error && (
              <div className="mt-4 p-3 bg-red-50 text-red-500 text-xs font-bold text-center rounded-xl animate-fade-in border border-red-100">
                 {error}
              </div>
           )}

        </div>

        {/* Footer Text */}
        <div className="mt-8 text-center px-4 opacity-60 hover:opacity-100 transition-opacity">
           <p className="text-[10px] text-gray-500 leading-relaxed">
              بتسجيل الدخول فإنك توافق على 
              <span className="underline cursor-pointer hover:text-navy mx-1">الشروط والأحكام</span> 
              و 
              <span className="underline cursor-pointer hover:text-navy mx-1">سياسة الخصوصية</span>
           </p>
        </div>

      </div>
    </div>
  );
};

