import React, { useState, useEffect } from 'react';
import { GOVERNORATES, AREAS } from '../data/locations';

interface QuickWizardProps {
  onComplete: () => void;
}

const QuickWizard: React.FC<QuickWizardProps> = ({ onComplete }) => {
  const isEditMode = window.location.hash.includes('mode=edit');

  // If edit mode, start at step 2 (Purpose)
  const [step, setStep] = useState(isEditMode ? 2 : 1);
  const [data, setData] = useState({
    name: '',
    purpose: '',
    propertyType: '',
    governorate: '',
    area: ''
  });

  // Load existing preferences if available
  useEffect(() => {
    const saved = localStorage.getItem('road80_preferences');
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        setData(prev => ({ ...prev, ...parsed }));
      } catch (e) {}
    }
  }, []);

  const handleNext = () => {
    if (step < 5) setStep(step + 1);
    else handleFinish();
  };

  const handleBack = () => {
    if (isEditMode && step === 2) {
       // Cancel edit, go back to home
       onComplete();
       return;
    }
    if (step > 1) setStep(step - 1);
  };

  const handleSelect = (key: string, value: string) => {
    const newData = { ...data, [key]: value };

    // If changing governorate, reset area if it doesn't match new gov
    if (key === 'governorate' && data.governorate !== value) {
         newData.area = '';
    }

    setData(newData);

    // Auto advance
    if (step < 5) {
        setTimeout(() => setStep(step + 1), 150);
    } else {
        setTimeout(() => saveAndComplete(newData), 150);
    }
  };

  const saveAndComplete = (finalData: typeof data) => {
      localStorage.setItem('road80_preferences', JSON.stringify(finalData));
      onComplete();
  };

  const handleFinish = () => {
      saveAndComplete(data);
  };

  const renderHeader = (title: string, subtitle?: string) => (
      <div className="mb-8 text-center animate-fade-in">
          <h2 className="text-2xl font-bold text-navy mb-2">{title}</h2>
          {subtitle && <p className="text-gray-400 text-sm">{subtitle}</p>}
      </div>
  );

  const renderOption = (label: string, isSelected: boolean, onClick: () => void) => (
    <button
      onClick={onClick}
      className={`w-full p-4 mb-3 rounded-2xl border flex items-center justify-between transition-all duration-200 active:scale-95 ${
        isSelected 
          ? 'border-navy bg-navy text-white shadow-lg shadow-navy/20' 
          : 'border-pale bg-white text-navy hover:border-mid hover:bg-slate-50'
      }`}
    >
      <span className="font-bold text-lg">{label}</span>
      {isSelected && <span className="text-white font-bold text-xl">✓</span>}
    </button>
  );

  return (
    <div className="w-full h-full bg-bg flex flex-col relative overflow-hidden">
        {/* Header / Progress */}
        <div className="px-6 pt-8 pb-4">
            <div className="w-full h-1.5 bg-pale rounded-full overflow-hidden mb-8">
                <div 
                    className="h-full bg-navy transition-all duration-500 rounded-full"
                    style={{ width: `${(step / 5) * 100}%` }}
                />
            </div>
        </div>

        {/* Scrollable Content */}
        <div className="flex-1 overflow-y-auto no-scrollbar px-6 pb-24">
            {step === 1 && !isEditMode && (
                <div className="flex flex-col h-full justify-center -mt-20">
                    {renderHeader('مرحباً بك 👋', 'الرجاء إدخال اسمك لنبدأ')}
                    <input 
                        type="text"
                        value={data.name}
                        onChange={(e) => setData({...data, name: e.target.value})}
                        placeholder="الاسم الكامل"
                        className="w-full h-16 rounded-2xl border border-pale px-6 text-xl font-bold text-navy focus:border-navy focus:outline-none bg-white text-center shadow-sm placeholder:text-gray-300"
                        autoFocus
                    />
                </div>
            )}

            {step === 2 && (
                <>
                    {renderHeader('ماذا تبحث؟')}
                    {['للبيع', 'للإيجار'].map(opt => (
                        renderOption(opt, data.purpose === opt, () => handleSelect('purpose', opt))
                    ))}
                </>
            )}

            {step === 3 && (
                <>
                    {renderHeader('نوع العقار')}
                    {['بيت', 'شقة', 'دور', 'عمارة', 'دوبلكس'].map(opt => (
                        renderOption(opt, data.propertyType === opt, () => handleSelect('propertyType', opt))
                    ))}
                </>
            )}

            {step === 4 && (
                <>
                    {renderHeader('المحافظة')}
                    {GOVERNORATES.map(opt => (
                        renderOption(opt, data.governorate === opt, () => handleSelect('governorate', opt))
                    ))}
                </>
            )}

            {step === 5 && (
                <>
                    {renderHeader('المنطقة', data.governorate)}
                    {(AREAS[data.governorate] || []).map(opt => (
                        renderOption(opt, data.area === opt, () => handleSelect('area', opt))
                    ))}
                </>
            )}
        </div>

        {/* Fixed Bottom Action */}
        <div className="absolute bottom-0 left-0 right-0 p-6 bg-gradient-to-t from-bg via-bg to-transparent z-10">
            {step === 1 && !isEditMode ? (
                <button 
                    onClick={handleNext}
                    disabled={!data.name.trim()}
                    className={`w-full py-4 rounded-xl font-bold text-white shadow-lg transition-all ${
                        data.name.trim() ? 'bg-navy shadow-navy/20 active:scale-95 hover:bg-blue' : 'bg-gray-300 cursor-not-allowed'
                    }`}
                >
                    التالي
                </button>
            ) : (
                <button 
                    onClick={handleBack}
                    className="w-full py-4 bg-transparent text-gray-400 font-bold hover:text-navy transition-colors"
                >
                    {isEditMode && step === 2 ? 'إلغاء' : 'رجوع'}
                </button>
            )}
        </div>
    </div>
  );
};

export default QuickWizard;

import React, { useState, useEffect, useRef } from 'react';
import { Listing } from '../types';
import { DEMO_ADS } from '../utils/db';
