const BannerSlider: React.FC = () => {
  const sliderRef = useRef<HTMLDivElement>(null);
  const [currentIndex, setCurrentIndex] = useState(0);

  useEffect(() => {
    const timer = setInterval(() => {
      setCurrentIndex(prev => (prev + 1) % SLIDER_IMAGES.length);
    }, 1500);
    return () => clearInterval(timer);
  }, []);

  useEffect(() => {
    if (sliderRef.current) {
        // In RTL, index 0 is on the right, index 1 is on the left.
        // To slide to index 1, we move the view to the left (content moves right).
        const target = sliderRef.current.children[currentIndex] as HTMLElement;
        if (target) {
            target.scrollIntoView({ behavior: 'smooth', block: 'nearest', inline: 'center' });
        }
    }
  }, [currentIndex]);

  return (
    <div 
        ref={sliderRef}
        className="w-full aspect-[2.5/1] relative overflow-x-auto flex snap-x snap-mandatory no-scrollbar rounded-2xl touch-pan-x"
        dir="rtl" // Ensure RTL context for correct ordering [Img1, Img2]
    >
      {SLIDER_IMAGES.map((src, index) => (
        <img
          key={index}
          src={src}
          alt="Banner"
          className="w-full h-full object-cover flex-shrink-0 snap-center pointer-events-none select-none"
        />
      ))}
    </div>
  );
};

