];

const BannerSlider: React.FC = () => {
  const [currentIndex, setCurrentIndex] = useState(0);
  const touchStartX = useRef<number | null>(null);

  useEffect(() => {
    const timer = setInterval(() => {
      setCurrentIndex(prev => (prev + 1) % SLIDER_IMAGES.length);
    }, 1500);
    return () => clearInterval(timer);
  }, []);

  const handleTouchStart = (e: React.TouchEvent) => {
    touchStartX.current = e.touches[0].clientX;
  };

  const handleTouchEnd = (e: React.TouchEvent) => {
    if (touchStartX.current === null) return;
    const touchEndX = e.changedTouches[0].clientX;
    const diff = touchStartX.current - touchEndX;

    // RTL Swipe Logic:
    // Swipe Right (Move finger L -> R): diff < 0 -> Next Slide
    // Swipe Left (Move finger R -> L): diff > 0 -> Prev Slide
    if (Math.abs(diff) > 50) {
        if (diff < 0) {
            setCurrentIndex(prev => (prev + 1) % SLIDER_IMAGES.length);
        } else {
            setCurrentIndex(prev => (prev - 1 + SLIDER_IMAGES.length) % SLIDER_IMAGES.length);
        }
    }
    touchStartX.current = null;
  };

  return (
    <div 
        className="w-full aspect-[2.5/1] relative overflow-hidden rounded-2xl touch-pan-y"
        dir="rtl"
    >
      <div 
        className="flex w-full h-full transition-transform duration-500 ease-in-out"
        style={{ transform: `translateX(${currentIndex * 100}%)` }}
        onTouchStart={handleTouchStart}
        onTouchEnd={handleTouchEnd}
      >
        {SLIDER_IMAGES.map((src, index) => (
          <img
            key={index}
            src={src}
            alt="Banner"
            className="w-full h-full object-cover flex-shrink-0 select-none pointer-events-none"
          />
        ))}
      </div>
    </div>
  );
};

