import React, { useState, useRef, useEffect } from 'react';
import { ChevronRightIcon, PlayIcon, CheckIcon, UserIcon, PhoneIcon, WhatsappIcon, BuildingIcon, SpinnerIcon, LockIcon, AppleIcon } from './Icons';
import { Listing } from '../types';
import { getListingById } from '../utils/db';

interface ListingDetailsPageProps {
  listingId: number;
  onBack: () => void;
}

const FALLBACK_IMAGE = 'https://raiyansoft.com/wp-content/uploads/2026/01/1.png';
const UNLOCK_FEE = '1 د.ك';

interface MediaItem {
  type: 'image' | 'video';
  src: string | File | Blob;
  id: string;
}

const ListingDetailsPage: React.FC<ListingDetailsPageProps> = ({ listingId, onBack }) => {
  const [listing, setListing] = useState<Listing | null>(null);
  const [loading, setLoading] = useState(true);
  const [activeImageIndex, setActiveImageIndex] = useState(0);
  const scrollRef = useRef<HTMLDivElement>(null);
  const thumbsRef = useRef<HTMLDivElement>(null);

  const [isUnlocked, setIsUnlocked] = useState(false);
  const [showUnlockPopup, setShowUnlockPopup] = useState(false);

  useEffect(() => {
    const fetchListing = async () => {
        setLoading(true);
        const data = await getListingById(Number(listingId));
        if (data) {
            setListing(data);

            // Check Unlock State
            const user = JSON.parse(localStorage.getItem('road80_user') || '{}');
            const userId = user.phone || 'guest';
            const unlockKey = `unlock_contact_${userId}_${data.id}`;
            const isOwner = data.publisherId === 'current_user';
            const isStoredUnlocked = localStorage.getItem(unlockKey) === 'true';

            setIsUnlocked(isOwner || isStoredUnlocked);
        } else {
            // Handle not found (go back)
            setTimeout(onBack, 100);
        }
        setLoading(false);
    };
    fetchListing();
  }, [listingId, onBack]);

  if (loading || !listing) {
      return (
          <div className="absolute inset-0 bg-bg z-50 flex items-center justify-center">
              <SpinnerIcon className="w-8 h-8 text-navy animate-spin" />
          </div>
      );
  }

  // Prepare Media Items
  const mediaItems: MediaItem[] = [];

  // Images
  const rawImages = listing.images && listing.images.length > 0 
    ? listing.images 
    : [listing.imageUrl || FALLBACK_IMAGE];

  rawImages.forEach((img, idx) => {
      mediaItems.push({ type: 'image', src: img, id: `img-${idx}` });
  });

  // Video (appended to end)
  if (listing.video) {
