import React, { useState, useEffect } from 'react';
import { UserIcon, PhoneIcon, WhatsappIcon, BuildingIcon, VerifiedIcon } from './Icons';
import { getListings, DEMO_ADS, DEMO_OFFICES } from '../utils/db';
