import ExplorePage from './components/ExplorePage';
import AuthPage from './components/AuthPage';
import QuickWizard from './components/QuickWizard';
import Header from './components/Header';
import { Tab, Listing } from './types';

// Duplicate category map for Title resolution
const CATEGORY_NAMES: Record<string, string> = {
  'real-estate': 'الشركات العقارية',
  'construction': 'الشركات الانشائية',
  'contracting': 'شركات المقاولات',
  'decor': 'قسم الديكور',
  'materials': 'مواد البناء'
};

const App: React.FC = () => {
  const [showSplash, setShowSplash] = useState(true);
  const [currentHash, setCurrentHash] = useState(window.location.hash);
  const [lastUpdate, setLastUpdate] = useState(Date.now());
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [theme, setTheme] = useState<'light' | 'dark'>(() => {
    // Default to Light Mode. Only enable Dark Mode if explicitly saved.
    const saved = localStorage.getItem('road80_theme');
    if (saved === 'dark') {
        return 'dark';
    }
    return 'light';
  });

  // Effect to apply theme class
  useEffect(() => {
    if (theme === 'dark') {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
    localStorage.setItem('road80_theme', theme);
  }, [theme]);

  const toggleTheme = () => {
    setTheme(prev => prev === 'light' ? 'dark' : 'light');
  };

  // Check auth on mount
  useEffect(() => {
    const user = localStorage.getItem('road80_user');
    if (user) {
      setIsAuthenticated(true);
    }
  }, []);

  // Routing Hook
  useEffect(() => {
    const onHashChange = () => setCurrentHash(window.location.hash);
    window.addEventListener('hashchange', onHashChange);

    // Initial Route Set if empty
    if (!window.location.hash) {
      window.location.hash = '#/home';
    }

    return () => window.removeEventListener('hashchange', onHashChange);
  }, []);

  // Parse Route
  const routePath = currentHash.replace('#', '').split('?')[0] || '/home';
  const isAuthRoute = ['/auth', '/verify'].includes(routePath);
  const isQuickStart = routePath.startsWith('/quick-start');

  // Route Guards
  useEffect(() => {
    if (!showSplash) {
      if (!isAuthenticated && !isAuthRoute) {
        // Not logged in -> Redirect to Auth
        window.location.hash = '#/auth';
      } else if (isAuthenticated && isAuthRoute) {
        // Logged in but on Auth page -> Redirect to Quick Start
        window.location.hash = '#/quick-start';
      }
    }
  }, [showSplash, isAuthenticated, isAuthRoute, routePath]);

  // Determine Logic
  let activeTab = Tab.HOME;
  let listingId: number | null = null;

  if (routePath.startsWith('/home')) activeTab = Tab.HOME;
  else if (routePath.startsWith('/companies')) activeTab = Tab.COMPANIES;
  else if (routePath.startsWith('/post-ad')) activeTab = Tab.ADD;
  else if (routePath.startsWith('/explore')) activeTab = Tab.EXPLORE;
  else if (routePath.startsWith('/profile')) activeTab = Tab.PROFILE;
  else if (routePath.startsWith('/ad/')) {
    activeTab = Tab.PROFILE; 
    const parts = routePath.split('/');
    if (parts.length >= 3) {
      listingId = parseInt(parts[2]);
    }
  }

  const getPageTitle = (tab: Tab): string => {
    switch (tab) {
      case Tab.HOME: return 'الرئيسية';
      case Tab.COMPANIES: return 'الشركات';
      case Tab.ADD: return 'انشر اعلانك';
      case Tab.EXPLORE: return 'اكسبلور';
      case Tab.PROFILE: return 'حسابي';
      default: return '80road';
    }
  };

  // Compute Header Props (Title & Back Button)
  const getHeaderProps = () => {
    const params = new URLSearchParams(currentHash.split('?')[1] || '');
    const categoryId = params.get('category');
    const userId = params.get('user');

    if (activeTab === Tab.COMPANIES) {
      if (categoryId) {
        // Sub-page: Company List (Filtered)
        return {
          title: CATEGORY_NAMES[categoryId] || 'الشركات',
          showBack: true,
          onBack: () => window.location.hash = '#/companies'
        };
      } else {
        // Root: Categories
        return {
          title: 'الشركات',
          showBack: true,
          onBack: () => window.location.hash = '#/home'
        };
      }
    }

    if (activeTab === Tab.PROFILE) {
      if (userId && userId !== 'current_user') {
        // Sub-page: Other User/Company Profile
        return {
          title: 'الملف التعريفي',
          showBack: true,
          onBack: () => window.history.back()
        };
      }
    }

    // Default
    return {
      title: getPageTitle(activeTab),
      showBack: false,
      onBack: undefined
    };
  };

  const headerProps = getHeaderProps();

  const handleWizardComplete = () => {
    window.location.hash = '#/profile';
    setLastUpdate(Date.now());
  };

  const handleListingClick = (listing: Listing) => {
    window.location.hash = `#/ad/${listing.id}`;
  };

  const handleBackFromDetails = () => {
    window.history.back();
  };

  const handleTabChange = () => {}; 

  const handleLoginSuccess = () => {
    setIsAuthenticated(true);
    window.location.hash = '#/quick-start';
  };

  const handleQuickWizardComplete = () => {
    window.location.hash = '#/home';
  };

  return (
    <div 
      className="relative w-full max-w-[430px] mx-auto bg-bg dark:bg-slate-950 sm:rounded-[40px] sm:shadow-2xl overflow-hidden shadow-2xl transition-colors duration-300"
      style={{ height: 'calc(var(--vh, 1vh) * 100)' }}
    >
      {showSplash ? (
        <SplashScreen onFinish={() => setShowSplash(false)} />
      ) : (
        <>
          {/* Auth Flow */}
          {(!isAuthenticated || isAuthRoute) ? (
             <AuthPage onLoginSuccess={handleLoginSuccess} />
          ) : (
            /* Protected App Shell */
            <>
              {/* Layer 1: Header */}
              {!listingId && !isQuickStart && (
                <Header 
                  title={headerProps.title} 
                  showBack={headerProps.showBack} 
                  onBack={headerProps.onBack} 
                />
              )}

              {/* Layer 2: Main Content Area */}
              <main 
                className="absolute left-0 right-0 overflow-hidden bg-bg dark:bg-slate-950 animate-fade-in transition-colors duration-300"
                style={{
                  top: (listingId || isQuickStart) ? '0' : 'calc(var(--header-h) + env(safe-area-inset-top))',
                  bottom: (listingId || isQuickStart) ? '0' : 'calc(var(--tab-h) + env(safe-area-inset-bottom))',
                  zIndex: (listingId || isQuickStart) ? 50 : 10
                }}
              >
                 {isQuickStart ? (
                    <QuickWizard onComplete={handleQuickWizardComplete} />
                 ) : listingId ? (
                    <ListingDetailsPage 
                      listingId={listingId}
                      onBack={handleBackFromDetails} 
                    />
                 ) : (
                   <>
                    <div className={`absolute inset-0 ${activeTab === Tab.HOME ? 'block' : 'hidden'}`}>
                      <div className="h-full w-full overflow-y-auto overflow-x-hidden no-scrollbar pb-20">
                        <HomePage theme={theme} onToggleTheme={toggleTheme} />
                      </div>
                    </div>

                    <div className={`absolute inset-0 ${activeTab === Tab.COMPANIES ? 'block' : 'hidden'}`}>
                      <div className="h-full w-full overflow-y-auto overflow-x-hidden no-scrollbar pb-20">
                        <OfficesPage />
                      </div>
                    </div>

                    <div className={`absolute inset-0 ${activeTab === Tab.ADD ? 'block' : 'hidden'}`}>
                       <AddWizard onComplete={handleWizardComplete} />
                    </div>

                    <div className={`absolute inset-0 ${activeTab === Tab.EXPLORE ? 'block' : 'hidden'}`}>
                      <div className="h-full w-full overflow-y-auto overflow-x-hidden no-scrollbar pb-20">
                        <ExplorePage />
                      </div>
                    </div>

                    <div className={`absolute inset-0 ${activeTab === Tab.PROFILE ? 'block' : 'hidden'}`}>
                       <div className="h-full w-full overflow-y-auto overflow-x-hidden no-scrollbar pb-20">
                         <ProfilePage 
                            key={lastUpdate} 
                            onListingClick={handleListingClick}
                         />
                       </div>
                    </div>
                   </>
                 )}
              </main>

              {/* Layer 3: Bottom Navigation */}
              {!listingId && !isQuickStart && (
                <BottomNavigation 
                    activeTab={activeTab} 
                    onTabChange={handleTabChange} 
                />
              )}
            </>
          )}
        </>
      )}
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';
import { ChevronRightIcon, PlayIcon, CheckIcon, UserIcon, PhoneIcon, WhatsappIcon, BuildingIcon, SpinnerIcon, LockIcon, AppleIcon } from './Icons';
import { Listing } from '../types';
import { getListingById } from '../utils/db';

interface ListingDetailsPageProps {
  listingId: number;
  onBack: () => void;
}

const FALLBACK_IMAGE = 'https://raiyansoft.com/wp-content/uploads/2026/01/1.png';
const UNLOCK_FEE = '1 د.ك';
const KNET_LOGO = "https://media.licdn.com/dms/image/v2/D4D0BAQFazp_I3lLeQg/company-logo_200_200/company-logo_200_200/0/1715599858189/the_shared_electronic_banking_services_co_knet_logo?e=2147483647&v=beta&t=FfjCLbNIUGrTCTi-tI5nXSNP9B4AcOJbWsFqV0bSWcM";

interface MediaItem {
  type: 'image' | 'video';
  src: string | File | Blob;
  id: string;
}

type PaymentStatus = 'IDLE' | 'STARTING' | 'VERIFYING' | 'CONFIRMING' | 'SUCCESS';

const ListingDetailsPage: React.FC<ListingDetailsPageProps> = ({ listingId, onBack }) => {
  const [listing, setListing] = useState<Listing | null>(null);
  const [loading, setLoading] = useState(true);
  const [activeImageIndex, setActiveImageIndex] = useState(0);
  const scrollRef = useRef<HTMLDivElement>(null);
  const thumbsRef = useRef<HTMLDivElement>(null);

  const [isUnlocked, setIsUnlocked] = useState(false);
  const [showUnlockPopup, setShowUnlockPopup] = useState(false);
  const [paymentStatus, setPaymentStatus] = useState<PaymentStatus>('IDLE');

  useEffect(() => {
    const fetchListing = async () => {
        setLoading(true);
        const data = await getListingById(Number(listingId));
        if (data) {
            setListing(data);
            const user = JSON.parse(localStorage.getItem('road80_user') || '{}');
            const userId = user.phone || 'guest';
            const unlockKey = `unlock_contact_${userId}_${data.id}`;
            const isOwner = data.publisherId === 'current_user';
            const isStoredUnlocked = localStorage.getItem(unlockKey) === 'true';
            setIsUnlocked(isOwner || isStoredUnlocked);
        } else {
            setTimeout(onBack, 100);
        }
        setLoading(false);
    };
    fetchListing();
  }, [listingId, onBack]);

  if (loading || !listing) {
      return (
          <div className="absolute inset-0 bg-bg dark:bg-slate-950 z-50 flex items-center justify-center transition-colors duration-300">
              <SpinnerIcon className="w-8 h-8 text-navy dark:text-blue animate-spin" />
          </div>
      );
  }

  const mediaItems: MediaItem[] = [];
  const rawImages = listing.images && listing.images.length > 0 
    ? listing.images 
    : [listing.imageUrl || FALLBACK_IMAGE];

  rawImages.forEach((img, idx) => {
      mediaItems.push({ type: 'image', src: img, id: `img-${idx}` });
  });

  if (listing.video) {
      mediaItems.push({ type: 'video', src: listing.video, id: 'vid-main' });
  }

  const getSrc = (src: string | File | Blob) => {
    if (src instanceof File || src instanceof Blob) {
      return URL.createObjectURL(src);
    }
    return src;
  };

  const handleScroll = (e: React.UIEvent<HTMLDivElement>) => {
    const width = e.currentTarget.offsetWidth;
    const scrollLeft = Math.abs(e.currentTarget.scrollLeft);
    const index = Math.round(scrollLeft / width);
    setActiveImageIndex(index);
    if (thumbsRef.current) {
        const thumb = thumbsRef.current.children[index] as HTMLElement;
        if (thumb) {
            thumb.scrollIntoView({ behavior: 'smooth', block: 'nearest', inline: 'center' });
        }
    }
  };

  const scrollToMedia = (index: number) => {
      setActiveImageIndex(index);
      if (scrollRef.current) {
          const child = scrollRef.current.children[index] as HTMLElement;
          if (child) {
              child.scrollIntoView({ behavior: 'smooth', block: 'nearest', inline: 'center' });
          }
      }
  };

  const handlePublisherClick = () => {
    if (listing.publisherId) {
      window.location.hash = `#/profile?user=${listing.publisherId}`;
    }
  };

  const handleUnlockPayment = () => {
    if (paymentStatus !== 'IDLE') return;
    setPaymentStatus('STARTING');
    setTimeout(() => setPaymentStatus('VERIFYING'), 800);
    setTimeout(() => setPaymentStatus('CONFIRMING'), 1800);
    setTimeout(() => {
        setPaymentStatus('SUCCESS');
        const user = JSON.parse(localStorage.getItem('road80_user') || '{}');
        const userId = user.phone || 'guest';
        const unlockKey = `unlock_contact_${userId}_${listing.id}`;
        localStorage.setItem(unlockKey, 'true');
        setIsUnlocked(true);
        setTimeout(() => {
            setShowUnlockPopup(false);
            setPaymentStatus('IDLE');
        }, 1500);
    }, 2600);
  };

  const handleContactAction = (type: 'WHATSAPP' | 'CALL') => {
    if (!isUnlocked) {
        setShowUnlockPopup(true);
        return;
    }
    if (type === 'WHATSAPP') {
        window.open('https://wa.me/96598812020', '_blank');
    } else {
        window.location.href = 'tel:+96598812020';
    }
  };

  const AttrBadge: React.FC<{ label: string; value: string | number | undefined }> = ({ label, value }) => {
    if (!value) return null;
    return (
      <div className="bg-white dark:bg-slate-900 border border-pale dark:border-slate-800 rounded-xl p-3 flex flex-col gap-1 items-start shadow-sm transition-colors duration-300">
        <span className="text-[10px] text-gray-400 font-medium">{label}</span>
        <span className="text-sm font-bold text-navy dark:text-slate-200">{value}</span>
      </div>
    );
  };

  const getPaymentText = () => {
    switch (paymentStatus) {
      case 'STARTING': return 'جاري بدء عملية الدفع...';
      case 'VERIFYING': return 'جاري التحقق من الدفع...';
      case 'CONFIRMING': return 'جاري تأكيد العملية...';
      case 'SUCCESS': return 'تم الدفع بنجاح';
      default: return 'فتح التواصل مع ناشر الإعلان';
    }
  };

  return (
    <div className="absolute inset-0 bg-bg dark:bg-slate-950 z-50 flex flex-col h-full overflow-hidden animate-fade-in transition-colors duration-300">
      {/* Header */}
      <div 
        className="absolute top-0 left-0 right-0 z-20 flex items-center justify-between px-4"
        style={{ 
            height: 'calc(var(--header-h) + env(safe-area-inset-top))', 
            paddingTop: 'env(safe-area-inset-top)',
            background: 'linear-gradient(to bottom, rgba(0,0,0,0.4) 0%, transparent 100%)'
        }}
      >
        <button 
          onClick={onBack}
          className="w-10 h-10 bg-white/20 backdrop-blur-md rounded-full flex items-center justify-center text-white active:scale-95 transition-all"
        >
          <ChevronRightIcon className="w-6 h-6 rotate-180" />
        </button>
        <div className="flex gap-3">
          <button className="w-10 h-10 bg-white/20 backdrop-blur-md rounded-full flex items-center justify-center text-white active:scale-95 transition-all">
             <CheckIcon className="w-5 h-5" />
          </button>
        </div>
      </div>

      <div className="flex-1 overflow-y-auto overflow-x-hidden pb-24 no-scrollbar bg-bg dark:bg-slate-950 transition-colors duration-300">
        <div className="relative bg-white dark:bg-slate-900 shadow-sm transition-colors duration-300">
             {/* Main Carousel - Strict 1:1 Aspect Ratio using padding hack for iOS stability */}
             <div className="relative w-full pt-[100%] bg-gray-200 dark:bg-slate-800 overflow-hidden group">
                 <div 
                    ref={scrollRef}
                    className="absolute inset-0 w-full h-full flex overflow-x-auto snap-x snap-mandatory no-scrollbar"
                    onScroll={handleScroll}
                    style={{ WebkitOverflowScrolling: 'touch' }}
                 >
                    {mediaItems.map((item, idx) => (
                        <div key={item.id} className="relative w-full h-full flex-shrink-0 snap-center bg-black flex items-center justify-center overflow-hidden">
                            {item.type === 'video' ? (
                                <video 
                                    src={getSrc(item.src)} 
                                    controls 
                                    playsInline
                                    className="w-full h-full object-contain" 
                                    poster={FALLBACK_IMAGE} 
                                />
                            ) : (
                                <img 
                                    src={getSrc(item.src)} 
                                    className="w-full h-full object-cover" 
                                    onError={(e) => (e.currentTarget.src = FALLBACK_IMAGE)} 
                                    alt={`Slide ${idx}`} 
                                />
                            )}
                        </div>
                    ))}
                 </div>
                 {/* Count Badge */}
                 <div className="absolute bottom-4 right-4 bg-black/60 backdrop-blur-md text-white text-[10px] font-bold px-2.5 py-1 rounded-full border border-white/10 z-10 pointer-events-none">
                    {activeImageIndex + 1} / {mediaItems.length}
                 </div>
             </div>

             {/* Thumbnails */}
             {mediaItems.length > 1 && (
                 <div ref={thumbsRef} className="flex gap-2 p-3 overflow-x-auto no-scrollbar border-b border-pale/50 dark:border-slate-800 bg-white dark:bg-slate-900 transition-colors duration-300">
                    {mediaItems.map((item, idx) => (
                        <button key={`thumb-${item.id}`} onClick={() => scrollToMedia(idx)} className={`relative flex-shrink-0 w-16 h-16 rounded-lg overflow-hidden border-2 transition-all ${activeImageIndex === idx ? 'border-navy dark:border-blue ring-1 ring-navy dark:ring-blue shadow-md opacity-100' : 'border-transparent opacity-60 hover:opacity-100'}`}>
                             {item.type === 'video' ? (
                                 <div className="w-full h-full bg-gray-800 flex items-center justify-center relative"><PlayIcon className="w-6 h-6 text-white z-10" /><div className="absolute inset-0 bg-black/20"></div></div>
                             ) : (
                                 <img src={getSrc(item.src)} className="w-full h-full object-cover" onError={(e) => (e.currentTarget.src = FALLBACK_IMAGE)} alt={`Thumb ${idx}`} />
                             )}
                        </button>
                    ))}
                 </div>
             )}
        </div>

        {/* Details Wrapper - Reduced top spacing */}
        <div className="flex flex-col gap-6 px-5 pt-3 pb-8">
            <div className="bg-white dark:bg-slate-900 rounded-3xl p-5 shadow-lg shadow-navy/5 dark:shadow-black/20 border border-pale dark:border-slate-800 transition-colors duration-300">
                <div className="flex justify-between items-start mb-2">
                    <h1 className="text-xl font-bold text-navy dark:text-slate-200 leading-snug max-w-[70%]">{listing.title}</h1>
                    <span className="text-blue dark:text-blue/80 font-bold text-lg">{listing.price}</span>
                </div>
                <div className="flex items-center gap-2 text-gray-500 dark:text-slate-400 text-sm mb-4">
                    <BuildingIcon className="w-4 h-4" />
                    <span>{listing.area}، {listing.governorate}</span>
                </div>
                <div className="flex items-center justify-between pt-4 border-t border-gray-100 dark:border-slate-800 transition-colors duration-300">
                    <div className={`flex items-center gap-2 ${listing.publisherId ? 'cursor-pointer active:scale-95 transition-transform' : ''}`} onClick={handlePublisherClick}>
                         <div className="w-8 h-8 rounded-full bg-gray-100 dark:bg-slate-800 flex items-center justify-center text-gray-400 overflow-hidden shadow-sm border border-pale dark:border-slate-700">
                            {listing.publisherAvatar ? (
                                <img src={listing.publisherAvatar} className="w-full h-full object-cover" alt={listing.publisherName} /> 
                            ) : (
                                <UserIcon className="w-4 h-4" />
                            )}
                         </div>
                         <span className={`text-xs font-bold text-navy dark:text-slate-300 ${listing.publisherId ? 'hover:text-blue dark:hover:text-blue' : ''}`}>
                             {listing.publisherName || 'مستخدم'}
                         </span>
                    </div>
                    <span className="text-[10px] text-gray-400 dark:text-slate-500 font-medium">
                        {listing.views ? `${listing.views} مشاهدة` : 'جديد'}
                    </span>
                </div>
            </div>

            <div>
                 <h3 className="text-lg font-bold text-navy dark:text-slate-200 mb-3 font-sans">الوصف</h3>
                 <p className="text-sm text-gray-600 dark:text-slate-400 leading-relaxed whitespace-pre-line font-sans">
                    {listing.description || 'لا يوجد وصف متاح لهذا العقار. يرجى التواصل مع المالك لمزيد من التفاصيل حول العقار ومميزاته.'}
                 </p>
            </div>

            <div>
                 <h3 className="text-lg font-bold text-navy dark:text-slate-200 mb-3 font-sans">تفاصيل العقار</h3>
                 <div className="grid grid-cols-2 gap-3">
                    <AttrBadge label="نوع الإعلان" value={listing.listingType} />
                    <AttrBadge label="نوع العقار" value={listing.propertyType} />
                    <AttrBadge label="المساحة" value={listing.size ? `${listing.size} م²` : undefined} />
                    <AttrBadge label="الغرف" value={listing.rooms} />
                    <AttrBadge label="الحمامات" value={listing.bathrooms} />
                    <AttrBadge label="بلكونة" value={listing.balcony} />
                    <AttrBadge label="المواقف" value={listing.parking} />
                    <AttrBadge label="نظام المواقف" value={listing.parkingSystems?.join(', ')} />
                    <AttrBadge label="التكييف" value={listing.ac} />
                    <AttrBadge label="الكهرباء" value={listing.electricity} />
                    <AttrBadge label="الماء" value={listing.water} />
                 </div>
            </div>
        </div>
      </div>

      <div className="absolute bottom-0 left-0 right-0 p-4 pt-4 bg-white dark:bg-slate-900 border-t border-pale dark:border-slate-800 z-20 transition-colors duration-300" style={{ paddingBottom: 'calc(env(safe-area-inset-bottom) + 16px)' }}>
          <div className="flex gap-2">
            <div className="flex-1 flex gap-1">
                <button onClick={() => handleContactAction('WHATSAPP')} className="flex-1 flex items-center justify-center gap-2 py-3 rounded-xl border border-navy/20 dark:border-slate-700 bg-green-50 dark:bg-green-950/20 text-green-700 dark:text-green-500 font-bold text-sm active:scale-95 transition-all">
                    <WhatsappIcon className="w-5 h-5" />
                    <span>واتساب</span>
                </button>
                {!isUnlocked && (
                    <button onClick={() => setShowUnlockPopup(true)} className="w-12 flex items-center justify-center bg-white dark:bg-slate-900 border border-pale dark:border-slate-800 rounded-xl text-navy dark:text-slate-400 shadow-sm active:scale-95 transition-all">
                        <LockIcon className="w-5 h-5 opacity-60" />
                    </button>
                )}
            </div>

            <div className="flex-1 flex gap-1">
                <button onClick={() => handleContactAction('CALL')} className="flex-1 flex items-center justify-center gap-2 py-3 rounded-xl bg-navy dark:bg-blue text-white font-bold text-sm shadow-lg shadow-navy/20 dark:shadow-blue/20 active:scale-95 transition-all">
                    <PhoneIcon className="w-5 h-5" />
                    <span>اتصال</span>
                </button>
                {!isUnlocked && (
                    <button onClick={() => setShowUnlockPopup(true)} className="w-12 flex items-center justify-center bg-white dark:bg-slate-900 border border-pale dark:border-slate-800 rounded-xl text-navy dark:text-slate-400 shadow-sm active:scale-95 transition-all">
                        <LockIcon className="w-5 h-5 opacity-60" />
                    </button>
                )}
            </div>
          </div>
      </div>

      {showUnlockPopup && (
        <div className="fixed inset-0 z-[100] flex items-end sm:items-center justify-center p-0 sm:p-4">
            <div className="absolute inset-0 bg-black/60 dark:bg-black/80 backdrop-blur-sm animate-fade-in" onClick={() => { if (paymentStatus === 'IDLE' || paymentStatus === 'SUCCESS') setShowUnlockPopup(false); }} />
            <div className="relative bg-white dark:bg-slate-900 w-full max-w-sm rounded-t-[32px] sm:rounded-[32px] p-8 shadow-2xl animate-fade-in-up border-t dark:border-slate-800 transition-colors duration-300">
                <div className="w-12 h-1.5 bg-gray-100 dark:bg-slate-800 rounded-full mx-auto mb-8 sm:hidden" />
                <div className="flex flex-col items-center text-center gap-6">
                    <div className="relative w-24 h-24 mb-2 flex items-center justify-center">
                        {paymentStatus === 'IDLE' && (
                            <div className="w-20 h-20 bg-pale/50 dark:bg-slate-800 rounded-full flex items-center justify-center text-navy dark:text-slate-200 border border-pale dark:border-slate-700 animate-fade-in">
                                <LockIcon className="w-10 h-10" />
                            </div>
                        )}
                        {(paymentStatus === 'STARTING' || paymentStatus === 'VERIFYING' || paymentStatus === 'CONFIRMING') && (
                            <div className="w-20 h-20 rounded-full border-4 border-pale dark:border-slate-800 flex items-center justify-center relative animate-fade-in">
                                <div className="absolute inset-0 border-4 border-navy dark:border-blue border-t-transparent rounded-full animate-spin"></div>
                                <SpinnerIcon className="w-10 h-10 text-navy/20 dark:text-blue/20" />
                            </div>
                        )}
                        {paymentStatus === 'SUCCESS' && (
                            <div className="w-20 h-20 bg-green-500 rounded-full flex items-center justify-center shadow-lg shadow-green-200 dark:shadow-green-900/40 animate-scale-in">
                                <svg className="w-12 h-12 text-white" viewBox="0 0 52 52">
                                    <path className="animate-draw" fill="none" stroke="currentColor" strokeWidth="5" strokeLinecap="round" strokeLinejoin="round" strokeDasharray="100" strokeDashoffset="100" d="M14.1 27.2l7.1 7.2 16.7-16.8" />
                                </svg>
                            </div>
                        )}
                    </div>
                    <div className="flex flex-col gap-2 min-h-[80px]">
                        <h3 className={`text-xl font-bold transition-colors duration-300 ${paymentStatus === 'SUCCESS' ? 'text-green-600 dark:text-green-500' : 'text-navy dark:text-slate-200'}`}>
                            {getPaymentText()}
                        </h3>
                        {paymentStatus === 'IDLE' ? (
                            <p className="text-sm text-gray-500 dark:text-slate-400 leading-relaxed max-w-[85%] mx-auto font-sans">
                                لفتح القفل والتواصل مع البائع في هذا الإعلان، يرجى الدفع مرة واحدة فقط.
                            </p>
                        ) : paymentStatus === 'SUCCESS' ? (
                            <p className="text-sm text-green-600/80 dark:text-green-500/80 font-medium animate-fade-in font-sans">
                                تم فتح التواصل مع ناشر الإعلان
                            </p>
                        ) : (
                            <div className="flex flex-col gap-4 mt-2">
                                <div className="w-full h-1.5 bg-gray-100 dark:bg-slate-800 rounded-full overflow-hidden">
                                    <div className={`h-full bg-navy dark:bg-blue transition-all duration-700 ease-out`} style={{ width: paymentStatus === 'STARTING' ? '30%' : paymentStatus === 'VERIFYING' ? '70%' : '95%' }}></div>
                                </div>
                            </div>
                        )}
                    </div>
                    {paymentStatus === 'IDLE' && (
                        <>
                            <div className="bg-bg dark:bg-slate-800 px-6 py-3 rounded-2xl border border-pale/50 dark:border-slate-700 flex items-center gap-3 animate-fade-in transition-colors duration-300">
                                <span className="text-xs text-gray-400 dark:text-slate-500 font-medium">رسوم الفتح:</span>
                                <span className="text-lg font-bold text-navy dark:text-slate-200">{UNLOCK_FEE}</span>
                            </div>
                            <div className="w-full flex flex-col gap-3 mt-4 animate-fade-in">
                                <button onClick={handleUnlockPayment} className="w-full h-14 bg-black dark:bg-slate-950 text-white rounded-2xl font-bold flex items-center justify-center gap-3 active:scale-95 transition-all shadow-xl shadow-black/10">
                                    <AppleIcon className="w-6 h-6 mb-1" />
                                    <span>الدفع عبر Apple Pay</span>
                                </button>
                                <button onClick={handleUnlockPayment} className="w-full h-14 bg-white dark:bg-slate-800 text-navy dark:text-slate-200 border border-gray-200 dark:border-slate-700 rounded-2xl font-bold flex items-center justify-center gap-3 active:scale-95 transition-all shadow-sm">
                                    <img src={KNET_LOGO} className="w-8 h-8 object-contain" alt="KNET" />
                                    <span>الدفع عبر الكي نت</span>
                                </button>
                                <button onClick={() => setShowUnlockPopup(false)} className="w-full h-12 text-gray-400 dark:text-slate-500 font-bold text-sm hover:text-navy dark:hover:text-slate-300 transition-colors active:scale-95 mt-1">
                                    إلغاء
                                </button>
                            </div>
                        </>
                    )}
                    {paymentStatus === 'SUCCESS' && (
                         <div className="w-full mt-4 animate-fade-in">
                             <button onClick={() => setShowUnlockPopup(false)} className="w-full h-14 bg-navy dark:bg-blue text-white rounded-2xl font-bold active:scale-95 transition-all shadow-lg shadow-navy/20">
                                 متابعة
                             </button>
                         </div>
                    )}
                </div>
                <div className="h-[env(safe-area-inset-bottom)] sm:hidden" />
            </div>
        </div>
      )}
    </div>
  );
};

