            className="w-full py-4 bg-white text-navy border border-pale rounded-xl font-bold flex items-center justify-center gap-2 active:scale-95 transition-all shadow-sm"
          >
            {isProcessing ? (
               <span className="animate-pulse">جاري المعالجة...</span>
            ) : (
              <>
               <img src={KNET_LOGO} className="w-8 h-8 object-contain" alt="KNET" />
               <span>الدفع عبر الكي نت</span>
              </>
            )}
          </button>
        </div>
      );
    }

    // Default for all other steps (Single Choice / Auto-advance)
    // Always render at least the back button as per requirement
    return (
      <div className="w-full">
        {backButton}
      </div>
    );
  };

  const renderContent = () => {
    switch (step) {
      case 1:
        return (
          <>
            {renderTitle('نوع الاعلان')}
            {['للبيع', 'للإيجار'].map(opt => (
              renderOption(opt, formData.listingType === opt, () => selectAndNext('listingType', opt))
            ))}
          </>
        );
      case 2:
        return (
          <>
            {renderTitle('نوع العقار')}
            {['بيت', 'شقة', 'دور', 'عمارة', 'دوبلكس'].map(opt => (
              renderOption(opt, formData.propertyType === opt, () => selectAndNext('propertyType', opt))
            ))}
          </>
        );
      case 3:
        return (
          <>
            {renderTitle('المحافظة')}
            {GOVERNORATES.map(opt => (
              renderOption(opt, formData.governorate === opt, () => selectAndNext('governorate', opt))
            ))}
          </>
        );
      case 4:
        const areas = AREAS[formData.governorate] || [];
        return (
          <>
            {renderTitle('المنطقة')}
            <div className="grid grid-cols-1 gap-1">
              {areas.map(opt => (
                renderOption(opt, formData.area === opt, () => selectAndNext('area', opt))
              ))}
            </div>
          </>
        );
      case 5:
        return (
          <>
            {renderTitle('عدد الغرف')}
            <div className="grid grid-cols-3 gap-3">
              {Array.from({ length: 12 }, (_, i) => i + 1).map(num => (
                <button
                  key={num}
                  onClick={() => selectAndNext('rooms', num)}
                  className={`aspect-square rounded-2xl border flex items-center justify-center text-lg font-bold transition-all ${
                    formData.rooms === num ? 'bg-navy text-white' : 'bg-white text-navy border-pale'
                  }`}
                >
                  {num}
                </button>
              ))}
            </div>
          </>
        );
      case 6:
        return (
          <>
            {renderTitle('عدد الحمامات')}
            <div className="grid grid-cols-3 gap-3">
              {[...Array.from({ length: 10 }, (_, i) => i + 1), '10+'].map(num => (
                <button
                  key={num}
                  onClick={() => selectAndNext('bathrooms', num)}
                  className={`aspect-square rounded-2xl border flex items-center justify-center text-lg font-bold transition-all ${
                    formData.bathrooms === num ? 'bg-navy text-white' : 'bg-white text-navy border-pale'
                  }`}
                >
                  {num}
                </button>
              ))}
            </div>
          </>
        );
      case 7:
        return (
          <>
            {renderTitle('المساحة')}
            <div className="flex flex-col items-center justify-center gap-8 py-10 bg-white rounded-3xl border border-pale shadow-sm">
              <span className="text-4xl font-bold text-blue">{formData.size} <span className="text-sm text-gray-400">م²</span></span>
              <input 
                type="range" 
                min="50" 
                max="2000" 
                step="5" 
                value={formData.size} 
                onChange={(e) => updateData('size', parseInt(e.target.value))}
                className="w-4/5 accent-navy h-2 bg-pale rounded-lg appearance-none cursor-pointer"
              />
            </div>
          </>
        );
      case 8:
        return (
          <>
            {renderTitle('بلكونة')}
            {['نعم', 'لا'].map(opt => (
              renderOption(opt, formData.balcony === opt, () => selectAndNext('balcony', opt))
            ))}
          </>
        );
      case 9:
        return (
          <>
            {renderTitle('عدد المواقف')}
            {['1', '2', '3', '3+'].map(opt => (
              renderOption(opt, formData.parking === opt, () => selectAndNext('parking', opt))
            ))}
          </>
        );
      case 10:
        return (
          <>
            {renderTitle('نظام المواقف')}
            {['مظلات', 'سرداب', 'اخرى'].map(opt => (
              renderOption(opt, formData.parkingSystems.includes(opt), () => selectAndNext('parkingSystems', [opt]))
            ))}
          </>
        );
      case 11:
        return (
          <>
            {renderTitle('الكهرباء')}
            {['على المالك', 'على المستأجر'].map(opt => (
              renderOption(opt, formData.electricity === opt, () => selectAndNext('electricity', opt))
            ))}
          </>
        );
      case 12:
        return (
          <>
            {renderTitle('الماء')}
            {['على المالك', 'على المستأجر'].map(opt => (
              renderOption(opt, formData.water === opt, () => selectAndNext('water', opt))
            ))}
          </>
        );
      case 13:
        return (
          <>
            {renderTitle('التكييف')}
            {['على المالك', 'على المستأجر'].map(opt => (
              renderOption(opt, formData.ac === opt, () => selectAndNext('ac', opt))
