  const renderOption = (label: string, isSelected: boolean, onClick: () => void) => (
    <button
      onClick={onClick}
      className={`w-full p-4 mb-3 rounded-2xl border flex items-center justify-between transition-all duration-200 active:scale-98 ${
        isSelected 
          ? 'border-navy bg-navy text-white shadow-lg shadow-navy/20' 
          : 'border-pale bg-white text-navy hover:border-mid'
      }`}
    >
      <span className="font-bold text-sm">{label}</span>
      {isSelected && <CheckIcon className="w-5 h-5 text-white" />}
    </button>
  );

  const renderTitle = (title: string) => (
    <h2 className="text-xl font-bold text-navy mb-6 text-center">{title}</h2>
  );

  // Show footer on all steps unless payment is successfully processed
  const showFooter = !isPaid;

  const renderFooterAction = () => {
    const isFirstStep = step === 1;

    // Shared Back Button (Secondary Style)
    const backButton = (
      <button 
        onClick={prevStep} 
        disabled={isFirstStep}
        className={`w-full py-3 bg-white border border-pale text-navy rounded-xl font-bold transition-all shadow-sm ${
          isFirstStep ? 'opacity-50 cursor-not-allowed' : 'active:scale-95 hover:bg-pale/30'
        }`}
      >
        رجوع
      </button>
    );

    // Primary Next Button
    const nextButton = (
      <button 
        onClick={nextStep} 
        className="w-full py-4 bg-navy text-white rounded-xl font-bold shadow-lg shadow-navy/20 active:scale-95 transition-all"
      >
        التالي
      </button>
    );

    // Steps that require a manual "Next" button (stacked layout)
    // 8: Size (Slider), 15: Video, 16: Images
    if ([8, 15, 16].includes(step)) {
      return (
        <div className="flex flex-col gap-3">
          {backButton}
          {nextButton}
        </div>
      );
    }

    // Step 17: Publish (Payment)
    if (step === 17) {
      return (
        <div className="flex flex-col gap-3">
          {backButton}
          <button 
            onClick={handlePublish}
            disabled={isProcessing}
            className="w-full py-4 bg-black text-white rounded-xl font-bold flex items-center justify-center gap-2 active:scale-95 transition-all shadow-xl"
          >
            {isProcessing ? (
               <span className="animate-pulse">جاري المعالجة...</span>
            ) : (
              <>
               <AppleIcon className="w-5 h-5 mb-0.5" />
               <span>الدفع والنشر (Apple Pay)</span>
              </>
            )}
          </button>
          <button 
            onClick={handlePublish}
            disabled={isProcessing}
            className="w-full py-4 bg-white text-navy border border-pale rounded-xl font-bold flex items-center justify-center gap-2 active:scale-95 transition-all shadow-sm"
          >
            {isProcessing ? (
               <span className="animate-pulse">جاري المعالجة...</span>
            ) : (
              <>
               <img src={KNET_LOGO} className="w-8 h-8 object-contain" alt="KNET" />
               <span>الدفع عبر الكي نت</span>
              </>
            )}
          </button>
        </div>
      );
    }

    // Default for all other steps (Single Choice / Auto-advance)
    // Always render at least the back button as per requirement
    return (
      <div className="w-full">
        {backButton}
      </div>
    );
  };

  const renderContent = () => {
    switch (step) {
      case 1:
        return (
          <>
            {renderTitle('نوع الاعلان')}
            {['للبيع', 'للإيجار'].map(opt => (
              renderOption(opt, formData.listingType === opt, () => selectAndNext('listingType', opt))
            ))}
          </>
        );
      case 2:
        return (
          <>
            {renderTitle('نوع العقار')}
            {['بيت', 'شقة', 'دور', 'عمارة', 'دوبلكس'].map(opt => (
              renderOption(opt, formData.propertyType === opt, () => selectAndNext('propertyType', opt))
            ))}
          </>
        );
      case 3:
        return (
          <>
            {renderTitle('الدولة')}
            {COUNTRIES.map(opt => (
              renderOption(opt, formData.country === opt, () => selectAndNext('country', opt))
            ))}
          </>
        );
      case 4:
        // Use Kuwait governorates regardless of country (Demo limitation)
        return (
          <>
            {renderTitle('المحافظة')}
            {GOVERNORATES.map(opt => (
              renderOption(opt, formData.governorate === opt, () => selectAndNext('governorate', opt))
            ))}
          </>
        );
      case 5:
        const areas = AREAS[formData.governorate] || [];
        return (
          <>
            {renderTitle('المنطقة')}
            <div className="grid grid-cols-1 gap-1">
              {areas.map(opt => (
                renderOption(opt, formData.area === opt, () => selectAndNext('area', opt))
              ))}
            </div>
          </>
        );
      case 6:
        return (
          <>
            {renderTitle('عدد الغرف')}
            <div className="grid grid-cols-3 gap-3">
              {Array.from({ length: 12 }, (_, i) => i + 1).map(num => (
                <button
                  key={num}
                  onClick={() => selectAndNext('rooms', num)}
                  className={`aspect-square rounded-2xl border flex items-center justify-center text-lg font-bold transition-all ${
                    formData.rooms === num ? 'bg-navy text-white' : 'bg-white text-navy border-pale'
                  }`}
                >
                  {num}
                </button>
              ))}
            </div>
          </>
        );
      case 7:
        return (
          <>
            {renderTitle('عدد الحمامات')}
            <div className="grid grid-cols-3 gap-3">
              {[...Array.from({ length: 10 }, (_, i) => i + 1), '10+'].map(num => (
                <button
