import React, { useState, useEffect } from 'react';
import { UserIcon, PhoneIcon, WhatsappIcon, BuildingIcon, VerifiedIcon } from './Icons';
import { getListings, DEMO_ADS, DEMO_OFFICES } from '../utils/db';
import { Listing } from '../types';

interface ProfilePageProps {
  onListingClick?: (listing: Listing) => void;
}

const FALLBACK_IMAGE = 'https://raiyansoft.com/wp-content/uploads/2026/01/1.png';

const ListingCard: React.FC<{ listing: Listing, onClick?: () => void }> = ({ listing, onClick }) => {
  const [imgSrc, setImgSrc] = useState<string>('');

  useEffect(() => {
    if (listing.imageUrl instanceof Blob || listing.imageUrl instanceof File) {
        setImgSrc(URL.createObjectURL(listing.imageUrl));
    } else if (typeof listing.imageUrl === 'string') {
        setImgSrc(listing.imageUrl);
    } else if (listing.images && listing.images.length > 0) {
         const first = listing.images[0];
         if (first instanceof Blob || first instanceof File) {
             setImgSrc(URL.createObjectURL(first));
         } else {
             setImgSrc(first as string);
         }
    } else {
        setImgSrc(FALLBACK_IMAGE);
    }
  }, [listing]);

  return (
    <div 
      onClick={onClick}
      className="flex flex-col bg-white dark:bg-slate-900 rounded-xl shadow-[0_2px_8px_rgba(0,0,0,0.04)] border border-pale/50 dark:border-slate-800 overflow-hidden active:scale-98 transition-all duration-300 cursor-pointer"
    >
      <div className="aspect-square bg-slate-100 dark:bg-slate-800 flex items-center justify-center relative">
        <img src={imgSrc} alt={listing.title} className="w-full h-full object-cover" onError={() => setImgSrc(FALLBACK_IMAGE)} />
        <span className="absolute top-2 left-2 bg-navy/80 dark:bg-blue/80 text-white text-[10px] px-2 py-0.5 rounded-full z-10 font-bold">جديد</span>
      </div>
      <div className="p-3 flex flex-col gap-1">
        <span className="text-blue dark:text-blue/80 font-bold text-sm text-right font-sans">{listing.price}</span>
        <h4 className="text-navy dark:text-slate-200 font-semibold text-xs truncate text-right font-sans">{listing.title}</h4>
        <div className="flex items-center justify-end gap-1 opacity-60">
          <span className="text-[10px] text-navy dark:text-slate-400 font-medium font-sans">{listing.area}</span>
          <div className="w-1 h-1 rounded-full bg-navy dark:bg-slate-500"></div>
        </div>
      </div>
    </div>
  );
};

const StatItem: React.FC<{ label: string; value: string }> = ({ label, value }) => (
  <div className="flex flex-col items-center gap-1">
    <span className="text-lg font-bold text-navy dark:text-slate-200 font-sans">{value}</span>
    <span className="text-xs text-gray-400 dark:text-slate-500 font-medium font-sans">{label}</span>
  </div>
);

const ProfilePage: React.FC<ProfilePageProps> = ({ onListingClick }) => {
  const getParams = () => {
     const hashSplit = window.location.hash.split('?');
     return new URLSearchParams(hashSplit[1] || '');
  };

  const params = getParams();
  const viewedUserId = params.get('user');
  const activeTabParam = params.get('tab');
  const isMe = !viewedUserId || viewedUserId === 'current_user';

  const [activeSubTab, setActiveSubTab] = useState<'ads' | 'favorites'>(
    (activeTabParam === 'favorites' && isMe) ? 'favorites' : 'ads'
  );
  const [savedListings, setSavedListings] = useState<Listing[]>([]);

  useEffect(() => {
    const handleHashChange = () => {
      const p = getParams();
      const tab = p.get('tab');
      if (isMe) setActiveSubTab(tab === 'favorites' ? 'favorites' : 'ads');
    };
    window.addEventListener('hashchange', handleHashChange);
    return () => window.removeEventListener('hashchange', handleHashChange);
  }, [isMe]);

  const handleTabChange = (tab: 'ads' | 'favorites') => {
    if (!isMe) return;
    const currentHash = window.location.hash.split('?')[0];
    window.location.hash = `${currentHash}?tab=${tab}`;
  };

  useEffect(() => {
    const loadListings = async () => {
        try {
            const dbListings = await getListings();
            const mapped: Listing[] = dbListings.map((l: any) => ({
                id: l.id,
                listingType: l.listingType || 'غير محدد',
                propertyType: l.propertyType || 'عقار',
                price: l.price || '0 د.ك',
                area: l.area || 'غير محدد',
                governorate: l.governorate || 'الكويت',
                title: `${l.listingType} ${l.propertyType} في ${l.area}`,
                rooms: l.rooms,
                bathrooms: l.bathrooms,
                size: l.size,
                balcony: l.balcony,
                parking: l.parking,
                parkingSystems: l.parkingSystems,
                electricity: l.electricity,
                water: l.water,
                ac: l.ac,
                description: l.description,
                images: l.images || [],
                video: l.video,
                imageUrl: l.imageUrl || FALLBACK_IMAGE,
                views: 0,
                publisherId: l.publisherId,
                publisherName: l.publisherName
            }));
            setSavedListings(mapped);
        } catch (e) { console.error(e); }
    };
    loadListings();
  }, []);

  let profileName = 'فهد الحمدان';
  let profileBio = 'وسيط عقاري معتمد.\nخبرة 10 سنوات في السوق العقاري.';
  let profileAvatar: string | null = null;
  let isVerified = false;
  let stats = { ads: "0", likes: isMe ? "27" : "12", views: isMe ? "1,240" : "540" };
  let displayList: Listing[] = [];

  if (isMe) {
      const myAds = [...savedListings, ...DEMO_ADS]; 
      const myFavs = [DEMO_ADS[3]]; 
      displayList = activeSubTab === 'ads' ? myAds : myFavs;
      stats.ads = myAds.length.toString();
  } else {
      const office = DEMO_OFFICES.find(o => o.id === viewedUserId);
      if (office) {
        profileName = office.officeName;
        profileBio = office.bio;
        profileAvatar = office.logo;
        isVerified = office.verified;
        stats = { ads: office.activeListingsCount.toString(), likes: Math.floor(office.totalViews / 10).toString(), views: office.totalViews.toLocaleString() };
        displayList = office.sampleListings;
      } else {
        profileName = 'ناشر الإعلان';
        profileBio = 'عضو في 80road';
        const externalAds = [...savedListings, ...DEMO_ADS].filter(l => l.publisherId === viewedUserId);
        displayList = externalAds;
        stats.ads = externalAds.length.toString();
      }
  }

  return (
    <div className="flex flex-col p-4 gap-6 pb-24 animate-fade-in transition-colors duration-300">
      <div className="flex items-center gap-4">
        <div className="w-20 h-20 rounded-full bg-gradient-to-br from-pale to-white dark:from-slate-800 dark:to-slate-900 flex items-center justify-center text-navy dark:text-slate-200 shrink-0 border-2 border-white dark:border-slate-800 shadow-md overflow-hidden relative">
          {profileAvatar ? (
             <img src={profileAvatar} alt={profileName} className="w-full h-full object-cover" />
          ) : (
             <UserIcon className="w-10 h-10 opacity-80" />
          )}
        </div>
        <div className="flex flex-col gap-1 flex-1">
          <div className="flex items-center gap-1">
             <h2 className="text-xl font-bold text-navy dark:text-slate-200 font-sans line-clamp-1">{profileName}</h2>
             {isVerified && <VerifiedIcon className="w-5 h-5 text-blue shrink-0" />}
          </div>
          <p className="text-xs text-gray-500 dark:text-slate-400 leading-snug font-sans font-normal whitespace-pre-line">
            {profileBio}
          </p>
        </div>
      </div>

      <div className="flex justify-between items-center px-4 py-4 bg-white dark:bg-slate-900 rounded-2xl shadow-sm border border-pale dark:border-slate-800 transition-colors duration-300">
        <StatItem label="الإعلانات" value={stats.ads} />
        <div className="w-px h-8 bg-gray-100 dark:bg-slate-800"></div>
        <StatItem label="اللايكات" value={stats.likes} />
        <div className="w-px h-8 bg-gray-100 dark:bg-slate-800"></div>
        <StatItem label="المشاهدات" value={stats.views} />
      </div>

      <div className="flex gap-3">
        <a href="https://wa.me/96598812020" target="_blank" rel="noopener noreferrer" className="flex-1 flex items-center justify-center gap-2 py-2.5 rounded-xl border border-navy/20 dark:border-slate-700 bg-white dark:bg-slate-900 text-navy dark:text-slate-200 font-semibold text-sm transition-all active:scale-98">
          <WhatsappIcon className="w-6 h-6" />
          <span>ارسال واتساب</span>
        </a>
        <a href="tel:+96598812020" className="flex-1 flex items-center justify-center gap-2 py-2.5 rounded-xl bg-navy dark:bg-blue text-white font-semibold text-sm shadow-lg shadow-navy/20 dark:shadow-blue/20 transition-all active:scale-98">
          <PhoneIcon className="w-5 h-5" />
          <span>اتصال</span>
        </a>
      </div>

      <div className="flex flex-col gap-4 mt-2">
        <h3 className="text-lg font-bold text-navy dark:text-slate-200 font-sans px-1">
            {isMe ? 'اعلاناتي' : `إعلانات ${profileName}`}
        </h3>
        {isMe && (
            <div className="flex p-1 bg-gray-100/80 dark:bg-slate-800 rounded-xl relative transition-colors duration-300">
            <button onClick={() => handleTabChange('ads')} className={`flex-1 py-2 text-xs font-bold rounded-lg transition-all duration-300 font-sans ${activeSubTab === 'ads' ? 'bg-white dark:bg-slate-900 shadow-[0_2px_8px_rgba(0,0,0,0.05)] text-navy dark:text-slate-200' : 'text-gray-400 dark:text-slate-500 hover:text-gray-600 dark:hover:text-slate-300'}`}>اعلاناتي</button>
            <button onClick={() => handleTabChange('favorites')} className={`flex-1 py-2 text-xs font-bold rounded-lg transition-all duration-300 font-sans ${activeSubTab === 'favorites' ? 'bg-white dark:bg-slate-900 shadow-[0_2px_8px_rgba(0,0,0,0.05)] text-navy dark:text-slate-200' : 'text-gray-400 dark:text-slate-500 hover:text-gray-600 dark:hover:text-slate-300'}`}>مفضلتي</button>
            </div>
        )}
        <div className="grid grid-cols-2 gap-3 min-h-[200px]">
          {displayList.map((item, idx) => (
            <ListingCard key={`${item.id}-${idx}`} listing={item} onClick={() => onListingClick && onListingClick(item)} />
          ))}
          {displayList.length === 0 && (
            <div className="col-span-2 py-10 text-center text-gray-400 dark:text-slate-600 text-sm font-medium">لا توجد إعلانات</div>
          )}
        </div>
      </div>
    </div>
  );
};

export default ProfilePage;

