            className="bg-white dark:bg-slate-900 rounded-3xl border border-pale dark:border-slate-800 shadow-sm overflow-hidden flex flex-col active:scale-98 transition-all duration-300 cursor-pointer"
          >
            <div className="relative h-28 bg-gray-50 dark:bg-slate-800 flex items-center justify-center p-4">
              <div className="w-[68px] h-[68px] rounded-full border-4 border-white dark:border-slate-700 shadow-md overflow-hidden bg-white dark:bg-slate-900 z-10">
                <img 
                  src={office.logo} 
                  alt={office.officeName} 
                  className="w-full h-full object-cover"
                  onError={(e) => e.currentTarget.src = 'https://raiyansoft.com/wp-content/uploads/2026/01/1.png'}
                />
              </div>
              {office.verified && (
                <div className="absolute top-3 left-3 text-blue drop-shadow-sm" title="مكتب موثق">
                   <VerifiedIcon className="w-6 h-6" />
                </div>
              )}
              <div className="absolute top-3 right-3 flex items-center gap-1.5 bg-white/95 dark:bg-slate-900/95 backdrop-blur-sm px-2.5 py-1 rounded-xl shadow-sm border border-pale/50 dark:border-slate-700">
                <span className="text-[17px] font-bold text-navy dark:text-slate-200 leading-none mt-0.5">{office.rating}</span>
                <StarIcon className="w-4 h-4 text-yellow-400" />
              </div>
            </div>

            <div className="p-4 flex flex-col items-center text-center flex-1">
              {/* Title with min-height for alignment */}
              <div className="min-h-[2.75rem] flex items-center justify-center w-full mb-0.5">
                 <h3 className="text-[18px] sm:text-[21px] font-semibold text-navy dark:text-slate-200 leading-[1.35] line-clamp-2">
                    {office.officeName}
                 </h3>
              </div>

              {/* Location */}
              <span className="text-[16px] font-medium text-gray-500 dark:text-slate-400 mb-2.5">
                 {office.governorate}
              </span>

              <div className="w-full mt-auto">
                <div className="flex justify-between items-center bg-gray-50 dark:bg-slate-800/50 rounded-xl px-3 py-2.5 mb-1.5 border border-pale/30 dark:border-slate-700/50">
                   <span className="text-[14px] font-medium text-gray-600 dark:text-slate-400">إعلانات نشطة</span>
                   <span className="text-[20px] font-bold text-blue dark:text-blue">{office.activeListingsCount}</span>
                </div>
                <button className="w-full h-[48px] rounded-xl bg-navy/5 dark:bg-slate-800 text-navy dark:text-slate-200 text-[18px] font-semibold hover:bg-navy/10 dark:hover:bg-slate-700 transition-colors flex items-center justify-center">
                  عرض الملف
                </button>
              </div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

export default OfficesPage;

import React, { useState, useRef, useEffect } from 'react';
import { ChevronRightIcon, PlayIcon, CheckIcon, UserIcon, PhoneIcon, WhatsappIcon, BuildingIcon, SpinnerIcon, LockIcon, AppleIcon } from './Icons';
import { Listing } from '../types';
import { getListingById } from '../utils/db';

interface ListingDetailsPageProps {
  listingId: number;
  onBack: () => void;
}

const FALLBACK_IMAGE = 'https://raiyansoft.com/wp-content/uploads/2026/01/1.png';
const UNLOCK_FEE = '1 د.ك';
const KNET_LOGO = "https://media.licdn.com/dms/image/v2/D4D0BAQFazp_I3lLeQg/company-logo_200_200/company-logo_200_200/0/1715599858189/the_shared_electronic_banking_services_co_knet_logo?e=2147483647&v=beta&t=FfjCLbNIUGrTCTi-tI5nXSNP9B4AcOJbWsFqV0bSWcM";

interface MediaItem {
  type: 'image' | 'video';
  src: string | File | Blob;
  id: string;
}

type PaymentStatus = 'IDLE' | 'STARTING' | 'VERIFYING' | 'CONFIRMING' | 'SUCCESS';

const ListingDetailsPage: React.FC<ListingDetailsPageProps> = ({ listingId, onBack }) => {
  const [listing, setListing] = useState<Listing | null>(null);
  const [loading, setLoading] = useState(true);
  const [activeImageIndex, setActiveImageIndex] = useState(0);
  const scrollRef = useRef<HTMLDivElement>(null);
  const thumbsRef = useRef<HTMLDivElement>(null);

  const [isUnlocked, setIsUnlocked] = useState(false);
  const [showUnlockPopup, setShowUnlockPopup] = useState(false);
  const [paymentStatus, setPaymentStatus] = useState<PaymentStatus>('IDLE');

  useEffect(() => {
    const fetchListing = async () => {
        setLoading(true);
        const data = await getListingById(Number(listingId));
        if (data) {
            setListing(data);
            const user = JSON.parse(localStorage.getItem('road80_user') || '{}');
            const userId = user.phone || 'guest';
            const unlockKey = `unlock_contact_${userId}_${data.id}`;
            const isOwner = data.publisherId === 'current_user';
            const isStoredUnlocked = localStorage.getItem(unlockKey) === 'true';
            setIsUnlocked(isOwner || isStoredUnlocked);
        } else {
            setTimeout(onBack, 100);
        }
        setLoading(false);
    };
    fetchListing();
  }, [listingId, onBack]);

  if (loading || !listing) {
      return (
          <div className="absolute inset-0 bg-bg dark:bg-slate-950 z-50 flex items-center justify-center transition-colors duration-300">
              <SpinnerIcon className="w-8 h-8 text-navy dark:text-blue animate-spin" />
          </div>
      );
  }

  const mediaItems: MediaItem[] = [];
  const rawImages = listing.images && listing.images.length > 0 
    ? listing.images 
    : [listing.imageUrl || FALLBACK_IMAGE];

  rawImages.forEach((img, idx) => {
      mediaItems.push({ type: 'image', src: img, id: `img-${idx}` });
  });

  if (listing.video) {
      mediaItems.push({ type: 'video', src: listing.video, id: 'vid-main' });
  }

  const getSrc = (src: string | File | Blob) => {
    if (src instanceof File || src instanceof Blob) {
      return URL.createObjectURL(src);
    }
    return src;
  };

  const handleScroll = (e: React.UIEvent<HTMLDivElement>) => {
    const width = e.currentTarget.offsetWidth;
    const scrollLeft = Math.abs(e.currentTarget.scrollLeft);
    const index = Math.round(scrollLeft / width);
    setActiveImageIndex(index);
    if (thumbsRef.current) {
        const thumb = thumbsRef.current.children[index] as HTMLElement;
        if (thumb) {
            thumb.scrollIntoView({ behavior: 'smooth', block: 'nearest', inline: 'center' });
        }
    }
  };

  const scrollToMedia = (index: number) => {
      setActiveImageIndex(index);
      if (scrollRef.current) {
          const child = scrollRef.current.children[index] as HTMLElement;
          if (child) {
              child.scrollIntoView({ behavior: 'smooth', block: 'nearest', inline: 'center' });
          }
      }
  };

  const handlePublisherClick = () => {
    if (listing.publisherId) {
      window.location.hash = `#/profile?user=${listing.publisherId}`;
    }
  };

  const handleUnlockPayment = () => {
    if (paymentStatus !== 'IDLE') return;
    setPaymentStatus('STARTING');
    setTimeout(() => setPaymentStatus('VERIFYING'), 800);
    setTimeout(() => setPaymentStatus('CONFIRMING'), 1800);
    setTimeout(() => {
        setPaymentStatus('SUCCESS');
        const user = JSON.parse(localStorage.getItem('road80_user') || '{}');
        const userId = user.phone || 'guest';
        const unlockKey = `unlock_contact_${userId}_${listing.id}`;
        localStorage.setItem(unlockKey, 'true');
        setIsUnlocked(true);
        setTimeout(() => {
            setShowUnlockPopup(false);
            setPaymentStatus('IDLE');
        }, 1500);
    }, 2600);
  };

  const handleContactAction = (type: 'WHATSAPP' | 'CALL') => {
    if (!isUnlocked) {
        setShowUnlockPopup(true);
        return;
    }
    if (type === 'WHATSAPP') {
        window.open('https://wa.me/96598812020', '_blank');
    } else {
        window.location.href = 'tel:+96598812020';
    }
  };

  const AttrBadge: React.FC<{ label: string; value: string | number | undefined }> = ({ label, value }) => {
    if (!value) return null;
    return (
      <div className="bg-white dark:bg-slate-900 border border-pale dark:border-slate-800 rounded-xl p-3 flex flex-col gap-1 items-start shadow-sm transition-colors duration-300">
        <span className="text-[13px] text-gray-400 font-medium">{label}</span>
        <span className="text-sm font-semibold text-navy dark:text-slate-200">{value}</span>
      </div>
    );
  };

  const getPaymentText = () => {
    switch (paymentStatus) {
      case 'STARTING': return 'جاري بدء عملية الدفع...';
      case 'VERIFYING': return 'جاري التحقق من الدفع...';
      case 'CONFIRMING': return 'جاري تأكيد العملية...';
      case 'SUCCESS': return 'تم الدفع بنجاح';
      default: return 'فتح التواصل مع ناشر الإعلان';
    }
  };

  return (
    <div className="absolute inset-0 bg-bg dark:bg-slate-950 z-50 flex flex-col h-full overflow-hidden animate-fade-in transition-colors duration-300">
      {/* Header */}
      <div 
        className="absolute top-0 left-0 right-0 z-20 flex items-center justify-between px-4"
        style={{ 
            height: 'calc(var(--header-h) + env(safe-area-inset-top))', 
            paddingTop: 'env(safe-area-inset-top)',
            background: 'linear-gradient(to bottom, rgba(0,0,0,0.4) 0%, transparent 100%)'
        }}
      >
        <button 
          onClick={onBack}
          className="w-10 h-10 bg-white/20 backdrop-blur-md rounded-full flex items-center justify-center text-white active:scale-95 transition-all"
        >
          <ChevronRightIcon className="w-6 h-6 rotate-180" />
        </button>
        <div className="flex gap-3">
          <button className="w-10 h-10 bg-white/20 backdrop-blur-md rounded-full flex items-center justify-center text-white active:scale-95 transition-all">
             <CheckIcon className="w-5 h-5" />
          </button>
        </div>
      </div>

      <div className="flex-1 overflow-y-auto overflow-x-hidden pb-24 no-scrollbar bg-bg dark:bg-slate-950 transition-colors duration-300">
        <div className="relative bg-white dark:bg-slate-900 shadow-sm transition-colors duration-300">
             {/* Main Carousel - Strict 1:1 Aspect Ratio using padding hack for iOS stability */}
             <div className="relative w-full pt-[100%] bg-gray-200 dark:bg-slate-800 overflow-hidden group">
                 <div 
                    ref={scrollRef}
                    className="absolute inset-0 w-full h-full flex overflow-x-auto snap-x snap-mandatory no-scrollbar"
                    onScroll={handleScroll}
                    style={{ WebkitOverflowScrolling: 'touch' }}
                 >
                    {mediaItems.map((item, idx) => (
                        <div key={item.id} className="relative w-full h-full flex-shrink-0 snap-center bg-black flex items-center justify-center overflow-hidden">
                            {item.type === 'video' ? (
                                <video 
                                    src={getSrc(item.src)} 
                                    controls 
                                    playsInline
                                    className="w-full h-full object-contain" 
                                    poster={FALLBACK_IMAGE} 
                                />
                            ) : (
                                <img 
                                    src={getSrc(item.src)} 
                                    className="w-full h-full object-cover" 
                                    onError={(e) => (e.currentTarget.src = FALLBACK_IMAGE)} 
                                    alt={`Slide ${idx}`} 
                                />
                            )}
                        </div>
                    ))}
                 </div>
                 {/* Count Badge */}
                 <div className="absolute bottom-4 right-4 bg-black/60 backdrop-blur-md text-white text-[13px] font-bold px-2.5 py-1 rounded-full border border-white/10 z-10 pointer-events-none">
                    {activeImageIndex + 1} / {mediaItems.length}
                 </div>
             </div>

             {/* Thumbnails */}
             {mediaItems.length > 1 && (
                 <div ref={thumbsRef} className="flex gap-2 p-3 overflow-x-auto no-scrollbar border-b border-pale/50 dark:border-slate-800 bg-white dark:bg-slate-900 transition-colors duration-300">
                    {mediaItems.map((item, idx) => (
                        <button key={`thumb-${item.id}`} onClick={() => scrollToMedia(idx)} className={`relative flex-shrink-0 w-16 h-16 rounded-lg overflow-hidden border-2 transition-all ${activeImageIndex === idx ? 'border-navy dark:border-blue ring-1 ring-navy dark:ring-blue shadow-md opacity-100' : 'border-transparent opacity-60 hover:opacity-100'}`}>
                             {item.type === 'video' ? (
                                 <div className="w-full h-full bg-gray-800 flex items-center justify-center relative"><PlayIcon className="w-6 h-6 text-white z-10" /><div className="absolute inset-0 bg-black/20"></div></div>
                             ) : (
                                 <img src={getSrc(item.src)} className="w-full h-full object-cover" onError={(e) => (e.currentTarget.src = FALLBACK_IMAGE)} alt={`Thumb ${idx}`} />
                             )}
                        </button>
                    ))}
                 </div>
             )}
        </div>

        {/* Details Wrapper - Reduced top spacing */}
        <div className="flex flex-col gap-6 px-5 pt-3 pb-8">
            <div className="bg-white dark:bg-slate-900 rounded-3xl p-5 shadow-lg shadow-navy/5 dark:shadow-black/20 border border-pale dark:border-slate-800 transition-colors duration-300">
                <div className="flex justify-between items-start mb-2">
                    <h1 className="text-xl font-bold text-navy dark:text-slate-200 leading-snug max-w-[70%]">{listing.title}</h1>
                    <span className="text-blue dark:text-blue/80 font-bold text-lg">{listing.price}</span>
                </div>
                <div className="flex items-center gap-2 text-gray-500 dark:text-slate-400 text-sm mb-4">
                    <BuildingIcon className="w-4 h-4" />
                    <span className="font-medium">{listing.area}، {listing.governorate}</span>
                </div>
                <div className="flex items-center justify-between pt-4 border-t border-gray-100 dark:border-slate-800 transition-colors duration-300">
                    <div className={`flex items-center gap-2 ${listing.publisherId ? 'cursor-pointer active:scale-95 transition-transform' : ''}`} onClick={handlePublisherClick}>
                         <div className="w-8 h-8 rounded-full bg-gray-100 dark:bg-slate-800 flex items-center justify-center text-gray-400 overflow-hidden shadow-sm border border-pale dark:border-slate-700">
                            {listing.publisherAvatar ? (
                                <img src={listing.publisherAvatar} className="w-full h-full object-cover" alt={listing.publisherName} /> 
                            ) : (
                                <UserIcon className="w-4 h-4" />
                            )}
                         </div>
                         <span className={`text-xs font-semibold text-navy dark:text-slate-300 ${listing.publisherId ? 'hover:text-blue dark:hover:text-blue' : ''}`}>
                             {listing.publisherName || 'مستخدم'}
                         </span>
                    </div>
                    <span className="text-[13px] text-gray-400 dark:text-slate-500 font-medium">
                        {listing.views ? `${listing.views} مشاهدة` : 'جديد'}
                    </span>
                </div>
            </div>

            <div>
                 <h3 className="text-lg font-bold text-navy dark:text-slate-200 mb-3 font-sans">الوصف</h3>
                 <p className="text-sm text-gray-600 dark:text-slate-400 leading-relaxed whitespace-pre-line font-sans font-normal">
                    {listing.description || 'لا يوجد وصف متاح لهذا العقار. يرجى التواصل مع المالك لمزيد من التفاصيل حول العقار ومميزاته.'}
                 </p>
            </div>

            <div>
                 <h3 className="text-lg font-bold text-navy dark:text-slate-200 mb-3 font-sans">تفاصيل العقار</h3>
                 <div className="grid grid-cols-2 gap-3">
                    <AttrBadge label="نوع الإعلان" value={listing.listingType} />
                    <AttrBadge label="نوع العقار" value={listing.propertyType} />
                    <AttrBadge label="المساحة" value={listing.size ? `${listing.size} م²` : undefined} />
                    <AttrBadge label="الغرف" value={listing.rooms} />
                    <AttrBadge label="الحمامات" value={listing.bathrooms} />
                    <AttrBadge label="بلكونة" value={listing.balcony} />
                    <AttrBadge label="المواقف" value={listing.parking} />
                    <AttrBadge label="نظام المواقف" value={listing.parkingSystems?.join(', ')} />
                    <AttrBadge label="التكييف" value={listing.ac} />
                    <AttrBadge label="الكهرباء" value={listing.electricity} />
                    <AttrBadge label="الماء" value={listing.water} />
                 </div>
            </div>
        </div>
      </div>

      <div className="absolute bottom-0 left-0 right-0 p-4 pt-4 bg-white dark:bg-slate-900 border-t border-pale dark:border-slate-800 z-20 transition-colors duration-300" style={{ paddingBottom: 'calc(env(safe-area-inset-bottom) + 16px)' }}>
          <div className="flex gap-2">
            <div className="flex-1 flex gap-1">
                <button onClick={() => handleContactAction('WHATSAPP')} className="flex-1 flex items-center justify-center gap-2 py-3 rounded-xl border border-navy/20 dark:border-slate-700 bg-green-50 dark:bg-green-950/20 text-green-700 dark:text-green-500 font-semibold text-sm active:scale-95 transition-all">
                    <WhatsappIcon className="w-5 h-5" />
                    <span>واتساب</span>
                </button>
                {!isUnlocked && (
                    <button onClick={() => setShowUnlockPopup(true)} className="w-12 flex items-center justify-center bg-white dark:bg-slate-900 border border-pale dark:border-slate-800 rounded-xl text-navy dark:text-slate-400 shadow-sm active:scale-95 transition-all">
                        <LockIcon className="w-5 h-5 opacity-60" />
                    </button>
                )}
            </div>

            <div className="flex-1 flex gap-1">
                <button onClick={() => handleContactAction('CALL')} className="flex-1 flex items-center justify-center gap-2 py-3 rounded-xl bg-navy dark:bg-blue text-white font-semibold text-sm shadow-lg shadow-navy/20 dark:shadow-blue/20 active:scale-95 transition-all">
                    <PhoneIcon className="w-5 h-5" />
                    <span>اتصال</span>
                </button>
                {!isUnlocked && (
                    <button onClick={() => setShowUnlockPopup(true)} className="w-12 flex items-center justify-center bg-white dark:bg-slate-900 border border-pale dark:border-slate-800 rounded-xl text-navy dark:text-slate-400 shadow-sm active:scale-95 transition-all">
                        <LockIcon className="w-5 h-5 opacity-60" />
                    </button>
                )}
            </div>
          </div>
      </div>

      {showUnlockPopup && (
        <div className="fixed inset-0 z-[100] flex items-end sm:items-center justify-center p-0 sm:p-4">
            <div className="absolute inset-0 bg-black/60 dark:bg-black/80 backdrop-blur-sm animate-fade-in" onClick={() => { if (paymentStatus === 'IDLE' || paymentStatus === 'SUCCESS') setShowUnlockPopup(false); }} />
            <div className="relative bg-white dark:bg-slate-900 w-full max-w-sm rounded-t-[32px] sm:rounded-[32px] p-8 shadow-2xl animate-fade-in-up border-t dark:border-slate-800 transition-colors duration-300">
                <div className="w-12 h-1.5 bg-gray-100 dark:bg-slate-800 rounded-full mx-auto mb-8 sm:hidden" />
                <div className="flex flex-col items-center text-center gap-6">
                    <div className="relative w-24 h-24 mb-2 flex items-center justify-center">
                        {paymentStatus === 'IDLE' && (
                            <div className="w-20 h-20 bg-pale/50 dark:bg-slate-800 rounded-full flex items-center justify-center text-navy dark:text-slate-200 border border-pale dark:border-slate-700 animate-fade-in">
                                <LockIcon className="w-10 h-10" />
                            </div>
                        )}
                        {(paymentStatus === 'STARTING' || paymentStatus === 'VERIFYING' || paymentStatus === 'CONFIRMING') && (
                            <div className="w-20 h-20 rounded-full border-4 border-pale dark:border-slate-800 flex items-center justify-center relative animate-fade-in">
                                <div className="absolute inset-0 border-4 border-navy dark:border-blue border-t-transparent rounded-full animate-spin"></div>
                                <SpinnerIcon className="w-10 h-10 text-navy/20 dark:text-blue/20" />
                            </div>
                        )}
                        {paymentStatus === 'SUCCESS' && (
                            <div className="w-20 h-20 bg-green-500 rounded-full flex items-center justify-center shadow-lg shadow-green-200 dark:shadow-green-900/40 animate-scale-in">
                                <svg className="w-12 h-12 text-white" viewBox="0 0 52 52">
                                    <path className="animate-draw" fill="none" stroke="currentColor" strokeWidth="5" strokeLinecap="round" strokeLinejoin="round" strokeDasharray="100" strokeDashoffset="100" d="M14.1 27.2l7.1 7.2 16.7-16.8" />
                                </svg>
                            </div>
                        )}
                    </div>
                    <div className="flex flex-col gap-2 min-h-[80px]">
                        <h3 className={`text-xl font-bold transition-colors duration-300 ${paymentStatus === 'SUCCESS' ? 'text-green-600 dark:text-green-500' : 'text-navy dark:text-slate-200'}`}>
                            {getPaymentText()}
                        </h3>
                        {paymentStatus === 'IDLE' ? (
                            <p className="text-sm text-gray-500 dark:text-slate-400 leading-relaxed max-w-[85%] mx-auto font-sans">
                                لفتح القفل والتواصل مع البائع في هذا الإعلان، يرجى الدفع مرة واحدة فقط.
                            </p>
                        ) : paymentStatus === 'SUCCESS' ? (
                            <p className="text-sm text-green-600/80 dark:text-green-500/80 font-medium animate-fade-in font-sans">
                                تم فتح التواصل مع ناشر الإعلان
                            </p>
                        ) : (
                            <div className="flex flex-col gap-4 mt-2">
                                <div className="w-full h-1.5 bg-gray-100 dark:bg-slate-800 rounded-full overflow-hidden">
                                    <div className={`h-full bg-navy dark:bg-blue transition-all duration-700 ease-out`} style={{ width: paymentStatus === 'STARTING' ? '30%' : paymentStatus === 'VERIFYING' ? '70%' : '95%' }}></div>
                                </div>
                            </div>
                        )}
                    </div>
                    {paymentStatus === 'IDLE' && (
                        <>
                            <div className="bg-bg dark:bg-slate-800 px-6 py-3 rounded-2xl border border-pale/50 dark:border-slate-700 flex items-center gap-3 animate-fade-in transition-colors duration-300">
                                <span className="text-xs text-gray-400 dark:text-slate-500 font-medium">رسوم الفتح:</span>
                                <span className="text-lg font-bold text-navy dark:text-slate-200">{UNLOCK_FEE}</span>
                            </div>
                            <div className="w-full flex flex-col gap-3 mt-4 animate-fade-in">
                                <button onClick={handleUnlockPayment} className="w-full h-14 bg-black dark:bg-slate-950 text-white rounded-2xl font-bold flex items-center justify-center gap-3 active:scale-95 transition-all shadow-xl shadow-black/10">
                                    <AppleIcon className="w-6 h-6 mb-1" />
                                    <span>الدفع عبر Apple Pay</span>
                                </button>
                                <button onClick={handleUnlockPayment} className="w-full h-14 bg-white dark:bg-slate-800 text-navy dark:text-slate-200 border border-gray-200 dark:border-slate-700 rounded-2xl font-bold flex items-center justify-center gap-3 active:scale-95 transition-all shadow-sm">
                                    <img src={KNET_LOGO} className="w-8 h-8 object-contain" alt="KNET" />
                                    <span>الدفع عبر الكي نت</span>
                                </button>
                                <button onClick={() => setShowUnlockPopup(false)} className="w-full h-12 text-gray-400 dark:text-slate-500 font-bold text-sm hover:text-navy dark:hover:text-slate-300 transition-colors active:scale-95 mt-1">
                                    إلغاء
                                </button>
                            </div>
                        </>
                    )}
                    {paymentStatus === 'SUCCESS' && (
                         <div className="w-full mt-4 animate-fade-in">
                             <button onClick={() => setShowUnlockPopup(false)} className="w-full h-14 bg-navy dark:bg-blue text-white rounded-2xl font-bold active:scale-95 transition-all shadow-lg shadow-navy/20">
                                 متابعة
                             </button>
                         </div>
                    )}
                </div>
                <div className="h-[env(safe-area-inset-bottom)] sm:hidden" />
            </div>
        </div>
      )}
    </div>
  );
};

export default ListingDetailsPage;

import React, { useState, useEffect } from 'react';
import { UserIcon, PhoneIcon, WhatsappIcon, BuildingIcon, VerifiedIcon } from './Icons';
import { getListings, DEMO_ADS, DEMO_OFFICES } from '../utils/db';
import { Listing } from '../types';

interface ProfilePageProps {
  onListingClick?: (listing: Listing) => void;
}

const FALLBACK_IMAGE = 'https://raiyansoft.com/wp-content/uploads/2026/01/1.png';

const ListingCard: React.FC<{ listing: Listing, onClick?: () => void }> = ({ listing, onClick }) => {
  const [imgSrc, setImgSrc] = useState<string>('');

  useEffect(() => {
    if (listing.imageUrl instanceof Blob || listing.imageUrl instanceof File) {
        setImgSrc(URL.createObjectURL(listing.imageUrl));
    } else if (typeof listing.imageUrl === 'string') {
        setImgSrc(listing.imageUrl);
    } else if (listing.images && listing.images.length > 0) {
         const first = listing.images[0];
         if (first instanceof Blob || first instanceof File) {
             setImgSrc(URL.createObjectURL(first));
         } else {
             setImgSrc(first as string);
         }
    } else {
        setImgSrc(FALLBACK_IMAGE);
    }
  }, [listing]);

  return (
    <div 
      onClick={onClick}
      className="flex flex-col bg-white dark:bg-slate-900 rounded-xl shadow-[0_2px_8px_rgba(0,0,0,0.04)] border border-pale/50 dark:border-slate-800 overflow-hidden active:scale-98 transition-all duration-300 cursor-pointer"
    >
      <div className="aspect-square bg-slate-100 dark:bg-slate-800 flex items-center justify-center relative">
        <img src={imgSrc} alt={listing.title} className="w-full h-full object-cover" onError={() => setImgSrc(FALLBACK_IMAGE)} />
        <span className="absolute top-2 left-2 bg-navy/80 dark:bg-blue/80 text-white text-[13px] px-2 py-0.5 rounded-full z-10 font-bold">جديد</span>
      </div>
      <div className="p-3 flex flex-col gap-1">
        <span className="text-blue dark:text-blue/80 font-bold text-sm text-right font-sans">{listing.price}</span>
        <h4 className="text-navy dark:text-slate-200 font-semibold text-xs truncate text-right font-sans">{listing.title}</h4>
        <div className="flex items-center justify-end gap-1 opacity-60">
          <span className="text-[13px] text-navy dark:text-slate-400 font-medium font-sans">{listing.area}</span>
          <div className="w-1 h-1 rounded-full bg-navy dark:bg-slate-500"></div>
        </div>
      </div>
    </div>
  );
};

const StatItem: React.FC<{ label: string; value: string }> = ({ label, value }) => (
  <div className="flex flex-col items-center gap-1">
    <span className="text-lg font-bold text-navy dark:text-slate-200 font-sans">{value}</span>
    <span className="text-xs text-gray-400 dark:text-slate-500 font-medium font-sans">{label}</span>
  </div>
);

const ProfilePage: React.FC<ProfilePageProps> = ({ onListingClick }) => {
  const getParams = () => {
     const hashSplit = window.location.hash.split('?');
     return new URLSearchParams(hashSplit[1] || '');
  };

  const params = getParams();
  const viewedUserId = params.get('user');
  const activeTabParam = params.get('tab');
  const isMe = !viewedUserId || viewedUserId === 'current_user';

  const [activeSubTab, setActiveSubTab] = useState<'ads' | 'favorites'>(
    (activeTabParam === 'favorites' && isMe) ? 'favorites' : 'ads'
  );
  const [savedListings, setSavedListings] = useState<Listing[]>([]);

  useEffect(() => {
    const handleHashChange = () => {
      const p = getParams();
      const tab = p.get('tab');
      if (isMe) setActiveSubTab(tab === 'favorites' ? 'favorites' : 'ads');
    };
    window.addEventListener('hashchange', handleHashChange);
    return () => window.removeEventListener('hashchange', handleHashChange);
  }, [isMe]);

  const handleTabChange = (tab: 'ads' | 'favorites') => {
    if (!isMe) return;
    const currentHash = window.location.hash.split('?')[0];
    window.location.hash = `${currentHash}?tab=${tab}`;
  };

  useEffect(() => {
    const loadListings = async () => {
        try {
            const dbListings = await getListings();
            const mapped: Listing[] = dbListings.map((l: any) => ({
                id: l.id,
                listingType: l.listingType || 'غير محدد',
                propertyType: l.propertyType || 'عقار',
                price: l.price || '0 د.ك',
                area: l.area || 'غير محدد',
                governorate: l.governorate || 'الكويت',
                title: `${l.listingType} ${l.propertyType} في ${l.area}`,
                rooms: l.rooms,
                bathrooms: l.bathrooms,
                size: l.size,
                balcony: l.balcony,
                parking: l.parking,
                parkingSystems: l.parkingSystems,
                electricity: l.electricity,
                water: l.water,
                ac: l.ac,
                description: l.description,
                images: l.images || [],
                video: l.video,
                imageUrl: l.imageUrl || FALLBACK_IMAGE,
                views: 0,
                publisherId: l.publisherId,
                publisherName: l.publisherName
            }));
            setSavedListings(mapped);
        } catch (e) { console.error(e); }
    };
    loadListings();
  }, []);

  let profileName = 'فهد الحمدان';
  let profileBio = 'وسيط عقاري معتمد.\nخبرة 10 سنوات في السوق العقاري.';
  let profileAvatar: string | null = null;
  let isVerified = false;
  let stats = { ads: "0", likes: isMe ? "27" : "12", views: isMe ? "1,240" : "540" };
  let displayList: Listing[] = [];

  if (isMe) {
      const myAds = [...savedListings, ...DEMO_ADS]; 
      const myFavs = [DEMO_ADS[3]]; 
      displayList = activeSubTab === 'ads' ? myAds : myFavs;
      stats.ads = myAds.length.toString();
  } else {
      const office = DEMO_OFFICES.find(o => o.id === viewedUserId);
      if (office) {
        profileName = office.officeName;
        profileBio = office.bio;
        profileAvatar = office.logo;
        isVerified = office.verified;
        stats = { ads: office.activeListingsCount.toString(), likes: Math.floor(office.totalViews / 10).toString(), views: office.totalViews.toLocaleString() };
        displayList = office.sampleListings;
      } else {
        profileName = 'ناشر الإعلان';
        profileBio = 'عضو في 80road';
        const externalAds = [...savedListings, ...DEMO_ADS].filter(l => l.publisherId === viewedUserId);
        displayList = externalAds;
        stats.ads = externalAds.length.toString();
      }
  }

  return (
    <div className="flex flex-col p-4 gap-6 pb-24 animate-fade-in transition-colors duration-300">
      <div className="flex items-center gap-4">
        <div className="w-20 h-20 rounded-full bg-gradient-to-br from-pale to-white dark:from-slate-800 dark:to-slate-900 flex items-center justify-center text-navy dark:text-slate-200 shrink-0 border-2 border-white dark:border-slate-800 shadow-md overflow-hidden relative">
          {profileAvatar ? (
             <img src={profileAvatar} alt={profileName} className="w-full h-full object-cover" />
          ) : (
             <UserIcon className="w-10 h-10 opacity-80" />
          )}
        </div>
        <div className="flex flex-col gap-1 flex-1">
          <div className="flex items-center gap-1">
             <h2 className="text-xl font-bold text-navy dark:text-slate-200 font-sans line-clamp-1">{profileName}</h2>
             {isVerified && <VerifiedIcon className="w-5 h-5 text-blue shrink-0" />}
          </div>
          <p className="text-xs text-gray-500 dark:text-slate-400 leading-snug font-sans font-normal whitespace-pre-line">
            {profileBio}
          </p>
        </div>
      </div>

      <div className="flex justify-between items-center px-4 py-4 bg-white dark:bg-slate-900 rounded-2xl shadow-sm border border-pale dark:border-slate-800 transition-colors duration-300">
        <StatItem label="الإعلانات" value={stats.ads} />
        <div className="w-px h-8 bg-gray-100 dark:bg-slate-800"></div>
        <StatItem label="اللايكات" value={stats.likes} />
        <div className="w-px h-8 bg-gray-100 dark:bg-slate-800"></div>
        <StatItem label="المشاهدات" value={stats.views} />
      </div>

      <div className="flex gap-3">
        <a href="https://wa.me/96598812020" target="_blank" rel="noopener noreferrer" className="flex-1 flex items-center justify-center gap-2 py-2.5 rounded-xl border border-navy/20 dark:border-slate-700 bg-white dark:bg-slate-900 text-navy dark:text-slate-200 font-semibold text-sm transition-all active:scale-98">
          <WhatsappIcon className="w-6 h-6" />
          <span>ارسال واتساب</span>
        </a>
        <a href="tel:+96598812020" className="flex-1 flex items-center justify-center gap-2 py-2.5 rounded-xl bg-navy dark:bg-blue text-white font-semibold text-sm shadow-lg shadow-navy/20 dark:shadow-blue/20 transition-all active:scale-98">
          <PhoneIcon className="w-5 h-5" />
          <span>اتصال</span>
        </a>
      </div>

      <div className="flex flex-col gap-4 mt-2">
        <h3 className="text-lg font-bold text-navy dark:text-slate-200 font-sans px-1">
            {isMe ? 'اعلاناتي' : `إعلانات ${profileName}`}
        </h3>
        {isMe && (
            <div className="flex p-1 bg-gray-100/80 dark:bg-slate-800 rounded-xl relative transition-colors duration-300">
            <button onClick={() => handleTabChange('ads')} className={`flex-1 py-2 text-xs font-bold rounded-lg transition-all duration-300 font-sans ${activeSubTab === 'ads' ? 'bg-white dark:bg-slate-900 shadow-[0_2px_8px_rgba(0,0,0,0.05)] text-navy dark:text-slate-200' : 'text-gray-400 dark:text-slate-500 hover:text-gray-600 dark:hover:text-slate-300'}`}>اعلاناتي</button>
            <button onClick={() => handleTabChange('favorites')} className={`flex-1 py-2 text-xs font-bold rounded-lg transition-all duration-300 font-sans ${activeSubTab === 'favorites' ? 'bg-white dark:bg-slate-900 shadow-[0_2px_8px_rgba(0,0,0,0.05)] text-navy dark:text-slate-200' : 'text-gray-400 dark:text-slate-500 hover:text-gray-600 dark:hover:text-slate-300'}`}>مفضلتي</button>
            </div>
        )}
        <div className="grid grid-cols-2 gap-3 min-h-[200px]">
          {displayList.map((item, idx) => (
            <ListingCard key={`${item.id}-${idx}`} listing={item} onClick={() => onListingClick && onListingClick(item)} />
          ))}
          {displayList.length === 0 && (
            <div className="col-span-2 py-10 text-center text-gray-400 dark:text-slate-600 text-sm font-medium">لا توجد إعلانات</div>
          )}
        </div>
      </div>
    </div>
  );
};

export default ProfilePage;

import React, { useEffect, useState } from 'react';
import { getExploreListings } from '../utils/db';
import { Listing } from '../types';
import { PlayIcon, SpinnerIcon } from './Icons';

const FALLBACK_IMAGE = 'https://raiyansoft.com/wp-content/uploads/2026/01/1.png';

const ExplorePage: React.FC = () => {
  const [listings, setListings] = useState<Listing[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchExplore = async () => {
      setLoading(true);
      const data = await getExploreListings();
      setListings(data);
      setLoading(false);
    };
    fetchExplore();
  }, []);

  const handleClick = (id: number) => {
    window.location.hash = `#/ad/${id}`;
  };

  const getPoster = (l: Listing) => {
    // Use first image as poster
    if (l.images && l.images.length > 0) {
       const first = l.images[0];
       if (first instanceof File || first instanceof Blob) {
           return URL.createObjectURL(first);
       }
       return first as string;
    }
    if (l.imageUrl) {
        if (l.imageUrl instanceof File || l.imageUrl instanceof Blob) {
           return URL.createObjectURL(l.imageUrl);
        }
        return l.imageUrl as string;
    }
    return FALLBACK_IMAGE;
  };

  if (loading) {
    return (
      <div className="flex justify-center items-center h-full">
         <SpinnerIcon className="w-8 h-8 text-navy animate-spin" />
      </div>
    );
  }

  return (
    <div className="w-full h-full bg-bg overflow-y-auto no-scrollbar pb-24 animate-fade-in">
      {/* Grid */}
      <div className="grid grid-cols-2 gap-0.5">
         {listings.map(item => (
           <div 
             key={item.id}
             onClick={() => handleClick(item.id)}
             className="relative aspect-square bg-gray-200 cursor-pointer overflow-hidden group"
           >
             {/* Thumbnail */}
             <img 
               src={getPoster(item)} 
               alt={item.title}
               className="w-full h-full object-cover transition-transform duration-500 group-hover:scale-105"
               onError={(e) => e.currentTarget.src = FALLBACK_IMAGE}
             />

             {/* Dark Gradient Overlay */}
             <div className="absolute inset-0 bg-gradient-to-t from-black/60 via-transparent to-transparent opacity-80" />

             {/* Play Icon Center */}
             <div className="absolute inset-0 flex items-center justify-center">
                <div className="w-10 h-10 rounded-full bg-white/20 backdrop-blur-md flex items-center justify-center border border-white/30">
                    <PlayIcon className="w-5 h-5 text-white ml-0.5" />
                </div>
             </div>

             {/* Meta Info (Bottom) */}
             <div className="absolute bottom-0 left-0 right-0 p-3 flex flex-col justify-end text-white">
                <span className="font-bold text-sm drop-shadow-md truncate">{item.price}</span>
                <div className="flex items-center justify-between mt-0.5">
                   <span className="text-[13px] opacity-90 truncate max-w-[70%]">{item.area}</span>
                   <span className="text-[13px] opacity-75">{item.propertyType}</span>
                </div>
             </div>
           </div>
         ))}
      </div>

      {listings.length === 0 && (
          <div className="flex flex-col items-center justify-center h-64 text-gray-400">
             <PlayIcon className="w-12 h-12 mb-2 opacity-20" />
             <p className="text-sm">لا توجد فيديوهات حالياً</p>
          </div>
      )}
    </div>
  );
};

export default ExplorePage;

import React, { useState, useEffect, useRef } from 'react';
import { SpinnerIcon, ChevronRightIcon, PhoneIcon } from './Icons';

interface AuthPageProps {
  onLoginSuccess: () => void;
}

const AuthPage: React.FC<AuthPageProps> = ({ onLoginSuccess }) => {
  const [step, setStep] = useState<'PHONE' | 'OTP'>('PHONE');
  const [phone, setPhone] = useState('98812020'); // Demo default
  const [otp, setOtp] = useState(['', '', '', '']);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [timer, setTimer] = useState(30);
  const inputs = useRef<(HTMLInputElement | null)[]>([]);

  // Sync route with internal step on mount/hash change
  useEffect(() => {
    const handleHash = () => {
      const hash = window.location.hash;
      if (hash.includes('/verify')) {
         const storedPhone = sessionStorage.getItem('temp_auth_phone');
         if (!storedPhone) {
            window.location.hash = '#/auth';
            setStep('PHONE');
         } else {
            setStep('OTP');
            setPhone(storedPhone);
         }
      } else {
         setStep('PHONE');
      }
    };

    handleHash();
    window.addEventListener('hashchange', handleHash);
    return () => window.removeEventListener('hashchange', handleHash);
  }, []);

  // Timer logic for OTP
  useEffect(() => {
    let interval: any;
    if (step === 'OTP' && timer > 0) {
      interval = setInterval(() => setTimer((t) => t - 1), 1000);
    }
    return () => clearInterval(interval);
  }, [step, timer]);

  const handlePhoneSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');

    // Basic Validation
    if (!phone || phone.length < 8 || isNaN(Number(phone))) {
       setError('يرجى إدخال رقم هاتف صحيح');
       return;
    }

    setLoading(true);
    // Simulate API call
    setTimeout(() => {
       setLoading(false);
       sessionStorage.setItem('temp_auth_phone', phone);
       window.location.hash = '#/verify';
    }, 800);
  };

  const handleOtpChange = (index: number, value: string) => {
    if (value.length > 1) value = value[0];
    if (!/^\d*$/.test(value)) return;

    const newOtp = [...otp];
    newOtp[index] = value;
    setOtp(newOtp);

    // Auto focus next
    if (value && index < 3) {
      inputs.current[index + 1]?.focus();
    }

    // Clear error on change
    if (error) setError('');
  };

  const handleKeyDown = (index: number, e: React.KeyboardEvent) => {
    if (e.key === 'Backspace' && !otp[index] && index > 0) {
      inputs.current[index - 1]?.focus();
    }
  };

  const handleVerify = async () => {
    const code = otp.join('');
    if (code.length !== 4) return;

    setLoading(true);
    setError('');

    setTimeout(() => {
       if (code === '1234') {
          // Success
          const session = {
             phone,
             token: 'demo_token_' + Date.now(),
             loggedInAt: Date.now()
          };
          localStorage.setItem('road80_user', JSON.stringify(session));
          onLoginSuccess();
       } else {
          setError('رمز التفعيل غير صحيح');
          setLoading(false);
          setOtp(['', '', '', '']);
          inputs.current[0]?.focus();
       }
    }, 1000);
  };

  const handleResend = () => {
     if (timer > 0) return;
     setTimer(30);
     // Simulate resend
     alert('تم إعادة إرسال الرمز (1234)');
  };

  return (
    <div className="min-h-full w-full bg-slate-50 flex flex-col items-center justify-center relative overflow-hidden animate-fade-in p-6">

      {/* Soft Background Blobs */}
      <div className="absolute top-[-10%] left-[-10%] w-[60%] h-[40%] bg-blue/5 rounded-full blur-3xl pointer-events-none" />
      <div className="absolute bottom-[-10%] right-[-10%] w-[60%] h-[40%] bg-navy/5 rounded-full blur-3xl pointer-events-none" />

      {/* Main Content Container */}
      <div className="w-full max-w-[340px] flex flex-col items-center z-10">

        {/* Logo */}
        <div className="mb-8">
           <img 
              src="https://raiyansoft.com/wp-content/uploads/2026/02/sg54.png" 
              className="w-32 h-auto drop-shadow-sm" 
              alt="Logo" 
           />
        </div>

        {/* Floating Sheet Card */}
        <div className="w-full bg-white rounded-[32px] shadow-[0_8px_30px_rgba(0,0,0,0.04)] p-8 border border-white/60">

           {/* Header Text */}
           <div className="text-center mb-8">
              <h1 className="text-2xl font-bold text-navy mb-2">
                 {step === 'PHONE' ? 'تسجيل الدخول' : 'التحقق'}
              </h1>
              <p className="text-gray-400 text-xs font-medium">
                 {step === 'PHONE' 
                    ? 'أهلاً بك في منصة 80road العقارية' 
                    : `تم إرسال رمز التفعيل إلى ${phone}`
                 }
              </p>
           </div>

           {step === 'PHONE' ? (
             <form onSubmit={handlePhoneSubmit} className="flex flex-col gap-6">

                {/* Phone Input Group */}
                <div className="flex flex-col gap-2">
                   <label className="text-xs font-bold text-gray-500 mr-2">رقم الهاتف</label>

                   {/* Container enforced to LTR to keep [Code] [Divider] [Input] order correct visually */}
                   <div 
                     dir="ltr"
                     className="relative h-16 bg-slate-50 rounded-2xl flex items-center px-4 border border-transparent focus-within:border-navy/20 focus-within:bg-white focus-within:ring-4 focus-within:ring-navy/5 transition-all"
                   >
                      {/* Country Code (Left) */}
                      <div className="flex items-center gap-2 shrink-0 text-navy select-none">
                         <span className="text-2xl pt-1">🇰🇼</span>
                         <span className="text-sm font-bold tracking-wider">+965</span>
                      </div>

                      {/* Divider */}
                      <div className="w-px h-6 bg-gray-200 shrink-0 mx-3"></div>

                      {/* Input (Right) */}
                      <input 
                        type="tel"
                        value={phone}
                        onChange={(e) => setPhone(e.target.value)}
                        className="flex-1 bg-transparent h-full text-left font-sans font-bold text-xl text-navy placeholder:text-gray-300 focus:outline-none tracking-wider"
                        placeholder="00000000"
                        maxLength={8}
                      />
                   </div>
                </div>

                <button 
                  type="submit"
                  disabled={loading}
                  className="w-full h-14 bg-navy text-white rounded-2xl font-bold text-lg shadow-lg shadow-navy/20 hover:bg-blue active:scale-95 transition-all flex items-center justify-center gap-2 mt-2"
                >
                  {loading ? <SpinnerIcon className="w-6 h-6 animate-spin text-white" /> : 'إرسال رمز التفعيل'}
                </button>
             </form>
           ) : (
             <div className="flex flex-col gap-8">

                {/* OTP Inputs */}
                <div className="flex justify-between items-center px-1" dir="ltr">
                   {otp.map((digit, idx) => (
                      <input
                        key={idx}
                        ref={el => inputs.current[idx] = el}
                        type="text"
                        inputMode="numeric"
                        maxLength={1}
                        value={digit}
                        onChange={(e) => handleOtpChange(idx, e.target.value)}
                        onKeyDown={(e) => handleKeyDown(idx, e)}
                        className={`w-14 h-16 rounded-2xl border-2 text-center text-2xl font-bold transition-all focus:outline-none focus:ring-4 focus:ring-navy/10 ${
                           digit ? 'border-navy bg-white text-navy' : 'border-gray-100 bg-slate-50 text-gray-800'
                        } ${error ? 'border-red-500 bg-red-50' : ''}`}
                      />
                   ))}
                </div>

                <button 
                  onClick={handleVerify}
                  disabled={loading || otp.join('').length !== 4}
                  className={`w-full h-14 rounded-2xl font-bold text-lg shadow-lg transition-all flex items-center justify-center gap-2 ${
                     otp.join('').length === 4 
                     ? 'bg-navy text-white shadow-navy/20 active:scale-95 hover:bg-blue' 
                     : 'bg-gray-100 text-gray-400 cursor-not-allowed'
                  }`}
                >
                  {loading ? <SpinnerIcon className="w-6 h-6 animate-spin" /> : 'تأكيد'}
                </button>

                {/* Resend & Back */}
                <div className="flex flex-col items-center gap-4 -mt-2">
                   <button 
                     onClick={handleResend}
                     disabled={timer > 0}
                     className={`text-xs font-bold transition-colors ${timer > 0 ? 'text-gray-400' : 'text-blue hover:text-navy'}`}
                   >
                     {timer > 0 ? `إعادة الإرسال بعد ${timer} ثانية` : 'إعادة إرسال الرمز'}
                   </button>

                   <button 
                     onClick={() => window.location.hash = '#/auth'}
                     className="text-xs text-gray-400 hover:text-navy transition-colors py-2 px-4 hover:bg-slate-50 rounded-lg"
                   >
                     تغيير رقم الهاتف
                   </button>
                </div>
             </div>
           )}

           {error && (
              <div className="mt-4 p-3 bg-red-50 text-red-500 text-xs font-bold text-center rounded-xl animate-fade-in border border-red-100">
                 {error}
              </div>
           )}

        </div>

        {/* Footer Text */}
        <div className="mt-8 text-center px-4 opacity-60 hover:opacity-100 transition-opacity">
           <p className="text-[13px] text-gray-500 leading-relaxed">
              بتسجيل الدخول فإنك توافق على 
              <span className="underline cursor-pointer hover:text-navy mx-1">الشروط والأحكام</span> 
              و 
              <span className="underline cursor-pointer hover:text-navy mx-1">سياسة الخصوصية</span>
           </p>
        </div>

      </div>
    </div>
  );
};

export default AuthPage;

import React, { useState, useEffect } from 'react';
import { ChevronRightIcon, CheckIcon, AppleIcon, UploadIcon, PlayIcon, BuildingIcon } from './Icons';
import { GOVERNORATES, AREAS } from '../data/locations';
import { saveListing } from '../utils/db';

interface AddWizardProps {
  onComplete: () => void;
}

const TOTAL_STEPS = 17;
const FALLBACK_IMAGE = 'https://raiyansoft.com/wp-content/uploads/2026/01/1.png';
const KNET_LOGO = "https://media.licdn.com/dms/image/v2/D4D0BAQFazp_I3lLeQg/company-logo_200_200/company-logo_200_200/0/1715599858189/the_shared_electronic_banking_services_co_knet_logo?e=2147483647&v=beta&t=FfjCLbNIUGrTCTi-tI5nXSNP9B4AcOJbWsFqV0bSWcM";

const COUNTRIES = [
  { name: 'الكويت', flag: '🇰🇼' },
  { name: 'السعودية', flag: '🇸🇦' },
  { name: 'الإمارات', flag: '🇦🇪' },
  { name: 'قطر', flag: '🇶🇦' },
  { name: 'البحرين', flag: '🇧🇭' },
  { name: 'عُمان', flag: '🇴🇲' },
  { name: 'سوريا', flag: '🇸🇾' },
  { name: 'مصر', flag: '🇪🇬' },
  { name: 'الأردن', flag: '🇯🇴' },
  { name: 'تركيا', flag: '🇹🇷' }
];

const AddWizard: React.FC<AddWizardProps> = ({ onComplete }) => {
  // Initialize step from URL
  const getStepFromUrl = () => {
    const params = new URLSearchParams(window.location.hash.split('?')[1]);
    const s = parseInt(params.get('step') || '1');
    return isNaN(s) || s < 1 ? 1 : (s > TOTAL_STEPS ? TOTAL_STEPS : s);
  };

  const [step, setStep] = useState(getStepFromUrl());
  const [formData, setFormData] = useState<any>({
    listingType: '',
    propertyType: '',
    country: 'الكويت',
    governorate: '',
    area: '',
    rooms: '',
    bathrooms: '',
    size: 400,
    balcony: '',
    parking: '',
    parkingSystems: [],
    electricity: '',
    water: '',
    ac: '',
    video: null,
    images: []
  });
  const [isProcessing, setIsProcessing] = useState(false);
  const [isPaid, setIsPaid] = useState(false);

  // Sync state with URL changes (back/forward)
  useEffect(() => {
    const handleHashChange = () => {
      const newStep = getStepFromUrl();
      setStep(newStep);
    };
    window.addEventListener('hashchange', handleHashChange);
    return () => window.removeEventListener('hashchange', handleHashChange);
  }, []);

  // Update URL when step changes internally
  const updateStepUrl = (newStep: number) => {
     const currentHash = window.location.hash.split('?')[0];
     window.location.hash = `${currentHash}?step=${newStep}`;
  };

  // Helper to scroll to top on step change
  useEffect(() => {
    const content = document.getElementById('wizard-content');
    if (content) content.scrollTop = 0;
  }, [step]);

  const updateData = (key: string, value: any) => {
    setFormData((prev: any) => ({ ...prev, [key]: value }));
  };

  const nextStep = () => {
    if (step < TOTAL_STEPS) updateStepUrl(step + 1);
  };

  const prevStep = () => {
    if (step > 1) updateStepUrl(step - 1);
  };

  const selectAndNext = (key: string, value: any) => {
    updateData(key, value);
    nextStep();
  };

  const handleMediaUpload = (e: React.ChangeEvent<HTMLInputElement>, type: 'video' | 'images') => {
    if (e.target.files && e.target.files.length > 0) {
      if (type === 'video') {
        updateData('video', e.target.files[0]);
      } else {
        const newImages = Array.from(e.target.files);
        setFormData((prev: any) => ({ ...prev, images: [...prev.images, ...newImages] }));
      }
    }
  };

  const handlePublish = async () => {
    setIsProcessing(true);
    // Simulate Payment
    setTimeout(async () => {
      setIsProcessing(false);
      setIsPaid(true);

      const newListing = {
        id: Date.now(),
        createdAt: new Date(),
        price: '5 د.ك', // Default dummy rental price or use logic
        publisherId: 'current_user',
        publisherName: 'فهد الحمدان',
        ...formData,
        imageUrl: formData.images.length > 0 
          ? URL.createObjectURL(formData.images[0]) 
          : FALLBACK_IMAGE
      };

      await saveListing(newListing);

      setTimeout(() => {
        onComplete();
        // Reset wizard
        setFormData({ size: 400, parkingSystems: [], images: [], country: 'الكويت' });
      }, 1500);
    }, 2000);
  };

  // Render Helpers
  const renderOption = (content: React.ReactNode, isSelected: boolean, onClick: () => void) => (
    <button
      onClick={onClick}
      className={`w-full p-4 mb-3 rounded-2xl border flex items-center justify-between transition-all duration-200 active:scale-98 ${
        isSelected 
          ? 'border-navy bg-navy text-white shadow-lg shadow-navy/20' 
          : 'border-pale bg-white text-navy hover:border-mid'
      }`}
    >
      <div className="font-bold text-sm">{content}</div>
      {isSelected && <CheckIcon className="w-5 h-5 text-white" />}
    </button>
  );

  const renderTitle = (title: string) => (
    <h2 className="text-xl font-bold text-navy mb-6 text-center">{title}</h2>
  );

  // Show footer on all steps unless payment is successfully processed
  const showFooter = !isPaid;

  const renderFooterAction = () => {
    const isFirstStep = step === 1;

    // Shared Back Button (Secondary Style)
    const backButton = (
      <button 
        onClick={prevStep} 
        disabled={isFirstStep}
        className={`w-full py-3 bg-white border border-pale text-navy rounded-xl font-bold transition-all shadow-sm ${
          isFirstStep ? 'opacity-50 cursor-not-allowed' : 'active:scale-95 hover:bg-pale/30'
        }`}
      >
        رجوع
      </button>
    );

    // Primary Next Button
    const nextButton = (
      <button 
        onClick={nextStep} 
        className="w-full py-4 bg-navy text-white rounded-xl font-bold shadow-lg shadow-navy/20 active:scale-95 transition-all"
      >
        التالي
      </button>
    );

    // Steps that require a manual "Next" button (stacked layout)
    // 8: Size (Slider), 15: Video, 16: Images
    if ([8, 15, 16].includes(step)) {
      return (
        <div className="flex flex-col gap-3">
          {backButton}
          {nextButton}
        </div>
      );
    }

    // Step 17: Publish (Payment)
    if (step === 17) {
      return (
        <div className="flex flex-col gap-3">
          {backButton}
          <button 
            onClick={handlePublish}
            disabled={isProcessing}
            className="w-full py-4 bg-black text-white rounded-xl font-bold flex items-center justify-center gap-2 active:scale-95 transition-all shadow-xl"
          >
            {isProcessing ? (
               <span className="animate-pulse">جاري المعالجة...</span>
            ) : (
              <>
               <AppleIcon className="w-5 h-5 mb-0.5" />
               <span>الدفع والنشر (Apple Pay)</span>
              </>
            )}
          </button>
          <button 
            onClick={handlePublish}
            disabled={isProcessing}
            className="w-full py-4 bg-white text-navy border border-pale rounded-xl font-bold flex items-center justify-center gap-2 active:scale-95 transition-all shadow-sm"
          >
            {isProcessing ? (
               <span className="animate-pulse">جاري المعالجة...</span>
            ) : (
              <>
               <img src={KNET_LOGO} className="w-8 h-8 object-contain" alt="KNET" />
               <span>الدفع عبر الكي نت</span>
              </>
            )}
          </button>
        </div>
      );
    }

    // Default for all other steps (Single Choice / Auto-advance)
    // Always render at least the back button as per requirement
    return (
      <div className="w-full">
        {backButton}
      </div>
    );
  };

  const renderContent = () => {
    switch (step) {
      case 1:
        return (
          <>
            {renderTitle('نوع الاعلان')}
            {['للبيع', 'للإيجار'].map(opt => (
              renderOption(opt, formData.listingType === opt, () => selectAndNext('listingType', opt))
            ))}
          </>
        );
      case 2:
        return (
          <>
            {renderTitle('نوع العقار')}
            {['بيت', 'شقة', 'دور', 'عمارة', 'دوبلكس'].map(opt => (
              renderOption(opt, formData.propertyType === opt, () => selectAndNext('propertyType', opt))
            ))}
          </>
        );
      case 3:
        return (
          <>
            {renderTitle('الدولة')}
            {COUNTRIES.map(opt => (
              renderOption(
                <div className="flex items-center gap-3">
                  <span className="text-2xl">{opt.flag}</span>
                  <span>{opt.name}</span>
                </div>, 
                formData.country === opt.name, 
                () => selectAndNext('country', opt.name)
              )
            ))}
          </>
        );
      case 4:
        // Use Kuwait governorates regardless of country (Demo limitation)
        return (
          <>
            {renderTitle('المحافظة')}
            {GOVERNORATES.map(opt => (
              renderOption(opt, formData.governorate === opt, () => selectAndNext('governorate', opt))
            ))}
          </>
        );
      case 5:
        const areas = AREAS[formData.governorate] || [];
        return (
          <>
            {renderTitle('المنطقة')}
            <div className="grid grid-cols-1 gap-1">
              {areas.map(opt => (
                renderOption(opt, formData.area === opt, () => selectAndNext('area', opt))
              ))}
            </div>
          </>
        );
      case 6:
        return (
          <>
            {renderTitle('عدد الغرف')}
            <div className="grid grid-cols-3 gap-3">
              {Array.from({ length: 12 }, (_, i) => i + 1).map(num => (
                <button
                  key={num}
                  onClick={() => selectAndNext('rooms', num)}
                  className={`aspect-square rounded-2xl border flex items-center justify-center text-lg font-bold transition-all ${
                    formData.rooms === num ? 'bg-navy text-white' : 'bg-white text-navy border-pale'
                  }`}
                >
                  {num}
                </button>
              ))}
            </div>
          </>
        );
      case 7:
        return (
          <>
            {renderTitle('عدد الحمامات')}
            <div className="grid grid-cols-3 gap-3">
              {[...Array.from({ length: 10 }, (_, i) => i + 1), '10+'].map(num => (
                <button
                  key={num}
                  onClick={() => selectAndNext('bathrooms', num)}
                  className={`aspect-square rounded-2xl border flex items-center justify-center text-lg font-bold transition-all ${
                    formData.bathrooms === num ? 'bg-navy text-white' : 'bg-white text-navy border-pale'
                  }`}
                >
                  {num}
                </button>
              ))}
            </div>
          </>
        );
      case 8:
        return (
          <>
            {renderTitle('المساحة')}
            <div className="flex flex-col items-center justify-center gap-8 py-10 bg-white rounded-3xl border border-pale shadow-sm">
              <span className="text-4xl font-bold text-blue">{formData.size} <span className="text-sm text-gray-400">م²</span></span>
              <input 
                type="range" 
                min="50" 
                max="2000" 
                step="5" 
                value={formData.size} 
                onChange={(e) => updateData('size', parseInt(e.target.value))}
                className="w-4/5 accent-navy h-2 bg-pale rounded-lg appearance-none cursor-pointer"
              />
            </div>
          </>
        );
      case 9:
        return (
          <>
            {renderTitle('بلكونة')}
            {['نعم', 'لا'].map(opt => (
              renderOption(opt, formData.balcony === opt, () => selectAndNext('balcony', opt))
            ))}
          </>
        );
      case 10:
        return (
          <>
            {renderTitle('عدد المواقف')}
            {['1', '2', '3', '3+'].map(opt => (
              renderOption(opt, formData.parking === opt, () => selectAndNext('parking', opt))
            ))}
          </>
        );
      case 11:
        return (
          <>
            {renderTitle('نظام المواقف')}
            {['مظلات', 'سرداب', 'اخرى'].map(opt => (
              renderOption(opt, formData.parkingSystems.includes(opt), () => selectAndNext('parkingSystems', [opt]))
            ))}
          </>
        );
      case 12:
        return (
          <>
            {renderTitle('الكهرباء')}
            {['على المالك', 'على المستأجر'].map(opt => (
              renderOption(opt, formData.electricity === opt, () => selectAndNext('electricity', opt))
            ))}
          </>
        );
      case 13:
        return (
          <>
            {renderTitle('الماء')}
            {['على المالك', 'على المستأجر'].map(opt => (
              renderOption(opt, formData.water === opt, () => selectAndNext('water', opt))
            ))}
          </>
        );
      case 14:
        return (
          <>
            {renderTitle('التكييف')}
            {['على المالك', 'على المستأجر'].map(opt => (
              renderOption(opt, formData.ac === opt, () => selectAndNext('ac', opt))
            ))}
          </>
        );
      case 15:
        return (
          <>
            {renderTitle('ارفع فيديو')}
            <div className="relative aspect-video bg-gray-100 rounded-xl overflow-hidden border-2 border-dashed border-mid mb-4 flex items-center justify-center group">
              {formData.video ? (
                <video src={URL.createObjectURL(formData.video)} className="w-full h-full object-cover" controls />
              ) : (
                <div className="flex flex-col items-center gap-2">
                  <div className="w-16 h-16 bg-navy/10 rounded-full flex items-center justify-center">
                    <PlayIcon className="w-8 h-8 text-navy" />
                  </div>
                  <span className="text-sm text-gray-500">فيديو ديمو</span>
                </div>
              )}
              <input 
                type="file" 
                accept="video/*" 
                onChange={(e) => handleMediaUpload(e, 'video')}
                className="absolute inset-0 opacity-0 cursor-pointer"
              />
            </div>
          </>
        );
      case 16:
        const demoImages = [
           'https://images.unsplash.com/photo-1522708323590-d24dbb6b0267?q=80&w=300&auto=format&fit=crop',
           'https://images.unsplash.com/photo-1502672260266-1c1ef2d93688?q=80&w=300&auto=format&fit=crop',
           'https://images.unsplash.com/photo-1600607687939-ce8a6c25118c?q=80&w=300&auto=format&fit=crop',
           'https://images.unsplash.com/photo-1600596542815-40b5104d57ea?q=80&w=300&auto=format&fit=crop',
        ];
        return (
          <>
            {renderTitle('ارفع صور العقار')}
            <div className="grid grid-cols-2 gap-3 mb-4">
              {/* Upload Button */}
              <div className="aspect-square bg-pale/30 rounded-xl border-2 border-dashed border-mid flex flex-col items-center justify-center relative active:bg-pale/50 transition-colors">
                <UploadIcon className="w-8 h-8 text-navy mb-2" />
                <span className="text-xs font-bold text-navy">رفع المزيد</span>
                <input 
                  type="file" 
                  multiple 
                  accept="image/*" 
                  onChange={(e) => handleMediaUpload(e, 'images')}
                  className="absolute inset-0 opacity-0 cursor-pointer"
                />
              </div>

              {/* User Uploaded */}
              {formData.images.map((file: File, i: number) => (
                <div key={`new-${i}`} className="aspect-square rounded-xl overflow-hidden bg-gray-100 relative">
                   <img src={URL.createObjectURL(file)} className="w-full h-full object-cover" onError={(e) => (e.currentTarget.src = FALLBACK_IMAGE)} />
                </div>
              ))}

              {/* Demo Images */}
              {demoImages.map((src, i) => (
                <div key={`demo-${i}`} className="aspect-square rounded-xl overflow-hidden bg-gray-100 relative">
                   <img src={src} className="w-full h-full object-cover" onError={(e) => (e.currentTarget.src = FALLBACK_IMAGE)} />
                   <span className="absolute top-1 right-1 bg-black/50 text-white text-[12px] px-1.5 rounded">ديمو</span>
                </div>
              ))}
            </div>
          </>
        );
      case 17:
        return (
          <>
            {renderTitle('ملخص الاعلان')}
            <div className="bg-white rounded-2xl p-4 shadow-sm border border-pale mb-6 text-sm flex flex-col gap-2">
               <div className="flex justify-between"><span className="text-gray-500">نوع الاعلان</span><span className="font-bold">{formData.listingType}</span></div>
               <div className="flex justify-between"><span className="text-gray-500">الدولة</span><span className="font-bold">{formData.country}</span></div>
               <div className="flex justify-between"><span className="text-gray-500">المنطقة</span><span className="font-bold">{formData.area}</span></div>
               <div className="flex justify-between"><span className="text-gray-500">السعر</span><span className="font-bold text-blue">5 د.ك</span></div>
               <div className="flex justify-between"><span className="text-gray-500">مدة النشر</span><span className="font-bold">30 يوم</span></div>
            </div>

            {isPaid && (
               <div className="flex flex-col items-center justify-center py-10 animate-fade-in">
                  <div className="w-16 h-16 bg-green-100 rounded-full flex items-center justify-center mb-4 text-green-600">
                    <CheckIcon className="w-8 h-8" />
                  </div>
                  <h3 className="text-xl font-bold text-navy mb-2">تم نشر الإعلان بنجاح</h3>
                  <p className="text-gray-500 text-sm">سيظهر إعلانك في حسابك فوراً</p>
               </div>
            )}
          </>
        );
      default:
        return null;
    }
  };

  return (
    <div className="w-full h-full relative">
      {/* 1. Progress Bar (Absolute Top of this container) */}
      <div className="absolute top-0 left-0 right-0 h-12 px-6 flex items-center justify-between z-20 bg-bg">
        <span className="text-xs font-bold text-navy">{step} من {TOTAL_STEPS}</span>
        <div className="flex-1 h-1.5 bg-pale mx-4 rounded-full overflow-hidden">
           <div 
             className="h-full bg-navy transition-all duration-300 rounded-full"
             style={{ width: `${(step / TOTAL_STEPS) * 100}%` }}
           ></div>
        </div>
      </div>

      {/* 2. Scrollable Content Area */}
      {/* Padded at top for Progress, Padded at bottom for Footer */}
      <div 
        id="wizard-content" 
        className="absolute inset-0 top-12 bottom-0 overflow-y-auto overflow-x-hidden no-scrollbar px-6 pb-40"
      >
        <div className="max-w-md mx-auto py-2">
           {renderContent()}
        </div>
      </div>

      {/* 3. Footer Actions (Sibling to content, Absolute Bottom of this container) */}
      {/* Since this container sits ABOVE the TabBar in the App Shell, bottom-0 here means visually 'Above Tab Bar' */}
      {showFooter && (
        <div className="absolute bottom-0 left-0 right-0 p-6 bg-gradient-to-t from-bg via-bg/95 to-transparent z-30">
           {renderFooterAction()}
        </div>
      )}
    </div>
  );
};

export default AddWizard;

