import React, { useState, useEffect } from 'react';
import { DEMO_OFFICES } from '../utils/db';
import { VerifiedIcon, StarIcon, ChevronRightIcon, BuildingIcon, ConstructionIcon, ContractingIcon, DecorIcon, MaterialsIcon } from './Icons';

export const CATEGORIES = [
  { id: 'real-estate', name: 'الشركات العقارية', icon: BuildingIcon },
  { id: 'construction', name: 'الشركات الانشائية', icon: ConstructionIcon },
  { id: 'contracting', name: 'شركات المقاولات', icon: ContractingIcon },
  { id: 'decor', name: 'قسم الديكور', icon: DecorIcon },
  { id: 'materials', name: 'مواد البناء', icon: MaterialsIcon },
];

const OfficesPage: React.FC = () => {
  const [selectedCategory, setSelectedCategory] = useState<string | null>(null);

  useEffect(() => {
    // Sync internal state with URL params
    const handleHashChange = () => {
      const params = new URLSearchParams(window.location.hash.split('?')[1]);
      setSelectedCategory(params.get('category'));
    };

    // Check initial load
    handleHashChange();

    window.addEventListener('hashchange', handleHashChange);
    return () => window.removeEventListener('hashchange', handleHashChange);
  }, []);

  const handleCategoryClick = (categoryId: string) => {
    // Update URL to navigate
    window.location.hash = `#/companies?category=${categoryId}`;
  };

  const handleCompanyClick = (companyId: string) => {
    window.location.hash = `#/profile?user=${companyId}`;
  };

  if (!selectedCategory) {
    // Render Category Grid View (Redesigned)
    return (
      <div className="w-full min-h-full bg-bg dark:bg-slate-950 p-6 pb-24 animate-fade-in transition-colors duration-300">
         <div className="grid grid-cols-2 gap-x-4 gap-y-8 pt-4">
           {CATEGORIES.map((cat) => (
             <button 
               key={cat.id}
               onClick={() => handleCategoryClick(cat.id)}
               className="flex flex-col items-center gap-3 group active:scale-95 transition-transform duration-200"
             >
               {/* Circle Container */}
               <div className="w-24 h-24 sm:w-28 sm:h-28 rounded-full bg-white dark:bg-slate-900 border border-pale dark:border-slate-800 shadow-[0_4px_20px_rgba(0,0,0,0.03)] flex items-center justify-center group-hover:border-navy/30 dark:group-hover:border-blue/30 group-hover:shadow-lg transition-all duration-300">
                 <cat.icon className="w-10 h-10 text-navy dark:text-blue group-hover:scale-110 transition-transform duration-300" />
               </div>

               {/* Label */}
               <span className="text-[18px] sm:text-[20px] font-bold text-navy dark:text-slate-200 text-center leading-tight px-1 max-w-full truncate">
                 {cat.name}
               </span>
             </button>
           ))}
         </div>
      </div>
    );
  }

  // Render Companies Grid View (Filtered)
  return (
    <div className="w-full min-h-full bg-bg dark:bg-slate-950 p-4 pb-24 animate-fade-in transition-colors duration-300">
      <div className="grid grid-cols-2 gap-4">
        {DEMO_OFFICES.map((office) => (
          <div 
            key={office.id}
            onClick={() => handleCompanyClick(office.id)}
            className="bg-white dark:bg-slate-900 rounded-3xl border border-pale dark:border-slate-800 shadow-sm overflow-hidden flex flex-col active:scale-98 transition-all duration-300 cursor-pointer"
          >
            <div className="relative h-28 bg-gray-50 dark:bg-slate-800 flex items-center justify-center p-4">
              <div className="w-[68px] h-[68px] rounded-full border-4 border-white dark:border-slate-700 shadow-md overflow-hidden bg-white dark:bg-slate-900 z-10">
                <img 
                  src={office.logo} 
                  alt={office.officeName} 
                  className="w-full h-full object-cover"
                  onError={(e) => e.currentTarget.src = 'https://raiyansoft.com/wp-content/uploads/2026/01/1.png'}
                />
              </div>
              {office.verified && (
                <div className="absolute top-3 left-3 text-blue drop-shadow-sm" title="مكتب موثق">
                   <VerifiedIcon className="w-6 h-6" />
                </div>
              )}
              <div className="absolute top-3 right-3 flex items-center gap-1.5 bg-white/95 dark:bg-slate-900/95 backdrop-blur-sm px-2.5 py-1 rounded-xl shadow-sm border border-pale/50 dark:border-slate-700">
                <span className="text-[14px] font-semibold text-navy dark:text-slate-200 leading-none mt-0.5">{office.rating}</span>
                <StarIcon className="w-4 h-4 text-yellow-400" />
