            <div className="p-4 flex flex-col items-center text-center flex-1">
              {/* Title with min-height for alignment */}
              <div className="min-h-[3rem] flex items-center justify-center w-full mb-0.5">
                 <h3 className="text-[18px] sm:text-[20px] font-bold text-navy dark:text-slate-200 leading-[1.35] line-clamp-2">
                    {office.officeName}
                 </h3>
              </div>

              {/* Location */}
              <span className="text-[14px] sm:text-[15px] font-medium text-gray-500 dark:text-slate-400 mb-2.5 max-w-full truncate px-1">
                 {office.governorate}
              </span>

              <div className="w-full mt-auto">
                <div className="flex justify-between items-center bg-gray-50 dark:bg-slate-800/50 rounded-xl px-3 py-2.5 mb-1.5 border border-pale/30 dark:border-slate-700/50">
                   <span className="text-[13px] sm:text-[14px] font-medium text-gray-600 dark:text-slate-400">إعلانات نشطة</span>
                   <span className="text-[16px] sm:text-[18px] font-bold text-blue dark:text-blue">{office.activeListingsCount}</span>
                </div>
                <button className="w-full h-[46px] rounded-xl bg-navy/5 dark:bg-slate-800 text-navy dark:text-slate-200 text-[15px] sm:text-[16px] font-semibold hover:bg-navy/10 dark:hover:bg-slate-700 transition-colors flex items-center justify-center">
                  عرض الملف
                </button>
              </div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

export default OfficesPage;

import React, { useState, useEffect } from 'react';
import { ChevronRightIcon, CheckIcon, AppleIcon, UploadIcon, PlayIcon, BuildingIcon } from './Icons';
import { GOVERNORATES, AREAS } from '../data/locations';
import { saveListing } from '../utils/db';

interface AddWizardProps {
  onComplete: () => void;
}

const TOTAL_STEPS = 17;
const FALLBACK_IMAGE = 'https://raiyansoft.com/wp-content/uploads/2026/01/1.png';
const KNET_LOGO = "https://media.licdn.com/dms/image/v2/D4D0BAQFazp_I3lLeQg/company-logo_200_200/company-logo_200_200/0/1715599858189/the_shared_electronic_banking_services_co_knet_logo?e=2147483647&v=beta&t=FfjCLbNIUGrTCTi-tI5nXSNP9B4AcOJbWsFqV0bSWcM";

const COUNTRIES = [
  { name: 'الكويت', flag: '🇰🇼' },
  { name: 'السعودية', flag: '🇸🇦' },
  { name: 'الإمارات', flag: '🇦🇪' },
  { name: 'قطر', flag: '🇶🇦' },
  { name: 'البحرين', flag: '🇧🇭' },
  { name: 'عُمان', flag: '🇴🇲' },
  { name: 'سوريا', flag: '🇸🇾' },
  { name: 'مصر', flag: '🇪🇬' },
  { name: 'الأردن', flag: '🇯🇴' },
  { name: 'تركيا', flag: '🇹🇷' }
];

const AddWizard: React.FC<AddWizardProps> = ({ onComplete }) => {
  // Initialize step from URL
  const getStepFromUrl = () => {
    const params = new URLSearchParams(window.location.hash.split('?')[1]);
    const s = parseInt(params.get('step') || '1');
    return isNaN(s) || s < 1 ? 1 : (s > TOTAL_STEPS ? TOTAL_STEPS : s);
  };

  const [step, setStep] = useState(getStepFromUrl());
  const [formData, setFormData] = useState<any>({
    listingType: '',
    propertyType: '',
    country: 'الكويت',
    governorate: '',
    area: '',
    rooms: '',
    bathrooms: '',
    size: 400,
    balcony: '',
    parking: '',
    parkingSystems: [],
    electricity: '',
    water: '',
    ac: '',
    video: null,
    images: []
  });
  const [isProcessing, setIsProcessing] = useState(false);
  const [isPaid, setIsPaid] = useState(false);

  // Sync state with URL changes (back/forward)
  useEffect(() => {
    const handleHashChange = () => {
      const newStep = getStepFromUrl();
      setStep(newStep);
    };
    window.addEventListener('hashchange', handleHashChange);
    return () => window.removeEventListener('hashchange', handleHashChange);
  }, []);

  // Update URL when step changes internally
  const updateStepUrl = (newStep: number) => {
     const currentHash = window.location.hash.split('?')[0];
     window.location.hash = `${currentHash}?step=${newStep}`;
  };

  // Helper to scroll to top on step change
  useEffect(() => {
    const content = document.getElementById('wizard-content');
    if (content) content.scrollTop = 0;
  }, [step]);

  const updateData = (key: string, value: any) => {
    setFormData((prev: any) => ({ ...prev, [key]: value }));
  };

  const nextStep = () => {
    if (step < TOTAL_STEPS) updateStepUrl(step + 1);
  };

  const prevStep = () => {
    if (step > 1) updateStepUrl(step - 1);
  };

  const selectAndNext = (key: string, value: any) => {
    updateData(key, value);
    nextStep();
  };

  const handleMediaUpload = (e: React.ChangeEvent<HTMLInputElement>, type: 'video' | 'images') => {
    if (e.target.files && e.target.files.length > 0) {
      if (type === 'video') {
        updateData('video', e.target.files[0]);
      } else {
        const newImages = Array.from(e.target.files);
        setFormData((prev: any) => ({ ...prev, images: [...prev.images, ...newImages] }));
      }
    }
  };

  const handlePublish = async () => {
    setIsProcessing(true);
    // Simulate Payment
    setTimeout(async () => {
      setIsProcessing(false);
      setIsPaid(true);

      const newListing = {
        id: Date.now(),
        createdAt: new Date(),
        price: '5 د.ك', // Default dummy rental price or use logic
        publisherId: 'current_user',
        publisherName: 'فهد الحمدان',
        ...formData,
        imageUrl: formData.images.length > 0 
          ? URL.createObjectURL(formData.images[0]) 
          : FALLBACK_IMAGE
      };

      await saveListing(newListing);

      setTimeout(() => {
        onComplete();
        // Reset wizard
        setFormData({ size: 400, parkingSystems: [], images: [], country: 'الكويت' });
      }, 1500);
    }, 2000);
  };

  // Render Helpers
  const renderOption = (content: React.ReactNode, isSelected: boolean, onClick: () => void) => (
    <button
      onClick={onClick}
      className={`w-full p-4 mb-3 rounded-2xl border flex items-center justify-between transition-all duration-200 active:scale-98 ${
        isSelected 
          ? 'border-navy bg-navy text-white shadow-lg shadow-navy/20' 
          : 'border-pale bg-white text-navy hover:border-mid'
      }`}
    >
      <div className="font-bold text-sm">{content}</div>
      {isSelected && <CheckIcon className="w-5 h-5 text-white" />}
    </button>
  );

  const renderTitle = (title: string) => (
    <h2 className="text-xl font-bold text-navy mb-6 text-center">{title}</h2>
  );

  // Show footer on all steps unless payment is successfully processed
  const showFooter = !isPaid;

  const renderFooterAction = () => {
    const isFirstStep = step === 1;

    // Shared Back Button (Secondary Style)
    const backButton = (
      <button 
        onClick={prevStep} 
        disabled={isFirstStep}
        className={`w-full py-3 bg-white border border-pale text-navy rounded-xl font-bold transition-all shadow-sm ${
          isFirstStep ? 'opacity-50 cursor-not-allowed' : 'active:scale-95 hover:bg-pale/30'
        }`}
      >
        رجوع
      </button>
    );

    // Primary Next Button
    const nextButton = (
      <button 
        onClick={nextStep} 
        className="w-full py-4 bg-navy text-white rounded-xl font-bold shadow-lg shadow-navy/20 active:scale-95 transition-all"
      >
        التالي
      </button>
    );

    // Steps that require a manual "Next" button (stacked layout)
    // 8: Size (Slider), 15: Video, 16: Images
    if ([8, 15, 16].includes(step)) {
      return (
        <div className="flex flex-col gap-3">
          {backButton}
          {nextButton}
        </div>
      );
    }

    // Step 17: Publish (Payment)
    if (step === 17) {
      return (
        <div className="flex flex-col gap-3">
          {backButton}
          <button 
            onClick={handlePublish}
            disabled={isProcessing}
            className="w-full py-4 bg-black text-white rounded-xl font-bold flex items-center justify-center gap-2 active:scale-95 transition-all shadow-xl"
          >
            {isProcessing ? (
               <span className="animate-pulse">جاري المعالجة...</span>
            ) : (
              <>
               <AppleIcon className="w-5 h-5 mb-0.5" />
               <span>الدفع والنشر (Apple Pay)</span>
              </>
            )}
          </button>
          <button 
            onClick={handlePublish}
            disabled={isProcessing}
            className="w-full py-4 bg-white text-navy border border-pale rounded-xl font-bold flex items-center justify-center gap-2 active:scale-95 transition-all shadow-sm"
          >
            {isProcessing ? (
               <span className="animate-pulse">جاري المعالجة...</span>
            ) : (
              <>
               <img src={KNET_LOGO} className="w-8 h-8 object-contain" alt="KNET" />
               <span>الدفع عبر الكي نت</span>
              </>
            )}
          </button>
        </div>
      );
    }

    // Default for all other steps (Single Choice / Auto-advance)
    // Always render at least the back button as per requirement
    return (
      <div className="w-full">
        {backButton}
      </div>
    );
  };

  const renderContent = () => {
    switch (step) {
      case 1:
        const adTypes = [
          { label: 'للبيع', value: 'للبيع' },
          { label: 'للإيجار', value: 'للإيجار' },
          { label: 'الفنادق', value: 'hotels' }
        ];
        return (
          <>
            {renderTitle('نوع الاعلان')}
            {adTypes.map(opt => (
              renderOption(opt.label, formData.listingType === opt.value, () => selectAndNext('listingType', opt.value))
            ))}
          </>
        );
      case 2:
        return (
          <>
            {renderTitle('نوع العقار')}
            {['بيت', 'شقة', 'دور', 'عمارة', 'دوبلكس'].map(opt => (
              renderOption(opt, formData.propertyType === opt, () => selectAndNext('propertyType', opt))
            ))}
          </>
        );
      case 3:
        return (
          <>
            {renderTitle('الدولة')}
            {COUNTRIES.map(opt => (
              renderOption(
                <div className="flex items-center gap-3">
                  <span className="text-2xl">{opt.flag}</span>
                  <span>{opt.name}</span>
                </div>, 
                formData.country === opt.name, 
                () => selectAndNext('country', opt.name)
              )
            ))}
          </>
        );
      case 4:
        // Use Kuwait governorates regardless of country (Demo limitation)
        return (
          <>
            {renderTitle('المحافظة')}
            {GOVERNORATES.map(opt => (
              renderOption(opt, formData.governorate === opt, () => selectAndNext('governorate', opt))
            ))}
          </>
        );
      case 5:
        const areas = AREAS[formData.governorate] || [];
        return (
          <>
            {renderTitle('المنطقة')}
            <div className="grid grid-cols-1 gap-1">
              {areas.map(opt => (
                renderOption(opt, formData.area === opt, () => selectAndNext('area', opt))
              ))}
            </div>
          </>
        );
      case 6:
        return (
          <>
            {renderTitle('عدد الغرف')}
            <div className="grid grid-cols-3 gap-3">
              {Array.from({ length: 12 }, (_, i) => i + 1).map(num => (
                <button
                  key={num}
                  onClick={() => selectAndNext('rooms', num)}
                  className={`aspect-square rounded-2xl border flex items-center justify-center text-lg font-bold transition-all ${
                    formData.rooms === num ? 'bg-navy text-white' : 'bg-white text-navy border-pale'
                  }`}
                >
                  {num}
                </button>
              ))}
            </div>
          </>
        );
      case 7:
        return (
          <>
            {renderTitle('عدد الحمامات')}
            <div className="grid grid-cols-3 gap-3">
              {[...Array.from({ length: 10 }, (_, i) => i + 1), '10+'].map(num => (
                <button
                  key={num}
                  onClick={() => selectAndNext('bathrooms', num)}
                  className={`aspect-square rounded-2xl border flex items-center justify-center text-lg font-bold transition-all ${
                    formData.bathrooms === num ? 'bg-navy text-white' : 'bg-white text-navy border-pale'
                  }`}
                >
                  {num}
                </button>
              ))}
            </div>
          </>
        );
      case 8:
        return (
          <>
            {renderTitle('المساحة')}
            <div className="flex flex-col items-center justify-center gap-8 py-10 bg-white rounded-3xl border border-pale shadow-sm">
              <span className="text-4xl font-bold text-blue">{formData.size} <span className="text-sm text-gray-400">م²</span></span>
              <input 
                type="range" 
                min="50" 
                max="2000" 
                step="5" 
                value={formData.size} 
                onChange={(e) => updateData('size', parseInt(e.target.value))}
                className="w-4/5 accent-navy h-2 bg-pale rounded-lg appearance-none cursor-pointer"
              />
            </div>
          </>
        );
      case 9:
        return (
          <>
            {renderTitle('بلكونة')}
            {['نعم', 'لا'].map(opt => (
              renderOption(opt, formData.balcony === opt, () => selectAndNext('balcony', opt))
            ))}
          </>
        );
      case 10:
        return (
          <>
            {renderTitle('عدد المواقف')}
            {['1', '2', '3', '3+'].map(opt => (
              renderOption(opt, formData.parking === opt, () => selectAndNext('parking', opt))
            ))}
          </>
        );
      case 11:
        return (
          <>
            {renderTitle('نظام المواقف')}
            {['مظلات', 'سرداب', 'اخرى'].map(opt => (
              renderOption(opt, formData.parkingSystems.includes(opt), () => selectAndNext('parkingSystems', [opt]))
            ))}
          </>
        );
      case 12:
        return (
          <>
            {renderTitle('الكهرباء')}
            {['على المالك', 'على المستأجر'].map(opt => (
              renderOption(opt, formData.electricity === opt, () => selectAndNext('electricity', opt))
            ))}
          </>
        );
      case 13:
        return (
          <>
            {renderTitle('الماء')}
            {['على المالك', 'على المستأجر'].map(opt => (
              renderOption(opt, formData.water === opt, () => selectAndNext('water', opt))
            ))}
          </>
        );
      case 14:
        return (
          <>
            {renderTitle('التكييف')}
            {['على المالك', 'على المستأجر'].map(opt => (
              renderOption(opt, formData.ac === opt, () => selectAndNext('ac', opt))
            ))}
          </>
        );
      case 15:
        return (
          <>
            {renderTitle('ارفع فيديو')}
            <div className="relative aspect-video bg-gray-100 rounded-xl overflow-hidden border-2 border-dashed border-mid mb-4 flex items-center justify-center group">
              {formData.video ? (
                <video src={URL.createObjectURL(formData.video)} className="w-full h-full object-cover" controls />
              ) : (
                <div className="flex flex-col items-center gap-2">
                  <div className="w-16 h-16 bg-navy/10 rounded-full flex items-center justify-center">
                    <PlayIcon className="w-8 h-8 text-navy" />
                  </div>
                  <span className="text-sm text-gray-500">فيديو ديمو</span>
                </div>
              )}
              <input 
                type="file" 
                accept="video/*" 
                onChange={(e) => handleMediaUpload(e, 'video')}
                className="absolute inset-0 opacity-0 cursor-pointer"
              />
            </div>
          </>
        );
      case 16:
        const demoImages = [
           'https://images.unsplash.com/photo-1522708323590-d24dbb6b0267?q=80&w=300&auto=format&fit=crop',
           'https://images.unsplash.com/photo-1502672260266-1c1ef2d93688?q=80&w=300&auto=format&fit=crop',
           'https://images.unsplash.com/photo-1600607687939-ce8a6c25118c?q=80&w=300&auto=format&fit=crop',
           'https://images.unsplash.com/photo-1600596542815-40b5104d57ea?q=80&w=300&auto=format&fit=crop',
        ];
        return (
          <>
            {renderTitle('ارفع صور العقار')}
            <div className="grid grid-cols-2 gap-3 mb-4">
              {/* Upload Button */}
              <div className="aspect-square bg-pale/30 rounded-xl border-2 border-dashed border-mid flex flex-col items-center justify-center relative active:bg-pale/50 transition-colors">
                <UploadIcon className="w-8 h-8 text-navy mb-2" />
                <span className="text-xs font-bold text-navy">رفع المزيد</span>
                <input 
                  type="file" 
                  multiple 
                  accept="image/*" 
                  onChange={(e) => handleMediaUpload(e, 'images')}
                  className="absolute inset-0 opacity-0 cursor-pointer"
                />
              </div>

              {/* User Uploaded */}
              {formData.images.map((file: File, i: number) => (
                <div key={`new-${i}`} className="aspect-square rounded-xl overflow-hidden bg-gray-100 relative">
                   <img src={URL.createObjectURL(file)} className="w-full h-full object-cover" onError={(e) => (e.currentTarget.src = FALLBACK_IMAGE)} />
                </div>
              ))}

              {/* Demo Images */}
              {demoImages.map((src, i) => (
                <div key={`demo-${i}`} className="aspect-square rounded-xl overflow-hidden bg-gray-100 relative">
                   <img src={src} className="w-full h-full object-cover" onError={(e) => (e.currentTarget.src = FALLBACK_IMAGE)} />
                   <span className="absolute top-1 right-1 bg-black/50 text-white text-[12px] px-1.5 rounded">ديمو</span>
                </div>
              ))}
            </div>
          </>
        );
      case 17:
        return (
          <>
            {renderTitle('ملخص الاعلان')}
            <div className="bg-white rounded-2xl p-4 shadow-sm border border-pale mb-6 text-sm flex flex-col gap-2">
               <div className="flex justify-between"><span className="text-gray-500">نوع الاعلان</span><span className="font-bold">{formData.listingType === 'hotels' ? 'الفنادق' : formData.listingType}</span></div>
               <div className="flex justify-between"><span className="text-gray-500">الدولة</span><span className="font-bold">{formData.country}</span></div>
               <div className="flex justify-between"><span className="text-gray-500">المنطقة</span><span className="font-bold">{formData.area}</span></div>
               <div className="flex justify-between"><span className="text-gray-500">السعر</span><span className="font-bold text-blue">5 د.ك</span></div>
               <div className="flex justify-between"><span className="text-gray-500">مدة النشر</span><span className="font-bold">30 يوم</span></div>
            </div>

            {isPaid && (
               <div className="flex flex-col items-center justify-center py-10 animate-fade-in">
                  <div className="w-16 h-16 bg-green-100 rounded-full flex items-center justify-center mb-4 text-green-600">
                    <CheckIcon className="w-8 h-8" />
                  </div>
                  <h3 className="text-xl font-bold text-navy mb-2">تم نشر الإعلان بنجاح</h3>
                  <p className="text-gray-500 text-sm">سيظهر إعلانك في حسابك فوراً</p>
               </div>
            )}
          </>
        );
      default:
        return null;
    }
  };

  return (
    <div className="w-full h-full relative">
      {/* 1. Progress Bar (Absolute Top of this container) */}
      <div className="absolute top-0 left-0 right-0 h-12 px-6 flex items-center justify-between z-20 bg-bg">
        <span className="text-xs font-bold text-navy">{step} من {TOTAL_STEPS}</span>
        <div className="flex-1 h-1.5 bg-pale mx-4 rounded-full overflow-hidden">
           <div 
             className="h-full bg-navy transition-all duration-300 rounded-full"
             style={{ width: `${(step / TOTAL_STEPS) * 100}%` }}
           ></div>
        </div>
      </div>

      {/* 2. Scrollable Content Area */}
      {/* Padded at top for Progress, Padded at bottom for Footer */}
      <div 
        id="wizard-content" 
        className="absolute inset-0 top-12 bottom-0 overflow-y-auto overflow-x-hidden no-scrollbar px-6 pb-40"
      >
        <div className="max-w-md mx-auto py-2">
           {renderContent()}
        </div>
      </div>

      {/* 3. Footer Actions (Sibling to content, Absolute Bottom of this container) */}
      {/* Since this container sits ABOVE the TabBar in the App Shell, bottom-0 here means visually 'Above Tab Bar' */}
      {showFooter && (
        <div className="absolute bottom-0 left-0 right-0 p-6 bg-gradient-to-t from-bg via-bg/95 to-transparent z-30">
           {renderFooterAction()}
        </div>
      )}
    </div>
  );
};

export default AddWizard;

import React, { useState, useEffect } from 'react';
import { UserIcon, PhoneIcon, WhatsappIcon, BuildingIcon, VerifiedIcon, InstagramIcon, TikTokIcon, SnapchatIcon, MapPinIcon, GlobeIcon, LinkIcon } from './Icons';
import { getListings, DEMO_ADS, DEMO_OFFICES } from '../utils/db';
import { Listing } from '../types';

interface ProfilePageProps {
  onListingClick?: (listing: Listing) => void;
}

const FALLBACK_IMAGE = 'https://raiyansoft.com/wp-content/uploads/2026/01/1.png';

const ListingCard: React.FC<{ listing: Listing, onClick?: () => void }> = ({ listing, onClick }) => {
  const [imgSrc, setImgSrc] = useState<string>('');

  useEffect(() => {
    if (listing.imageUrl instanceof Blob || listing.imageUrl instanceof File) {
        setImgSrc(URL.createObjectURL(listing.imageUrl));
    } else if (typeof listing.imageUrl === 'string') {
        setImgSrc(listing.imageUrl);
    } else if (listing.images && listing.images.length > 0) {
         const first = listing.images[0];
         if (first instanceof Blob || first instanceof File) {
             setImgSrc(URL.createObjectURL(first));
         } else {
             setImgSrc(first as string);
         }
    } else {
        setImgSrc(FALLBACK_IMAGE);
    }
  }, [listing]);

  return (
    <div 
      onClick={onClick}
      className="flex flex-col bg-white dark:bg-slate-900 rounded-xl shadow-[0_2px_8px_rgba(0,0,0,0.04)] border border-pale/50 dark:border-slate-800 overflow-hidden active:scale-98 transition-all duration-300 cursor-pointer"
    >
      <div className="aspect-square bg-slate-100 dark:bg-slate-800 flex items-center justify-center relative">
        <img src={imgSrc} alt={listing.title} className="w-full h-full object-cover" onError={() => setImgSrc(FALLBACK_IMAGE)} />
        <span className="absolute top-2 left-2 bg-navy/80 dark:bg-blue/80 text-white text-[13px] px-2 py-0.5 rounded-full z-10 font-bold">جديد</span>
